// Аналог Angular DrillDownPanelComponent (sti-drill-down-panel)
// Панель вкладок для навигации по drill-down отчётам
//
// Angular:
//   - stiJsViewerToolBar контейнер
//   - sti-button с styleName='stiJsViewerStandartSmallButton' для каждой вкладки
//   - className = styleName + (selected ? 'Selected' : (over ? 'Over' : 'Default'))
//   - action(button): saveState → setReportParams → getPages
//   - close(button): splice → navigate to first

import React from 'react';
import { useViewer } from '../hooks/useViewer';

export const DrillDownPanel: React.FC = () => {
    const { model } = useViewer();

    const visible = model.controls.drillDownPanel?.visible ?? false;
    const buttons: any[] = model.drillDownButtons ?? [];

    if (!visible || buttons.length === 0) { return null; }

    const displayMode = model.options?.toolbar?.displayMode ?? 'Simple';
    const ddService = model.drillDownService;
    const isSeparated = displayMode === 'Separated';

    return (
        <div
            className={'stiJsViewerToolBar' + (isSeparated ? ' stiJsViewerToolBarSeparated' : '')}
            style={{ display: visible ? '' : 'none' }}
        >
            <div style={{ paddingTop: displayMode === 'Simple' ? 2 : undefined }}>
                <table
                    className="stiJsViewerToolBarTable"
                    cellPadding={0}
                    cellSpacing={0}
                    style={{
                        margin: 0,
                        boxSizing: 'border-box',
                        border: isSeparated ? '0px' : undefined,
                        color: model.options?.toolbar?.fontColor,
                        fontFamily: model.options?.toolbar?.fontFamily,
                    }}
                >
                    <tbody>
                        <tr className="stiJsViewerClearAllStyles">
                            <td className="stiJsViewerClearAllStyles">
                                <table className="stiJsViewerClearAllStyles" cellPadding={0} cellSpacing={0}>
                                    <tbody>
                                        <tr className="stiJsViewerClearAllStyles">
                                            {buttons.map((button: any, i: number) => {
                                                if (!button.visible) return null;
                                                return (
                                                    <td
                                                        key={i}
                                                        className="stiJsViewerClearAllStyles"
                                                        style={{ padding: 0, border: 0, lineHeight: 0 }}
                                                    >
                                                        <DrillDownButton
                                                            button={button}
                                                            showClose={i > 0}
                                                            isSeparated={isSeparated}
                                                            onAction={() => ddService?.selectButton(button)}
                                                            onClose={() => ddService?.closeButton(button)}
                                                        />
                                                    </td>
                                                );
                                            })}
                                        </tr>
                                    </tbody>
                                </table>
                            </td>
                        </tr>
                    </tbody>
                </table>
            </div>
        </div>
    );
};

/**
 * Кнопка drill-down вкладки — аналог Angular sti-button
 * styleName = 'stiJsViewerStandartSmallButton'
 * className = styleName + (selected ? 'Selected' : (over ? 'Over' : 'Default'))
 */
const DrillDownButton: React.FC<{
    button: any;
    showClose: boolean;
    isSeparated: boolean;
    onAction: () => void;
    onClose: () => void;
}> = ({ button, showClose, isSeparated, onAction, onClose }) => {
    const [over, setOver] = React.useState(false);

    const styleName = 'stiJsViewerStandartSmallButton';
    const stateClass = button.selected ? 'Selected' : (over ? 'Over' : 'Default');
    const className = `${styleName} ${styleName}${stateClass}`;

    return (
        <table
            className={className}
            cellPadding={0}
            cellSpacing={0}
            style={{
                display: 'inline-block',
                margin: '2px 1px 2px 2px',
                cursor: 'default',
                height: isSeparated ? 28 : undefined,
            }}
            onMouseEnter={() => setOver(true)}
            onMouseLeave={() => setOver(false)}
        >
            <tbody>
                <tr className="stiJsViewerClearAllStyles">
                    <td
                        className="stiJsViewerClearAllStyles"
                        style={{
                            padding: '0 6px',
                            lineHeight: '22px',
                            whiteSpace: 'nowrap',
                            cursor: 'pointer',
                            verticalAlign: 'middle',
                        }}
                        onClick={onAction}
                    >
                        {button.caption ?? 'Report'}
                    </td>
                    {showClose && (
                        <CloseButton onClose={onClose} />
                    )}
                </tr>
            </tbody>
        </table>
    );
};

/** Кнопка закрытия вкладки — аналог Angular sti-button с imageName='CloseForm.png' */
const CloseButton: React.FC<{ onClose: () => void }> = ({ onClose }) => {
    const [over, setOver] = React.useState(false);

    return (
        <td
            className="stiJsViewerClearAllStyles"
            style={{
                verticalAlign: 'middle',
                padding: '0 6px 0 2px',
                cursor: 'pointer',
                lineHeight: 0,
            }}
            onMouseEnter={() => setOver(true)}
            onMouseLeave={() => setOver(false)}
            onClick={(e) => { e.stopPropagation(); onClose(); }}
        >
            <svg
                width="7"
                height="7"
                viewBox="0 0 7 7"
                style={{
                    display: 'inline-block',
                    verticalAlign: 'middle',
                    opacity: over ? 1 : 0.6,
                }}
            >
                <line x1="0" y1="0" x2="7" y2="7" stroke="#555" strokeWidth="1.2" />
                <line x1="7" y1="0" x2="0" y2="7" stroke="#555" strokeWidth="1.2" />
            </svg>
        </td>
    );
};
