// Аналог Angular CheckboxComponent

import React, { useState } from 'react';
import { useViewer } from '../hooks/useViewer';

export interface CheckboxProps {
    isChecked?: boolean;
    isEnabled?: boolean;
    captionText?: string;
    tooltip?: string;
    margin?: string;
    width?: string;
    nullable?: boolean;
    onChange?: (checked: boolean | null) => void;
}

export const StiCheckbox: React.FC<CheckboxProps> = ({
    isChecked: initialChecked = false,
    isEnabled = true,
    captionText,
    tooltip,
    margin,
    width,
    nullable = false,
    onChange
}) => {
    const { model } = useViewer();
    const [checked, setChecked] = useState(initialChecked);
    const [isNull, setIsNull] = useState(false);
    const [over, setOver] = useState(false);

    const isTouchDevice = model.options?.isTouchDevice ?? false;
    const boxSize = isTouchDevice ? 16 : 13;

    const handleClick = () => {
        if (!isEnabled) { return; }
        const newChecked = !checked || isNull;
        const newNull = nullable && newChecked && !isNull;
        setChecked(newChecked);
        setIsNull(newNull);
        onChange?.(newNull ? null : newChecked);
    };

    const className = isEnabled ? 'stiJsViewerCheckBox' : 'stiJsViewerCheckBoxDisabled';

    const imgSrc = model.img?.(
        (isNull ? 'CheckBoxIndeterminate' : 'CheckBox') + '.png'
    );

    return (
        <table
            cellPadding={0} cellSpacing={0}
            className={className}
            title={tooltip}
            style={{ margin, width, boxSizing: 'content-box', cursor: isEnabled ? 'pointer' : 'default', userSelect: 'none' }}
            onMouseOver={() => setOver(true)}
            onMouseLeave={() => setOver(false)}
            onClick={handleClick}
        >
            <tbody>
                <tr>
                    <td style={{ lineHeight: 0, padding: isTouchDevice ? '1px 3px 1px 1px' : '' }}>
                        <div style={{ width: boxSize, height: boxSize, boxSizing: 'content-box' }}
                            className={isEnabled ? (over ? 'stiJsViewerCheckBoxImageBlockOver' : 'stiJsViewerCheckBoxImageBlock') : 'stiJsViewerCheckBoxImageBlockDisabled'}
                        >
                            {isNull ? (
                                <div className="stiJsViewerCheckBoxNullBlock"
                                    style={{ left: 2, top: 6, width: 9, opacity: isEnabled ? 1 : 0.5 }} />
                            ) : (
                                <img
                                    src={imgSrc ?? ''}
                                    alt=""
                                    style={{
                                        visibility: checked ? 'visible' : 'hidden',
                                        width: 12, height: 12,
                                        opacity: isEnabled ? 1 : 0.5,
                                        verticalAlign: 'baseline'
                                    }}
                                />
                            )}
                        </div>
                    </td>
                    {captionText != null && (
                        <td style={{ padding: isTouchDevice ? '' : '1px 0 0 4px', whiteSpace: 'nowrap' }}>
                            {captionText}
                        </td>
                    )}
                </tr>
            </tbody>
        </table>
    );
};
