// Аналог Angular NotificationFormComponent — информационная форма с кнопкой действия

import React from 'react';
import { useViewer } from '../hooks/useViewer';
import { BaseForm } from './BaseForm';

export interface NotificationFormProps {
    visible: boolean;
    onClose: () => void;
}

export const NotificationForm: React.FC<NotificationFormProps> = ({ visible, onClose }) => {
    const { model } = useViewer();
    const opts = model.notificationFormOptions;

    const handleAction = () => {
        if (opts?.action) {
            opts.action();
        } else {
            onClose();
        }
    };

    const handleClose = () => {
        if (opts?.cancelAction) {
            opts.cancelAction();
        }
        onClose();
    };

    const [btnOver, setBtnOver] = React.useState(false);

    return (
        <BaseForm
            name="notificationForm"
            caption={model.loc?.('Viewer') ?? 'Viewer'}
            visible={visible}
            level={4}
            defaultTop={150}
            showButtons={false}
            onOk={handleAction}
            onClose={handleClose}
        >
            <table cellPadding={0} cellSpacing={0} style={{ minWidth: 300 }}>
                <tbody>
                    {opts?.image && (
                        <tr>
                            <td style={{ textAlign: 'center', paddingTop: 20 }}>
                                <img
                                    src={model.img?.(opts.image) ?? ''}
                                    alt=""
                                    style={{ width: 112, height: 112 }}
                                />
                            </td>
                        </tr>
                    )}
                    {opts?.message && (
                        <tr>
                            <td>
                                <div
                                    className="stiJsViewerNotificationFormMessage"
                                    style={{ padding: '10px 20px', textAlign: 'center', fontSize: 14, fontWeight: 600 }}
                                >
                                    {opts.message}
                                </div>
                            </td>
                        </tr>
                    )}
                    {opts?.description && (
                        <tr>
                            <td>
                                <div
                                    className="stiJsViewerNotificationFormDescription"
                                    style={{ padding: '0 20px 10px', textAlign: 'center', fontSize: 12, color: '#666' }}
                                >
                                    {opts.description}
                                </div>
                            </td>
                        </tr>
                    )}
                    <tr>
                        <td style={{ textAlign: 'center' }}>
                            <button
                                onClick={handleAction}
                                onMouseOver={() => setBtnOver(true)}
                                onMouseOut={() => setBtnOver(false)}
                                className="stiJsViewerLoginButton"
                                style={{
                                    margin: '20px 30px 30px',
                                    minWidth: 200, height: 40,
                                    fontSize: 14, cursor: 'pointer',
                                    border: '1px solid #aaa', borderRadius: 3,
                                    background: btnOver ? '#e0e0e0' : '#f0f0f0',
                                }}
                            >
                                {opts?.buttonCaption ?? 'OK'}
                            </button>
                        </td>
                    </tr>
                </tbody>
            </table>
        </BaseForm>
    );
};
