// Аналог Angular PasswordFormComponent — форма ввода пароля при открытии файла

import React, { useState, useEffect } from 'react';
import { useViewer } from '../hooks/useViewer';
import { BaseForm } from './BaseForm';
import { StiTextBox } from '../controls/TextBox';

export interface PasswordFormProps {
    visible: boolean;
    formData?: any;
    onSubmit: (password: string, formData?: any) => void;
    onClose: () => void;
}

export const PasswordForm: React.FC<PasswordFormProps> = ({ visible, formData, onSubmit, onClose }) => {
    const { model } = useViewer();
    const [password, setPassword] = useState('');

    // Сбросить пароль при каждом открытии формы
    useEffect(() => {
        if (visible) { setPassword(''); }
    }, [visible]);

    const caption = (model.loc?.('PasswordSaveReport') ?? 'Password').replace(':', '');

    const handleOk = () => {
        onSubmit(password, formData);
        onClose();
    };

    return (
        <BaseForm
            name="passwordForm"
            caption={caption}
            visible={visible}
            level={2}
            defaultTop={150}
            onOk={handleOk}
            onClose={onClose}
        >
            <table cellPadding={0} cellSpacing={0} style={{ margin: 5 }}>
                <tbody>
                    <tr>
                        <td className="stiJsViewerCaptionControls" style={{ paddingRight: 8, whiteSpace: 'nowrap' }}>
                            {model.loc?.('PasswordEnter') ?? 'Enter password:'}
                        </td>
                        <td>
                            <StiTextBox
                                type="password"
                                autocomplete="new-password"
                                width={200}
                                focusOnCreate={true}
                                value={password}
                                onChange={setPassword}
                                onEnter={handleOk}
                            />
                        </td>
                    </tr>
                </tbody>
            </table>
        </BaseForm>
    );
};
