// Аналог Angular ButtonComponent — универсальная кнопка просмотрщика

import React, { useState, useRef } from 'react';
import { useViewer } from '../hooks/useViewer';

export interface ButtonProps {
    caption?: string;
    imageName?: string;
    arrow?: 'Up' | 'Down' | null;
    selected?: boolean;
    enabled?: boolean;
    styleName?: string;
    height?: string;
    width?: string;
    margin?: string;
    minWidth?: string;
    display?: string;
    tooltip?: string | boolean;
    closeButton?: boolean;
    onClick?: () => void;
    onClose?: () => void;
    children?: React.ReactNode;
}

export const StiButton: React.FC<ButtonProps> = ({
    caption,
    imageName,
    arrow,
    selected = false,
    enabled = true,
    styleName = 'stiJsViewerStandartSmallButton',
    height = '23px',
    width,
    margin = '1px',
    minWidth,
    display,
    tooltip,
    closeButton = false,
    onClick,
    onClose,
    children
}) => {
    const { model } = useViewer();
    const [over, setOver] = useState(false);

    const suffix = !enabled ? 'Disabled' : (selected ? 'Selected' : (over ? 'Over' : 'Default'));
    const className = styleName + ' ' + styleName + suffix;

    const imgSrc = imageName ? model.img?.(imageName) : null;
    const isTouchDevice = model.options?.isTouchDevice ?? false;
    const imgW = 16, imgH = 16;

    const handleClick = (e: React.MouseEvent) => {
        e.stopPropagation();
        if (enabled) { onClick?.(); }
    };

    return (
        <div
            className={className}
            title={typeof tooltip === 'string' ? tooltip : undefined}
            style={{
                height, width, minWidth, margin, display: display ?? 'inline-block',
                cursor: enabled ? 'pointer' : 'default',
                boxSizing: 'content-box', userSelect: 'none'
            }}
            onMouseOver={() => { if (enabled) setOver(true); }}
            onMouseOut={() => setOver(false)}
            onClick={handleClick}
        >
            <table cellPadding={0} cellSpacing={0} style={{ height: '100%', width: '100%' }}>
                <tbody>
                    <tr>
                        {/* Иконка */}
                        {imgSrc && (
                            <td style={{ lineHeight: 0, padding: '0 3px', textAlign: 'center' }}>
                                <img
                                    src={imgSrc} alt=""
                                    style={{ width: imgW, height: imgH, opacity: enabled ? 1 : 0.5 }}
                                />
                            </td>
                        )}
                        {/* Текст */}
                        {caption != null && (
                            <td style={{ whiteSpace: 'nowrap', textAlign: 'left', padding: '1px 5px' }}>
                                {caption}
                            </td>
                        )}
                        {/* Стрелка */}
                        {arrow && (
                            <td style={{ lineHeight: 0 }}>
                                <img
                                    src={model.img?.(`Arrows.SmallArrow${arrow}.png`) ?? ''}
                                    alt=""
                                    style={{ width: 8, height: 8, padding: caption ? '0 5px' : '0 5px 0 2px', opacity: enabled ? 1 : 0.5 }}
                                />
                            </td>
                        )}
                        {/* Кнопка закрытия */}
                        {closeButton && (
                            <td style={{ lineHeight: 0 }}>
                                <StiButton
                                    imageName="CloseForm.png"
                                    margin="0 2px 0 0"
                                    width={isTouchDevice ? '22px' : '17px'}
                                    height={isTouchDevice ? '22px' : '17px'}
                                    onClick={() => { onClose?.(); }}
                                />
                            </td>
                        )}
                        {children && <td>{children}</td>}
                    </tr>
                </tbody>
            </table>
        </div>
    );
};
