// Аналог Angular ResourcesPanelComponent
// Панель ресурсов отчёта: кнопки с иконкой, именем и размером файла

import React, { useState } from 'react';
import { useViewer } from '../hooks/useViewer';
import { StiReactControllerService } from '../services/controller.service';

// ─── Конвертер размера файла ──────────────────────────────────────────────────

function humanFileSize(bytes: number, decimals = 1): string {
    if (!bytes) { return '0 B'; }
    const k = 1024;
    const dm = decimals < 0 ? 0 : decimals;
    const sizes = ['B', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(dm)) + ' ' + sizes[i];
}

// ─── Кнопка ресурса ───────────────────────────────────────────────────────────

interface ResourceButtonProps {
    resource: any;
    onView: (name: string) => void;
    onSave: (name: string) => void;
}

const ResourceButton: React.FC<ResourceButtonProps> = ({ resource, onView, onSave }) => {
    const { model } = useViewer();
    const [over, setOver] = useState(false);
    const [menuOpen, setMenuOpen] = useState(false);

    const imgName = model.img?.('BigResource' + resource.type + '.png')
        ? 'BigResource' + resource.type + '.png'
        : 'BigResource.png';

    const loc = (k: string) => model.loc?.(k) ?? k;

    return (
        <div style={{ position: 'relative', display: 'inline-block' }}>
            <div
                className={`stiJsViewerFormButton stiJsViewerFormButton${over ? 'Over' : 'Default'}`}
                style={{
                    display: 'inline-flex', alignItems: 'center', gap: 6,
                    padding: '3px 8px 3px 4px', margin: '3px 0 3px 3px',
                    cursor: 'pointer', minWidth: 80
                }}
                onMouseOver={() => setOver(true)}
                onMouseOut={() => { setOver(false); }}
                onClick={() => setMenuOpen(v => !v)}
            >
                <img
                    src={model.img?.(imgName) ?? ''}
                    alt=""
                    style={{ width: 32, height: 32, padding: '4px 8px 4px 4px' }}
                />
                <div style={{ lineHeight: '14px', overflow: 'hidden' }}>
                    <div style={{
                        whiteSpace: 'nowrap', overflow: 'hidden',
                        textOverflow: 'ellipsis', maxWidth: 150, fontSize: 12
                    }}>
                        {resource.name}
                    </div>
                    <div style={{ fontSize: 11, color: '#888' }}>
                        {humanFileSize(resource.size, 1)}
                    </div>
                </div>
            </div>

            {/* Контекстное меню */}
            {menuOpen && (
                <div
                    style={{
                        position: 'absolute', top: '100%', left: 0, zIndex: 100,
                        background: '#fff', border: '1px solid #ccc',
                        boxShadow: '2px 2px 6px rgba(0,0,0,0.15)', minWidth: 120
                    }}
                    onMouseLeave={() => setMenuOpen(false)}
                >
                    <div
                        className="stiJsViewerMenuItem"
                        style={{ padding: '5px 12px', cursor: 'pointer', fontSize: 12 }}
                        onClick={() => { onView(resource.name); setMenuOpen(false); }}
                    >
                        {loc('ButtonView')}
                    </div>
                    <div
                        className="stiJsViewerMenuItem"
                        style={{ padding: '5px 12px', cursor: 'pointer', fontSize: 12 }}
                        onClick={() => { onSave(resource.name); setMenuOpen(false); }}
                    >
                        {loc('SaveFile')}
                    </div>
                </div>
            )}
        </div>
    );
};

// ─── Главный компонент ────────────────────────────────────────────────────────

export const ResourcesPanel: React.FC = () => {
    const { model, controller } = useViewer();

    const visible = model.controls.resourcesPanel.visible;
    const resources: any[] = model.reportParams?.resources ?? [];

    if (!visible || resources.length === 0) { return null; }

    const displayMode = model.options?.toolbar?.displayMode ?? 'Simple';
    const ctrl = controller as StiReactControllerService;

    const handleView = (name: string) => {
        const allowedInBrowser = ['Image', 'Pdf', 'Txt'];
        const res = resources.find((r: any) => r.name === name);
        const viewType = res && allowedInBrowser.includes(res.type) && !model.options?.jsMode
            ? 'View' : 'SaveFile';
        ctrl.postReportResource(name, viewType);
    };

    const handleSave = (name: string) => {
        ctrl.postReportResource(name, 'SaveFile');
    };

    return (
        <div
            className={`stiJsViewerToolBar${displayMode === 'Separated' ? ' stiJsViewerToolBarSeparated' : ''}`}
            style={{ zIndex: 3, fontFamily: model.options?.toolbar?.fontFamily }}
        >
            <div style={{ paddingTop: displayMode === 'Simple' ? 2 : 0 }}>
                <div
                    className="stiJsViewerToolBarTable"
                    style={{
                        boxSizing: 'border-box', display: 'table',
                        border: displayMode === 'Separated' ? '0' : undefined
                    }}
                >
                    <table cellPadding={0} cellSpacing={0}>
                        <tbody>
                            <tr>
                                {resources.map((res: any, i: number) => (
                                    <td key={i}>
                                        <ResourceButton
                                            resource={res}
                                            onView={handleView}
                                            onSave={handleSave}
                                        />
                                    </td>
                                ))}
                            </tr>
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};
