// Аналог Angular PageService
// Вычисляет layout (позиции/размеры) всех панелей просмотрщика

import { StiReactModelService } from './model.service';

export interface Rectangle {
    top: number;
    left: number;
    right: number;
    bottom: number;
    width: number;
    height: number;
}

function emptyRect(): Rectangle {
    return { top: 0, left: 0, right: 0, bottom: 0, width: 0, height: 0 };
}

export class StiReactPageService {

    constructor(private model: StiReactModelService) { }

    /**
     * Вычислить layout — аналог calculateLayoutInner().
     * Возвращает прямоугольник для панели отчёта.
     */
    public calculateLayout(): Rectangle {
        const reportLayout = emptyRect();
        const panelEl = this.model.controls.reportPanelElement;
        const options = this.model.options;

        if (!panelEl) { return reportLayout; }

        const reportParams = this.model.reportParams;
        const isMobile = options?.isMobileDevice ?? false;
        const autoHide = options?.toolbar?.autoHide ?? false;
        const displayMode = options?.toolbar?.displayMode ?? 'Simple';

        if (reportParams?.type === 'Report') {
            // Toolbar
            const toolbarVisible = this.model.controls.toolbar?.visible && !(isMobile && autoHide);
            if (toolbarVisible) {
                const toolbarEl = panelEl.previousElementSibling as HTMLElement;
                reportLayout.top += toolbarEl?.offsetHeight ?? 0;
            }

            // DrillDown panel
            if (this.model.controls.drillDownPanel?.visible) {
                reportLayout.top += this.getControlHeight('drillDownPanel');
            }

            // Find panel
            if (this.model.controls.findPanel?.visible) {
                reportLayout.top += this.getControlHeight('findPanel');
            }

            // Resources panel
            if (this.model.controls.resourcesPanel?.visible) {
                reportLayout.top += this.getControlHeight('resourcesPanel');
            }

            // Bookmarks panel
            if (this.model.controls.bookmarksPanel?.visible) {
                reportLayout.left += options?.appearance?.bookmarksTreeWidth ?? 200;
                if (displayMode === 'Simple') { reportLayout.left += 2; }
            }

            // Navigate panel
            const navVisible = this.model.controls.navigatePanel?.visible && !(isMobile && autoHide);
            if (navVisible) {
                reportLayout.bottom = this.getControlHeight('navigatePanel');
            }
        }

        // Parameters panel
        if (this.model.controls.parametersPanel?.visible) {
            const position = options?.appearance?.currentParametersPanelPosition ?? 'Top';
            if (position === 'Left') {
                const paramsWidth = this.getControlWidth('parametersPanel');
                reportLayout.left += paramsWidth;
                if (displayMode === 'Simple') { reportLayout.left += 2; }
            } else if (position === 'Top') {
                reportLayout.top += this.getControlHeight('parametersPanel');
            }
        }

        if (displayMode === 'Simple' && reportLayout.top > 0) {
            reportLayout.top += 2;
        }

        // Итоговые размеры
        reportLayout.width  = panelEl.offsetWidth  - reportLayout.left - reportLayout.right;
        reportLayout.height = panelEl.offsetHeight - reportLayout.top  - reportLayout.bottom;

        return reportLayout;
    }

    /**
     * Вычислить zoom по ширине первой страницы.
     */
    public getZoomByPageWidth(reportLayout: Rectangle): number {
        const zoom = this.getCurrentZoom();
        const pageEl = this.getFirstPageElement();
        if (!pageEl) { return zoom; }
        return (reportLayout.width - 40) * zoom / pageEl.offsetWidth;
    }

    /**
     * Вычислить zoom по высоте первой страницы.
     */
    public getZoomByPageHeight(reportLayout: Rectangle): number {
        const zoom = this.getCurrentZoom();
        const pageEl = this.getFirstPageElement();
        if (!pageEl) { return zoom; }
        return (reportLayout.height - 40) * zoom / pageEl.offsetHeight;
    }

    private getCurrentZoom(): number {
        const z = this.model.reportParams?.zoom;
        return (z == null || z < 0) ? 100 : z;
    }

    private getFirstPageElement(): HTMLElement | null {
        const viewMode = this.model.reportParams?.viewMode;
        const pageIndex = viewMode === 'SinglePage' ? 0 : (this.model.reportParams?.pageNumber ?? 0);
        return this.model.pages[pageIndex]?.page ?? null;
    }

    private getControlHeight(controlName: string): number {
        // В React мы не используем Angular ElementRef, поэтому ищем элемент по CSS-классу
        const el = document.querySelector(`.stiJsViewer${this.capitalize(controlName)}`) as HTMLElement;
        return el?.offsetHeight ?? 0;
    }

    private getControlWidth(controlName: string): number {
        const el = document.querySelector(`.stiJsViewer${this.capitalize(controlName)}`) as HTMLElement;
        return el?.offsetWidth ?? 0;
    }

    private capitalize(str: string): string {
        return str.charAt(0).toUpperCase() + str.slice(1);
    }
}
