// Аналог Angular BookmarksPanelComponent
// Дерево закладок (bookmarks tree) с раскрываемыми узлами

import React, { useState } from 'react';
import { useViewer } from '../hooks/useViewer';
import { BookmarkNode } from '../services/model.service';

interface TreeNodeProps {
    node: BookmarkNode;
    isLast: boolean;
    level: number;
}

const TreeNode: React.FC<TreeNodeProps> = ({ node, isLast, level }) => {
    const { model, controller } = useViewer();
    const [open, setOpen] = useState(true);
    const hasChildren = (node.children?.length ?? 0) > 0;

    const handleClick = () => {
        controller.postViewerEvent('BookmarkClick', { stiweb_bookmarkAnchor: node.url });
    };

    const imgSize = 16;
    const folderSrc = open ? model.img?.('FolderOpen.png') : model.img?.('Folder.png');
    const nodeSrc = model.img?.('Node.png');

    return (
        <div style={{ paddingLeft: level > 0 ? 18 : 0 }}>
            <div
                style={{ display: 'flex', alignItems: 'center', padding: '2px 0', cursor: 'pointer', whiteSpace: 'nowrap' }}
            >
                {/* Toggle */}
                {hasChildren ? (
                    <span
                        onClick={e => { e.stopPropagation(); setOpen(!open); }}
                        style={{ marginRight: 2, fontSize: 10, color: '#666', userSelect: 'none', minWidth: 12 }}
                    >
                        {open ? '▼' : '▶'}
                    </span>
                ) : (
                    <span style={{ minWidth: 14 }} />
                )}

                {/* Icon */}
                {hasChildren ? (
                    folderSrc
                        ? <img src={folderSrc} alt="" style={{ width: imgSize, height: imgSize, marginRight: 4 }} />
                        : <span style={{ marginRight: 4 }}>{open ? '📂' : '📁'}</span>
                ) : (
                    nodeSrc
                        ? <img src={nodeSrc} alt="" style={{ width: imgSize, height: imgSize, marginRight: 4 }} />
                        : <span style={{ marginRight: 4 }}>📄</span>
                )}

                {/* Title */}
                <a
                    onClick={handleClick}
                    style={{ cursor: 'pointer', color: '#0066cc', textDecoration: 'none', fontSize: 13 }}
                >
                    {node.title}
                </a>
            </div>

            {/* Children */}
            {hasChildren && open && (
                <div>
                    {node.children!.map((child, i) => (
                        <TreeNode
                            key={i}
                            node={child}
                            isLast={i === node.children!.length - 1}
                            level={level + 1}
                        />
                    ))}
                </div>
            )}
        </div>
    );
};

export const BookmarksPanel: React.FC = () => {
    const { model } = useViewer();

    const visible = model.controls.bookmarksPanel?.visible ?? false;
    if (!visible || !model.nodes?.length) { return null; }

    const opts = model.options;
    const width = opts?.appearance?.bookmarksTreeWidth ?? 220;
    const displayMode = opts?.toolbar?.displayMode ?? 'Simple';
    const bgColor = opts?.toolbar?.backgroundColor ?? '#f9f9f9';
    const borderColor = opts?.toolbar?.borderColor ?? '#ccc';
    const fontFamily = opts?.toolbar?.fontFamily ?? 'inherit';

    const rootImg = model.img?.('BookmarksRoot.png');

    return (
        <div
            className={'stiJsViewerBookmarksPanel' + (displayMode === 'Separated' ? ' stiJsViewerBookmarksPanelSeparated' : '')}
            style={{
                width, minWidth: width, flexShrink: 0,
                background: bgColor,
                borderRight: `1px solid ${borderColor}`,
                overflow: 'auto',
                fontFamily,
                fontSize: 13,
                padding: '6px 8px',
                boxSizing: 'border-box'
            }}
        >
            {/* Корневой узел */}
            <div style={{ display: 'flex', alignItems: 'center', gap: 4, marginBottom: 4 }}>
                {rootImg
                    ? <img src={rootImg} alt="" style={{ width: 16, height: 16 }} />
                    : <span>🔖</span>
                }
                <strong style={{ fontSize: 13 }}>
                    {model.loc?.('Bookmarks') ?? 'Bookmarks'}
                </strong>
            </div>

            {/* Дерево */}
            {model.nodes.map((node, i) => (
                <TreeNode
                    key={i}
                    node={node}
                    isLast={i === model.nodes.length - 1}
                    level={0}
                />
            ))}
        </div>
    );
};
