// Аналог Angular ControllerService
// Оркестрирует всю логику просмотрщика: загрузку, события, действия

import { StiReactModelService } from './model.service';
import { StiReactHttpClientService } from './http-client.service';
import { StiReactStylesService } from './styles.service';
import { StiReactAnimationService } from './animation.service';
import { StiReactPrintService } from './print.service';
import { StiReactHelperService } from './helper.service';
import { StiReactEditableFieldsService } from './editable-fields.service';

type MessageHandler = (message: ViewerMessage) => void;

export interface ViewerMessage {
    action: string;
    data?: any;
}

export class StiReactControllerService {

    private _handlers: MessageHandler[] = [];
    private _actionHandlers: MessageHandler[] = [];
    private _stateUpdateCallback: (() => void) | null = null;

    /** Сервис стилей — инициализируется после создания контроллера */
    public stylesService: StiReactStylesService | null = null;
    /** Сервис анимации — для scrollToPage */
    private animationService: StiReactAnimationService;
    /** Сервис печати */
    public printService: StiReactPrintService;
    /** Сервис утилит */
    private helperService: StiReactHelperService;
    /** Сервис редактирования полей */
    public editableFieldsService: StiReactEditableFieldsService;

    constructor(
        private model: StiReactModelService,
        private httpClient: StiReactHttpClientService
    ) {
        // Создаём styles service здесь, чтобы не создавать циклическую зависимость
        this.stylesService = new StiReactStylesService(model);
        this.animationService = new StiReactAnimationService(model);
        this.helperService = new StiReactHelperService(model, this.animationService);
        this.printService = new StiReactPrintService(model, this.helperService, httpClient, this);
        this.editableFieldsService = new StiReactEditableFieldsService(this, model, this.helperService);
        // Poll for errors and pending bookmark navigation (same as Angular setInterval)
        setInterval(() => {
            if (this.model.httpError) {
                const err = this.model.httpError;
                this.showError(err?.error?.text || err?.message || 'Unknown error');
                this.model.httpError = null;
            }
            if (this.model.navigateNode) {
                this.postBookmarkNodeAction(this.model.navigateNode);
                this.model.navigateNode = null;
            }
        }, 250);
    }

    // Register a React state-update trigger so controller can force re-renders
    public setStateUpdateCallback(cb: () => void) {
        this._stateUpdateCallback = cb;
    }

    public triggerUpdate() {
        this._stateUpdateCallback?.();
    }

    // Subscribe to viewer messages (component load, report load, etc.)
    public onMessage(handler: MessageHandler) {
        this._handlers.push(handler);
        return () => { this._handlers = this._handlers.filter(h => h !== handler); };
    }

    // Subscribe to action messages (errors, exports, email, print, design)
    public onAction(handler: MessageHandler) {
        this._actionHandlers.push(handler);
        return () => { this._actionHandlers = this._actionHandlers.filter(h => h !== handler); };
    }

    private emit(message: ViewerMessage) {
        this._handlers.forEach(h => h(message));
    }

    private emitAction(message: ViewerMessage) {
        this._actionHandlers.forEach(h => h(message));
    }

    /** Публичный вариант emitAction — для компонентов, которым нужно послать событие вверх */
    public emitActionPublic(action: string, data: any) {
        this.emitAction({ action, data });
    }

    // Load viewer — first call to backend (InitViewer)
    public async loadViewer() {
        try {
            this.model.showProgress = true;
            this.triggerUpdate();

            const data = await this.httpClient.post(this.model.action, {
                stiweb_component: 'Viewer',
                stiweb_imagesScalingFactor: window.devicePixelRatio > 1 ? 2 : 1,
                properties: this.model.properties
                    ? btoa(JSON.stringify(this.model.properties))
                    : undefined
            });

            await this.processResponse(data);
            this.emit({ action: 'viewer_loaded', data });

            // After InitViewer, automatically request the report (same as Angular flow)
            await this.postViewerEvent('GetReport', {
                properties: this.model.properties
                    ? btoa(JSON.stringify(this.model.properties))
                    : undefined
            });
        } catch (e) {
            this.model.showProgress = false;
            this.triggerUpdate();
        }
    }

    // Handle viewer events (user interactions -> backend)
    public async postViewerEvent(action: string, params: Record<string, any> = {}) {
        console.log('[Controller] postViewerEvent:', action, '| params:', JSON.stringify(params));
        try {
            this.model.showProgress = true;
            this.triggerUpdate();

            const data = await this.httpClient.post('ViewerEvent', {
                stiweb_component: 'Viewer',
                stiweb_action: action,
                ...params
            });

            // Binary result (export/print file download)
            if (data?.isBinary) {
                this.downloadFile(data.blob, data.contentType);
                this.model.showProgress = false;
                this.triggerUpdate();
                return;
            }

            await this.processResponse(data);
        } catch (e) {
            this.model.showProgress = false;
            this.triggerUpdate();
        }
    }

    private async processResponse(data: any) {
        if (!data) return;
        console.log('[Controller] processResponse action:', data?.action,
            '| reportParams action:', data?.reportParams?.action,
            '| pagesArray len:', (data?.pagesArray ?? data?.reportParams?.pagesArray)?.length ?? 0,
            '| clientGuid in response:', data?.clientGuid ?? data?.reportParams?.clientGuid ?? '(none)',
            '| ALL keys:', Object.keys(data ?? {}));

        // Если сервер вернул свой clientGuid — используем его для всех дальнейших запросов
        const serverGuid = data?.clientGuid ?? data?.reportParams?.clientGuid;
        if (serverGuid && serverGuid !== this.model.clientGuid) {
            console.log('[Controller] Updating clientGuid from server:', serverGuid);
            (this.model as any)._clientGuid = serverGuid;
        }

        // Apply options from InitViewer response.
        // Stimulsoft serializes C# object StiReactViewerOptions which may use PascalCase
        // property names (e.g. "Toolbar", "Appearance") in JSON.
        // We normalise everything to camelCase nested sub-objects that our components expect.
        if (data.options || data.jsOptions) {
            const raw = data.options ?? {};
            const js  = data.jsOptions ?? {};

            // Helper: get property case-insensitively
            const getProp = (obj: any, key: string): any => {
                if (obj == null) return undefined;
                if (obj[key] !== undefined) return obj[key];
                const upper = key.charAt(0).toUpperCase() + key.slice(1);
                if (obj[upper] !== undefined) return obj[upper];
                const lower = key.charAt(0).toLowerCase() + key.slice(1);
                return obj[lower];
            };

            // Extract toolbar settings — try nested object first (camelCase & PascalCase),
            // then fall back to flat root-level properties
            const rawToolbar = getProp(raw, 'toolbar') ?? getProp(raw, 'Toolbar') ?? {};
            const rawAppearance = getProp(raw, 'appearance') ?? getProp(raw, 'Appearance') ?? {};

            const toolbar = {
                visible:              getProp(rawToolbar, 'visible')              ?? getProp(raw, 'showToolbar')             ?? true,
                showPrintButton:      getProp(rawToolbar, 'showPrintButton')      ?? getProp(raw, 'showPrintButton')         ?? true,
                showSaveButton:       getProp(rawToolbar, 'showSaveButton')       ?? getProp(raw, 'showSaveButton')          ?? true,
                showOpenButton:       getProp(rawToolbar, 'showOpenButton')       ?? getProp(raw, 'showOpenButton')          ?? false,
                showSendEmailButton:  getProp(rawToolbar, 'showSendEmailButton')  ?? getProp(raw, 'showSendEmailButton')     ?? false,
                showFindButton:       getProp(rawToolbar, 'showFindButton')       ?? getProp(raw, 'showFindButton')          ?? true,
                showBookmarksButton:  getProp(rawToolbar, 'showBookmarksButton')  ?? getProp(raw, 'showBookmarksButton')     ?? true,
                showParametersButton: getProp(rawToolbar, 'showParametersButton') ?? getProp(raw, 'showParametersButton')    ?? true,
                showDesignButton:     getProp(rawToolbar, 'showDesignButton')     ?? getProp(raw, 'showDesignButton')        ?? false,
                showAboutButton:      getProp(rawToolbar, 'showAboutButton')      ?? getProp(raw, 'showAboutButton')         ?? true,
                showFullScreenButton: getProp(rawToolbar, 'showFullScreenButton') ?? getProp(raw, 'showFullScreenButton')    ?? true,
                showZoomButton:       getProp(rawToolbar, 'showZoomButton')       ?? getProp(raw, 'showZoomButton')          ?? true,
                showViewModeButton:   getProp(rawToolbar, 'showViewModeButton')   ?? getProp(raw, 'showViewModeButton')      ?? true,
                showFirstPageButton:      getProp(rawToolbar, 'showFirstPageButton')      ?? getProp(raw, 'showFirstPageButton')         ?? true,
                showPreviousPageButton:   getProp(rawToolbar, 'showPreviousPageButton')   ?? getProp(raw, 'showPreviousPageButton')      ?? true,
                showCurrentPageControl:   getProp(rawToolbar, 'showCurrentPageControl')   ?? getProp(raw, 'showCurrentPageControl')      ?? true,
                showNextPageButton:       getProp(rawToolbar, 'showNextPageButton')       ?? getProp(raw, 'showNextPageButton')          ?? true,
                showLastPageButton:       getProp(rawToolbar, 'showLastPageButton')       ?? getProp(raw, 'showLastPageButton')          ?? true,
                showPinToolbarButton:     getProp(rawToolbar, 'showPinToolbarButton')     ?? getProp(raw, 'showPinToolbarButton')        ?? false,
                showEditorButton:         getProp(rawToolbar, 'showEditorButton')         ?? getProp(raw, 'showEditorButton')            ?? false,
                showResourcesButton:      getProp(rawToolbar, 'showResourcesButton')      ?? getProp(raw, 'showResourcesButton')        ?? false,
                showButtonCaptions:       getProp(rawToolbar, 'showButtonCaptions')       ?? getProp(raw, 'showButtonCaptions')          ?? false,
                printDestination:         getProp(rawToolbar, 'printDestination')         ?? getProp(raw, 'printDestination')            ?? 'Default',
                autoHide:                 getProp(rawToolbar, 'autoHide')                 ?? getProp(raw, 'autoHide')                    ?? false,
                displayMode:          getProp(rawToolbar, 'displayMode')          ?? 'Simple',
                backgroundColor:      getProp(rawToolbar, 'backgroundColor')      ?? null,
                borderColor:          getProp(rawToolbar, 'borderColor')          ?? null,
                fontColor:            getProp(rawToolbar, 'fontColor')            ?? null,
                fontFamily:           getProp(rawToolbar, 'fontFamily')           ?? null,
            };

            const appearance = {
                scrollbarsMode:                  getProp(rawAppearance, 'scrollbarsMode')                  ?? getProp(raw, 'scrollbarsMode')              ?? true,
                backgroundColor:                 getProp(rawAppearance, 'backgroundColor')                 ?? getProp(raw, 'backgroundColor')             ?? '#c6c6c6',
                fullScreenMode:                  getProp(rawAppearance, 'fullScreenMode')                  ?? false,
                currentParametersPanelPosition:  getProp(rawAppearance, 'currentParametersPanelPosition')  ?? getProp(rawAppearance, 'parametersPanelPosition') ?? 'Top',
                reportDisplayMode:               getProp(rawAppearance, 'reportDisplayMode')               ?? 'OnePage',
                printToPdfMode:                  getProp(rawAppearance, 'printToPdfMode')                  ?? 'Hidden',
                rightToLeft:                     getProp(rawAppearance, 'rightToLeft')                     ?? false,
                saveMenuImageSize:               getProp(rawAppearance, 'saveMenuImageSize')               ?? 'Small',
            };

            // ВАЖНО: viewerId устанавливается только ОДИН РАЗ (из InitViewer).
            // Если мы уже знаем viewerId — сохраняем его, иначе берём из ответа.
            // Это критично: CSS от сервера scoped к конкретному viewerId (#viewerXXX),
            // и если DOM-элемент получит другой id — стили не применятся.
            const existingViewerId = this.model.options?.viewerId;
            const newViewerId = getProp(js, 'viewerId') ?? getProp(raw, 'viewerId');
            const stableViewerId = existingViewerId ?? newViewerId;

            // Нормализуем exports: сервер может прислать PascalCase ключи (Exports.ShowExportToPdf),
            // а toolbar.service.ts ожидает camelCase (exports.showExportToPdf).
            // Angular решает это через рекурсивный toLower() — повторяем аналогично.
            const rawExports = getProp(raw, 'exports') ?? getProp(raw, 'Exports') ?? {};
            const exports = this.toLowerKeys(rawExports);

            // defaultSettings приходит от сервера (для определения HtmlType, ExcelType и т.д.)
            if (data.defaultSettings) {
                exports.defaultSettings = data.defaultSettings;
            }

            const merged: any = {
                ...raw,
                ...js,
                toolbar,
                appearance,
                exports,
                viewerId: stableViewerId,
                cultureName: getProp(js, 'cultureName') ?? getProp(raw, 'cultureName'),
            };

            this.model.options = merged;
        }

        // Apply localization data
        if (data.loc)           this.model.localization         = data.loc;
        if (data.images)        this.model.images               = data.images;
        if (data.months)        this.model.months               = data.months;
        if (data.dayOfWeek)     this.model.dayOfWeek            = data.dayOfWeek;
        if (data.dateRanges)    this.model.dateRanges           = data.dateRanges;
        if (data.encodingData)  this.model.encodingData         = data.encodingData;
        if (data.paperSizes)    this.model.paperSizes           = data.paperSizes;
        if (data.pdfSecurityCertificates) this.model.pdfSecurityCertificates = data.pdfSecurityCertificates;

        // Report data (GetReport returns fields at top level, not inside reportParams)
        if (data.reportParams) {
            this.model.reportParams = data.reportParams;
        } else if (data.reportFileName || data.pagesCount != null) {
            // Stimulsoft GetReport/DrillDown response: fields are at root level.
            // Аналог Angular reportParams setter — копируем все поля из ответа
            const current = this.model.reportParams;
            this.model.setReportParams({
                ...current,
                type:              data.reportType     ?? current.type,
                reportType:        data.reportType     ?? current.reportType,
                reportFileName:    data.reportFileName  ?? current.reportFileName,
                pagesCount:        data.pagesCount      ?? current.pagesCount,
                zoom:              data.zoom            ?? current.zoom     ?? 100,
                viewMode:          data.viewMode        ?? current.viewMode ?? 'SinglePage',
                resources:         data.resources       ?? current.resources,
                exportSettings:    data.exportSettings  ?? current.exportSettings,
                // DrillDown-критичные поля (аналог Angular setter)
                drillDownGuid:           data.drillDownGuid           ?? current.drillDownGuid,
                dashboardDrillDownGuid:  data.dashboardDrillDownGuid  ?? current.dashboardDrillDownGuid,
                collapsingStates:        data.collapsingStates        ?? current.collapsingStates,
                bookmarksContent:        data.bookmarksContent        ?? current.bookmarksContent,
                tableOfContentsPointers: data.tableOfContentsPointers ?? current.tableOfContentsPointers,
                isEditableReport:        data.isEditableReport        ?? current.isEditableReport,
            });
        }

        // Гарантируем дефолтный zoom=100 — без него сервер вернёт sizes "0;0"
        if (!this.model.reportParams.zoom) {
            this.model.reportParams.zoom = 100;
        }

        // Pages HTML — Stimulsoft uses "pagesArray" field name.
        // ВАЖНО: GetPagesArray() в C# добавляет в конец массива:
        //   предпоследний элемент = строка CSS-стилей (может быть scoped "#viewerId ...")
        //   последний элемент     = строка chart-скриптов
        // Нужно извлечь их отдельно, а не рендерить как страницы.
        const rawArray: any[] = data.pagesArray ?? data.pages ?? [];
        if (rawArray.length > 0) {
            // Последние два элемента — строки (CSS + chart script). Страницы — объекты.
            // Ищем с конца: берём строки-хвост, остальное — страницы.
            let pagesEndIdx = rawArray.length;
            // Стили: предпоследний или последний могут быть строками
            const last       = rawArray[rawArray.length - 1];
            const secondLast = rawArray.length >= 2 ? rawArray[rawArray.length - 2] : null;

            let chartScript: string | null = null;
            let cssStyles: string | null   = null;

            if (typeof last === 'string') {
                chartScript = last;
                pagesEndIdx--;
                if (typeof secondLast === 'string') {
                    cssStyles = secondLast;
                    pagesEndIdx--;
                }
            }

            this.model.pages = rawArray.slice(0, pagesEndIdx);

            // Применяем CSS-стили из pagesArray (scoped CSS для страниц отчёта)
            if (cssStyles && this.stylesService) {
                this.stylesService.setupStyle(cssStyles, 'pagesCss');
            }
            // Сохраняем chart scripts для отложенного выполнения ПОСЛЕ React-рендеринга
            // (chartScript создаёт SVG-элементы, которые должны быть привязаны к DOM-узлам страниц)
            if (chartScript) {
                this.model.pendingChartScript = chartScript;
            }
        }

        // Bookmarks — Stimulsoft uses "bookmarksContent" field name
        if (data.bookmarksContent) {
            this.model.nodes = data.bookmarksContent;
        } else if (data.bookmarks) {
            this.model.nodes = data.bookmarks;
        }

        // CSS стили из отдельного поля (base64-encoded, от InitViewer)
        if (data.styles && this.stylesService) {
            try {
                const decoded = atob(data.styles);
                this.stylesService.setupStyle(decoded, 'viewerCss');
            } catch {
                this.stylesService.setupStyle(data.styles, 'viewerCss');
            }
        } else if (data.css && this.stylesService) {
            try {
                const decoded = atob(data.css);
                this.stylesService.setupStyle(decoded, 'viewerCss');
            } catch {
                this.stylesService.setupStyle(data.css, 'viewerCss');
            }
        }

        // Chart scripts из отдельного поля (если не извлечены из pagesArray)
        if (data.chartScript) {
            this.model.pendingChartScript = data.chartScript;
        }

        // Кастомные шрифты
        if (data.customFonts && this.stylesService) {
            this.stylesService.addCustomFontStyles(data.customFonts);
        }

        // Interactions (parameters panel)
        if (data.interactions) {
            this.model.interactions = data.interactions;
            if (data.interactions.paramsVariables != null) {
                this.model.controls.parametersPanel.visible = true;
            }
        }

        // Password form request
        if (data.action === 'PasswordForm') {
            this.showForm('passwordForm', data);
        }

        // Notification form
        if (data.notificationFormOptions) {
            this.model.notificationFormOptions = data.notificationFormOptions;
            this.showForm('notificationForm');
        }

        this.model.showProgress = false;
        this.triggerUpdate();

        // Emit appropriate action message
        const action = data.action || data.reportParams?.action;
        if (action) {
            this.emit({ action, data });
        }

        // После GetReport/OpenReport — запросить параметры отчёта (аналог Angular InitVars)
        // Angular делает это в report-panel.component.ts после получения GetReport
        if ((data.action === 'GetReport' || data.action === 'OpenReport') &&
            !this.model.options?.isParametersReceived) {
            const reportType = data.reportType ?? this.model.reportParams?.reportType ?? this.model.reportParams?.type;
            const showParams = this.model.options?.toolbar?.showParametersButton ?? true;
            if (showParams) {
                // Небольшая задержка как в Angular (setTimeout(() => {...}))
                setTimeout(() => this.loadInitVars(), 0);
            }
        }

        // Обработка печати (HTML-based: PrintWithPreview / PrintWithoutPreview)
        if (data.action === 'PrintReport' && data.subAction && data.html) {
            this.printService.handlePrintResult(data.subAction, data.html);
        }

        // Обработка InitVars (параметры отчёта)
        if (data.action === 'InitVars' && data) {
            this.showParametersPanel(data);
        }
    }

    /** Запросить начальные значения параметров (аналог Angular postInteraction({action:'InitVars'})) */
    private async loadInitVars() {
        try {
            const data = await this.httpClient.post('ViewerEvent', {
                stiweb_component: 'Viewer',
                stiweb_action: 'InitVars'
            });
            if (data) {
                await this.processResponse(data);
                // Сервер не возвращает action:'InitVars' в ответе — вызываем напрямую
                if (!this.model.options?.isParametersReceived) {
                    this.showParametersPanel(data);
                }
            }
        } catch { /* ignore */ }
    }

    /** Показать панель параметров (аналог Angular InteractionsService.showParametersPanel) */
    public showParametersPanel(data: any) {
        if (!data) return;

        // data может быть самим объектом параметров или обёрткой
        const paramsVariables = data.paramsVariables ?? data;
        if (!paramsVariables || typeof paramsVariables !== 'object') return;

        this.model.options = { ...this.model.options, isParametersReceived: true };

        const countParameters = Object.keys(paramsVariables).length;
        if (countParameters === 0) return;

        const minCount = this.model.options?.appearance?.minParametersCountForMultiColumns ?? 5;
        const countColumns = countParameters <= minCount ? 1 : (this.model.options?.appearance?.parametersPanelColumnsCount ?? 1);
        let countInColumn = Math.trunc(countParameters / countColumns);
        if (countInColumn * countColumns < countParameters) countInColumn++;

        // Инициализируем список элементов
        const vars = { ...paramsVariables };
        for (const i of Object.keys(vars)) {
            const variable = vars[i];
            if (variable?.items) {
                variable.items.forEach((v: any, index: number) => {
                    let isChecked = true;
                    if (variable.value instanceof Array && !variable.allowUserValues &&
                        variable.value.indexOf(variable.items[index].value) < 0 &&
                        variable.value.indexOf(variable.items[index].key) < 0) {
                        isChecked = false;
                    }
                    if (variable.isFirstInitialization && variable.checkedStates && index < variable.checkedStates.length) {
                        isChecked = variable.checkedStates[index];
                    }
                    v.isChecked = isChecked;
                    v.visible = true;
                });
            }
            if (variable) {
                variable.isNull = variable.type === 'DateTime' && variable.value === null && variable.basicType === 'NullableValue';
            }
        }

        this.model.interactions = {
            paramsVariables: vars,
            countColumns: new Array(countColumns),
            countInColumn: new Array(countInColumn)
        };
        this.model.controls.parametersPanel.visible = true;
        this.triggerUpdate();
    }

    /** Сброс состояния viewer (аналог Angular clearViewerState) */
    private clearViewerState() {
        const rp = this.model.reportParams;
        this.model.setReportParams({
            type: 'Auto',
            pageNumber: 0,
            originalPageNumber: 0,
            zoom: rp?.zoom ?? 100,
            viewMode: rp?.viewMode ?? 'SinglePage',
            drillDownGuid: null,
            dashboardDrillDownGuid: null,
            collapsingStates: null,
            bookmarksContent: null,
            editableParameters: null,
            resources: null,
            drillDownParameters: [],
            elementName: null,
            variablesValues: null,
            tableOfContentsPointers: [],
            isEditableReport: false,
        });

        if (this.model.options) {
            this.model.options.paramsVariables = null;
            this.model.options.isParametersReceived = false;
            this.model.options.drillDownInProgress = false;
            this.model.options.displayModeFromReport = null;
        }

        this.model.pages = [];
        this.model.interactions = null;
        this.model.controls.parametersPanel.visible = false;
        this.model.controls.bookmarksPanel.visible = false;
        this.model.nodes = null;
        this.triggerUpdate();
    }

    public async postBookmarkNodeAction(node: any) {
        await this.postViewerEvent('BookmarkClick', { stiweb_bookmarkAnchor: node.url });
    }

    /**
     * Главный обработчик действий тулбара — точная копия Angular action()
     * Обновляет model.reportParams, потом вызывает getPages() или нужный запрос
     */
    public action(event: { name: string; value?: any }) {
        console.log('[Controller] action:', event.name, '| reportParams:', JSON.stringify(this.model.reportParams));
        const rp = this.model.reportParams;

        switch (event.name) {
            case 'GoToPage':
                rp.pageNumber = event.value ?? 0;
                break;
            case 'FirstPage':
                rp.pageNumber = 0;
                break;
            case 'PrevPage':
                rp.pageNumber = Math.max(0, (rp.pageNumber ?? 1) - 1);
                break;
            case 'NextPage':
                rp.pageNumber = Math.min((rp.pagesCount ?? 1) - 1, (rp.pageNumber ?? 0) + 1);
                break;
            case 'LastPage':
                rp.pageNumber = (rp.pagesCount ?? 1) - 1;
                break;

            case 'ViewModeSinglePage':    rp.viewMode = 'SinglePage';    rp.pageNumber = 0; break;
            case 'ViewModeContinuous':    rp.viewMode = 'Continuous';    rp.pageNumber = 0; break;
            case 'ViewModeMultiplePages': rp.viewMode = 'MultiplePages'; rp.pageNumber = 0; break;

            case 'Zoom25':  rp.zoom = 25;  break;
            case 'Zoom50':  rp.zoom = 50;  break;
            case 'Zoom75':  rp.zoom = 75;  break;
            case 'Zoom100': rp.zoom = 100; break;
            case 'Zoom150': rp.zoom = 150; break;
            case 'Zoom200': rp.zoom = 200; break;
            case 'ZoomOnePage':
                rp.zoom = -1; break;
            case 'ZoomPageWidth':
                rp.zoom = -2; break;

            case 'Print': {
                let format = 'PrintPdf';
                const dest = this.model.options?.toolbar?.printDestination;
                if (dest === 'Direct')      format = 'PrintWithoutPreview';
                else if (dest === 'WithPreview') format = 'PrintWithPreview';
                this.emitAction({ action: 'Print', data: { format } });
                return;
            }
            case 'PrintPdf':
            case 'PrintWithPreview':
            case 'PrintWithoutPreview':
                this.emitAction({ action: 'Print', data: { format: event.name } });
                return;

            case 'Find':
                if (this.model.controls.findPanel) {
                    this.model.controls.findPanel.visible = !this.model.controls.findPanel.visible;
                }
                this.triggerUpdate();
                return;
            case 'Bookmarks':
                if (this.model.controls.bookmarksPanel) {
                    this.model.controls.bookmarksPanel.visible = !this.model.controls.bookmarksPanel.visible;
                }
                this.triggerUpdate();
                return;
            case 'Parameters':
                if (this.model.controls.parametersPanel) {
                    this.model.controls.parametersPanel.visible = !this.model.controls.parametersPanel.visible;
                }
                this.triggerUpdate();
                return;
            case 'Resources':
                if (this.model.controls.resourcesPanel) {
                    this.model.controls.resourcesPanel.visible = !this.model.controls.resourcesPanel.visible;
                }
                this.triggerUpdate();
                return;
            case 'Editor':
                // Toggle editable fields — handled by EditableFieldsService subscription
                this.emitAction({ action: 'Editor' });
                // Trigger re-render so toolbar updates the selected state
                this.triggerUpdate();
                return;
            case 'FullScreen':
                this.emitAction({ action: 'FullScreen', data: null });
                return;
            case 'About':
                this.emitAction({ action: 'About', data: null });
                return;
            case 'Design':
                this.emitAction({ action: 'Design', data: null });
                return;
            case 'Open':
                this.model.openDialogFileMask = null;
                setTimeout(() => {
                    this.model.openDialogFileMask = '.mdc,.mdz,.mdx,.mrt,.mrz,.mrx';
                    this.triggerUpdate();
                });
                return;

            default:
                if (event.name.indexOf('saveMenu') === 0) {
                    this.emitAction({ action: 'Export', data: { format: event.name.substring(8) } });
                    return;
                }
                if (event.name.indexOf('sendEmailMenu') === 0) {
                    this.emitAction({ action: 'SendEmail', data: { format: event.name.substring(13) } });
                    return;
                }
                break;
        }

        // Навигационные действия: в Continuous mode — скроллим, иначе — запрашиваем страницы
        const isNavAction = ['FirstPage', 'PrevPage', 'NextPage', 'LastPage', 'GoToPage'].includes(event.name);
        if (isNavAction && this.pagesNavigationIsActive()) {
            this.scrollToPage();
            this.triggerUpdate();
            return;
        }

        // После обновления reportParams — запрашиваем страницы (аналог Angular getPages())
        this.postViewerEvent('GetPages', this.buildGetPagesParams());
    }

    /**
     * Аналог Angular pagesNavigationIsActive():
     * Навигация скроллом активна только в Continuous mode + scrollbarsMode/fullScreenMode
     */
    public pagesNavigationIsActive(): boolean {
        const opts = this.model.options;
        return (opts?.appearance?.fullScreenMode || opts?.appearance?.scrollbarsMode) &&
            this.model.reportParams?.viewMode === 'Continuous';
    }

    /**
     * Аналог Angular scrollToPage():
     * В Continuous mode — плавно скроллим к целевой странице
     */
    private scrollToPage() {
        if (this.model.reportParams?.viewMode !== 'Continuous') return;

        const panel = this.model.controls.reportPanelElement;
        if (!panel) return;

        const pageNumber = this.model.reportParams.pageNumber ?? 0;
        const pageEl = panel.querySelector(`[data-pageindex="${pageNumber}"]`) as HTMLElement;
        if (!pageEl) return;

        const endTime = new Date().getTime() + (this.model.options?.scrollDuration || 300);
        const targetTop = pageEl.offsetTop;
        this.animationService.showAnimationForScroll(panel, targetTop, endTime, () => {});
    }

    // Получить страницы с текущими настройками (аналог Angular getPages())
    public getPages() {
        return this.postViewerEvent('GetPages', this.buildGetPagesParams());
    }

    /** Параметры для запроса GetPages — zoom, pageNumber, viewMode и др. */
    /**
     * Рекурсивная нормализация ключей: первый символ в lowercase (аналог Angular toLower())
     * Exports.ShowExportToPdf → exports.showExportToPdf
     */
    private toLowerKeys(obj: any): any {
        if (obj === null || obj === undefined || typeof obj !== 'object' || Array.isArray(obj)) {
            return obj;
        }
        const result: any = {};
        for (const key of Object.keys(obj)) {
            const lowerKey = key.charAt(0).toLowerCase() + key.slice(1);
            const val = obj[key];
            result[lowerKey] = (typeof val === 'object' && val !== null && !Array.isArray(val))
                ? this.toLowerKeys(val)
                : val;
        }
        return result;
    }

    private buildGetPagesParams(): Record<string, any> {
        const rp = this.model.reportParams;
        return {
            zoom:       rp.zoom       ?? 100,
            pageNumber: rp.pageNumber ?? 0,
            viewMode:   rp.viewMode   ?? 'SinglePage',
            ...(rp.drillDownGuid     ? { drillDownGuid:    rp.drillDownGuid }    : {}),
            ...(rp.collapsingStates  ? { collapsingStates: JSON.stringify(rp.collapsingStates) } : {}),
        };
    }

    /**
     * Открыть файл отчёта из base64-строки (аналог Angular loadFile)
     * Вызывается из OpenDialogComponent после чтения файла через FileReader
     */
    public loadFile(fileName: string, content: string) {
        if (!content || content === '') { return; }

        // Если XML или JSON — кодируем в base64
        if (content.indexOf('<?xml') === 0 || content.indexOf('{') === 0) {
            content = btoa(content);
        }

        const base64Data = content.indexOf('base64,') > 0
            ? content.substr(content.indexOf('base64,') + 7)
            : content;

        const data: Record<string, any> = {
            openingFileName: fileName || 'Report.mdc',
            base64Data
        };

        // Зашифрованные форматы требуют пароля
        const lname = fileName.toLowerCase();
        if (lname.endsWith('.mdx') || lname.endsWith('.mrx')) {
            this.showForm('passwordForm', data);
        } else {
            // Angular: clearViewerState() + reportParams.reportFileName = fileName
            this.clearViewerState();
            this.model.reportParams.reportFileName = data.openingFileName;
            this.postViewerEvent('OpenReport', data);
        }
    }

    /**
     * Запросить ресурс отчёта (аналог Angular postReportResource)
     */
    public async postReportResource(resourceName: string, viewType: string) {
        await this.postViewerEvent('ReportResource', {
            stiweb_resource: resourceName,
            stiweb_viewType: viewType
        });
    }

    public showError(text: string | null, message?: string) {
        this.model.errorMessage = { text: text || message || 'Error' };
        this.showForm('errorMessageForm');
        this.emitAction({ action: 'Error', data: this.model.errorMessage });
    }

    public viewerResized() {
        // Trigger re-render on resize
        this.triggerUpdate();
    }

    // ─── Form management (analogue of Angular FormService) ──────────────────────

    public showForm(name: string, formData?: any) {
        this.model.form = { name, formData };
        this.triggerUpdate();
    }

    public closeForm(name?: string) {
        if (!name || this.model.form?.name === name) {
            if (this.model.form?.name === 'notificationForm' && this.model.notificationFormOptions?.action) {
                this.model.notificationFormOptions.action();
            }
            this.model.form = null;
            this.triggerUpdate();
        }
    }

    /**
     * Аналог Angular printService.postPrint():
     * Отправляет запрос печати на сервер и обрабатывает результат в зависимости от типа.
     * - PrintPdf: получаем blob PDF → открываем в iframe → window.print()
     * - PrintWithPreview: получаем HTML → открываем в popup
     * - PrintWithoutPreview: получаем HTML → скрытый iframe → window.print()
     */
    public async postPrint(printAction: string) {
        if (this.model.showDashboard) {
            // Dashboard print handled separately
            return;
        }

        // Apple touch devices: PrintPdf → export as PDF with OpenAfterExport
        if (printAction === 'PrintPdf' &&
            /iPhone|iPad|iPod|Macintosh/i.test(navigator.userAgent) &&
            this.helperService.isTouchDevice() &&
            !this.model.options?.replaceHtmlFormWithRequest) {
            this.postExport('Pdf', { OpenAfterExport: true });
            return;
        }

        switch (printAction) {
            case 'PrintPdf': {
                // PDF print: get blob → load in iframe → trigger browser print dialog
                await this.printAsPdf();
                break;
            }
            default: {
                // PrintWithPreview / PrintWithoutPreview: send to server, get HTML back
                // Don't use postViewerEvent — it would download the HTML response as a file.
                // Instead, call httpClient.post directly and route the HTML to printService.
                try {
                    this.model.showProgress = true;
                    this.triggerUpdate();

                    const resp = await this.httpClient.post('ViewerEvent', {
                        action: 'PrintReport',
                        printAction,
                        bookmarksPrint: this.model.options?.appearance?.bookmarksPrint,
                    });

                    // Server returns HTML as text (may come as JSON with {action, subAction, html}
                    // or as raw HTML blob depending on content-type)
                    if (resp?.action === 'PrintReport' && resp?.html) {
                        this.printService.handlePrintResult(resp.subAction ?? printAction, resp.html);
                    } else if (resp?.isBinary && resp.blob) {
                        // HTML came back as blob — read it as text
                        const html = await resp.blob.text();
                        this.printService.handlePrintResult(printAction, html);
                    }
                } catch (e) {
                    console.error('[Controller] postPrint error:', e);
                } finally {
                    this.model.showProgress = false;
                    this.triggerUpdate();
                }
                break;
            }
        }
    }

    /**
     * PrintPdf: запрашиваем PDF blob с сервера, грузим в скрытый iframe → window.print()
     * Аналог Angular printAsPdf + printAsPdfPopup
     */
    private async printAsPdf() {
        try {
            this.model.showProgress = true;
            this.triggerUpdate();

            // Send PrintReport request via existing httpClient.post
            // action → stiweb_action, printAction → inside stiweb_parameters
            const resp = await this.httpClient.post('ViewerEvent', {
                action: 'PrintReport',
                printAction: 'PrintPdf',
                bookmarksPrint: this.model.options?.appearance?.bookmarksPrint,
                responseType: 'blob'
            });

            if (!resp?.isBinary || !resp.blob) {
                console.warn('[Controller] printAsPdf: expected blob response, got:', resp);
                return;
            }

            const pdfBlob = resp.blob;
            const printToPdfMode = this.model.options?.appearance?.printToPdfMode;
            const navigatorName = this.helperService.getNavigatorName();

            if (printToPdfMode === 'Popup' || navigatorName === 'Safari' || navigatorName === 'iPad') {
                // Popup mode: open in new window
                const blobUrl = URL.createObjectURL(pdfBlob);
                const win = window.open(blobUrl, '_blank');
                if (win) {
                    win.onload = () => { win.focus(); win.print(); };
                }
            } else {
                // Iframe mode: load in hidden iframe → trigger print
                this.printService.printAsPdf(pdfBlob);
            }
        } catch (e) {
            console.error('[Controller] printAsPdf error:', e);
        } finally {
            this.model.showProgress = false;
            this.triggerUpdate();
        }
    }

    /**
     * Аналог Angular controller.postExport():
     * Шаг 1: запрос с onlyFileName=true → получаем имя файла
     * Шаг 2: запрос без onlyFileName → получаем blob → скачиваем
     */
    public async postExport(format: string, settings?: any, isDashboardExport = false) {
        // Нормализация ExcelType (Angular: Excel → Excel2007, ExcelBiff → ExcelBinary)
        if (settings?.ExcelType) {
            settings.ExcelType = settings.ExcelType === 'Excel' ? 'Excel2007'
                : (settings.ExcelType === 'ExcelBiff' ? 'ExcelBinary' : settings.ExcelType);
        }

        // exportFormat передаём как есть — сервер ожидает конкретные значения enum StiExportFormat:
        // ImageJpeg, ImagePng, ImageBmp, Csv, Xml, Json, ExcelBiff, Html5 и т.д.
        // Обобщённые 'Image', 'Data' — только для Dashboard-экспорта.
        // Для дашбордов нормализуем: ImageXxx → Image, Csv/Dbf/... → Data и т.д.
        let exportFormat = format;
        if (isDashboardExport) {
            if (/^Image/.test(format)) exportFormat = 'Image';
            else if (format === 'Html5' || format === 'Mht') exportFormat = 'Html';
            else if (['ExcelBiff', 'Excel', 'ExcelXml', 'ExcelBinary'].includes(format)) exportFormat = 'Excel';
            else if (['Csv', 'Dbf', 'Xml', 'Dif', 'Sylk', 'Json'].includes(format)) exportFormat = 'Data';
        }

        const actionName = isDashboardExport ? 'ExportDashboard' : 'ExportReport';
        const exportData: Record<string, any> = {
            exportFormat,
            exportSettings: settings ?? {},
        };

        try {
            this.model.showProgress = true;
            this.triggerUpdate();

            console.log('[Controller] postExport:', { format, exportFormat, actionName, settings });

            // Шаг 1: получаем имя файла
            const fnResp = await this.httpClient.post('ViewerEvent', {
                action: actionName,
                ...exportData,
                onlyFileName: true,
            });
            console.log('[Controller] Step 1 (fileName) response:', fnResp);
            const fileName = fnResp?.fileName ?? `report.${format.toLowerCase()}`;

            // Шаг 2: получаем blob файла
            console.log('[Controller] Step 2 sending:', { action: actionName, ...exportData });
            const resp = await this.httpClient.post('ViewerEvent', {
                action: actionName,
                ...exportData,
            });
            console.log('[Controller] Step 2 response:', resp, resp?.blob?.size, resp?.blob?.type);

            // Если вернулся blob — всегда скачиваем файл
            if (resp?.isBinary && resp.blob) {
                const url = URL.createObjectURL(resp.blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = fileName;
                document.body.appendChild(a);
                a.click();
                document.body.removeChild(a);
                URL.revokeObjectURL(url);
            }

            this.emitAction({ action: 'ExportReport', data: { format, fileName } });
        } catch (err) {
            console.error('[Controller] postExport error:', err);
            this.showError('Export failed');
        } finally {
            this.model.showProgress = false;
            this.triggerUpdate();
        }
    }

    /** Open export form (analogue of Angular toolbar save/email menu) */
    public openExportForm(format: string, sendMail = false) {
        this.model.exportFormat = format;
        this.showForm(sendMail ? 'sendEmailForm' : 'exportForm', { format, sendMail });
    }

    private downloadFile(blob: Blob, contentType: string) {
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = this.getFilenameFromContentType(contentType);
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
        this.emitAction({ action: 'ExportReport', data: { contentType } });
    }

    private getFilenameFromContentType(contentType: string): string {
        const map: Record<string, string> = {
            'application/pdf': 'report.pdf',
            'application/vnd.ms-excel': 'report.xls',
            'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet': 'report.xlsx',
            'application/msword': 'report.doc',
            'application/vnd.openxmlformats-officedocument.wordprocessingml.document': 'report.docx',
        };
        return map[contentType] || 'report';
    }
}
