// Аналог Angular FindService
// Поиск текста по страницам отчёта, подсветка совпадений, навигация

import { StiReactModelService } from './model.service';
import { StiReactHelperService } from './helper.service';
import { StiReactAnimationService } from './animation.service';

export class StiReactFindService {

    private readonly SYMBOLS = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz1234567890';
    private findLabels: any[] = [];

    public text = '';
    public lastFindText = '';
    public matchCase = false;
    public matchWholeWord = false;
    public findMode = false;

    constructor(
        private model: StiReactModelService,
        private helper: StiReactHelperService,
        private animationService: StiReactAnimationService
    ) { }

    /** Скрыть все метки поиска */
    public hideFindLabels() {
        this.findLabels.forEach((label) => {
            const parent = label.parentElement;
            if (parent) {
                parent.removeChild(label);
                if (label.ownerElement?.oldPositionStyle != null) {
                    label.ownerElement.style.position = label.ownerElement.oldPositionStyle;
                }
            }
        });
        this.findLabels = [];
        this.findMode = false;
        this.lastFindText = '';
    }

    /** Выбрать следующую/предыдущую метку */
    public selectFindLabel(direction: string) {
        if (this.findLabels.length === 0) { return; }

        let selectedIndex = 0;
        for (let i = 0; i < this.findLabels.length; i++) {
            if (this.findLabels[i].isSelected) {
                this.findLabels[i].setSelected(false);
                selectedIndex = i;
                break;
            }
        }

        if (direction === 'Next') {
            selectedIndex = (selectedIndex + 1) % this.findLabels.length;
        } else {
            selectedIndex = (selectedIndex - 1 + this.findLabels.length) % this.findLabels.length;
        }

        this.findLabels[selectedIndex].setSelected(true);
        this.goToFindedElement(this.findLabels[selectedIndex]);
    }

    /** Показать метки для всех совпадений */
    public showFindLabels() {
        this.hideFindLabels();
        if (!this.text) { return; }

        this.findMode = true;
        this.lastFindText = this.text;
        const searchText = this.matchCase ? this.text : this.text.toLowerCase();

        // В React model.pages — массив объектов {content, sizes, ...}, без DOM-ссылок.
        // Фактические DOM-элементы страниц — <div data-pageindex="N"> внутри reportPanelElement.
        const reportPanel = this.model.controls.reportPanelElement as HTMLElement;
        if (!reportPanel) { return; }

        const pageElements = reportPanel.querySelectorAll<HTMLElement>('[data-pageindex]');
        pageElements.forEach((pageEl) => {
            const allElements = pageEl.getElementsByTagName('*');
            for (let i = 0; i < allElements.length; i++) {
                const el = allElements[i] as HTMLElement;
                let innerText = el.innerHTML;

                if (innerText && el.childNodes.length === 1 && el.childNodes[0].nodeName === '#text') {
                    if (!this.matchCase) { innerText = innerText.toLowerCase(); }

                    if (innerText.indexOf(searchText) >= 0) {
                        if (this.matchWholeWord && !this.isWholeWord(innerText, searchText)) { continue; }

                        const label: any = document.createElement('div');
                        label.ownerElement = el;
                        label.className = 'stiJsViewerFindLabel';
                        label.style.width = (el.offsetWidth - 4) + 'px';
                        label.style.height = (el.offsetHeight - 4) + 'px';
                        label.style.top = '0px';
                        label.style.left = '0px';

                        label.ownerElement.oldPositionStyle = el.style.position;
                        if (el.style.position !== 'absolute' && el.style.position !== 'fixed') {
                            el.style.position = 'relative';
                        }
                        el.insertBefore(label, el.childNodes[0]);

                        label.setSelected = function (state: boolean) {
                            this.isSelected = state;
                            this.style.border = '2px solid ' + (state ? 'red' : '#8a8a8a');
                        };

                        if (this.findLabels.length === 0) {
                            label.setSelected(true);
                        }
                        this.findLabels.push(label);
                    }
                }
            }
        });

        if (this.findLabels.length > 0) {
            this.goToFindedElement(this.findLabels[0]);
        }
    }

    private goToFindedElement(findLabel: any) {
        const ownerEl: HTMLElement = findLabel?.ownerElement;
        const reportPanelEl = this.model.controls.reportPanelElement;
        if (!ownerEl || !reportPanelEl) { return; }

        const scrollbarsMode = this.model.options?.appearance?.scrollbarsMode;
        const targetTop = this.helper.findPosY(
            ownerEl,
            scrollbarsMode ? 'stiJsViewerReportPanel' : undefined,
            true
        ) - ownerEl.offsetHeight - 50;

        const endTime = new Date().getTime() + (this.model.options?.scrollDuration ?? 300);
        this.animationService.showAnimationForScroll(reportPanelEl, targetTop, endTime, () => { });
    }

    private isWholeWord(str: string, word: string): boolean {
        const index = str.indexOf(word);
        const pre  = str.substring(index - 1, index);
        const next = str.substring(index + word.length, index + word.length + 1);
        return (
            (pre  === '' || this.SYMBOLS.indexOf(pre)  === -1) &&
            (next === '' || this.SYMBOLS.indexOf(next) === -1)
        );
    }
}
