// Аналог Angular FullScreenService
// Управляет переходом вьювера в полноэкранный режим и обратно

import { StiReactModelService } from './model.service';
import { StiReactPageService } from './page.service';

export class StiReactFullScreenService {

    constructor(
        private model: StiReactModelService,
        private pageService: StiReactPageService
    ) { }

    /**
     * Переключить полноэкранный режим
     * @param viewerEl DOM-элемент вьювера (корневой div)
     */
    public changeFullScreenMode(fullScreenMode: boolean, viewerEl: HTMLElement) {
        this.model.options.appearance.fullScreenMode = fullScreenMode;

        if (fullScreenMode) {
            // Сохраняем текущие стили
            this.model.fullScreenOptions = {
                scrollbarsMode: this.model.options.appearance.scrollbarsMode,
                zIndex:         viewerEl.style.zIndex,
                position:       viewerEl.style.position,
                width:          viewerEl.style.width,
                height:         viewerEl.style.height,
                overflow:       document.body.style.overflow
            };

            this.model.options.appearance.scrollbarsMode = true;
            viewerEl.style.zIndex    = '1000000';
            viewerEl.style.position  = this.model.options.reportDesignerMode ? 'absolute' : 'fixed';
            viewerEl.style.width     = '100%';
            viewerEl.style.height    = '100%';
            viewerEl.style.top       = '0';
            viewerEl.style.left      = '0';
            document.body.style.overflow = 'hidden';
        } else if (this.model.fullScreenOptions) {
            this.model.options.appearance.scrollbarsMode = this.model.fullScreenOptions.scrollbarsMode;
            viewerEl.style.zIndex    = this.model.fullScreenOptions.zIndex   || '';
            viewerEl.style.position  = this.model.fullScreenOptions.position || '';
            viewerEl.style.width     = this.model.fullScreenOptions.width    || '';
            viewerEl.style.height    = this.model.fullScreenOptions.height   || '';
            viewerEl.style.top       = '';
            viewerEl.style.left      = '';
            document.body.style.overflow = this.model.fullScreenOptions.overflow || '';
            this.model.fullScreenOptions = null;
        }

        this.pageService.calculateLayout();
    }
}
