// Analogue of Angular StylesService
// Injects <style> and <script> tags into the document head for viewer CSS and chart scripts

import { StiReactModelService } from './model.service';

export class StiReactStylesService {

    private pagesCss: Record<string, HTMLStyleElement> = {};

    constructor(private model: StiReactModelService) { }

    /**
     * Create or update a named <style> tag in the document head.
     * Used to inject server-generated CSS (page styles, themes, etc.)
     */
    public setupStyle(style: string, id: string) {
        if (this.pagesCss[id] == null) {
            const el = document.createElement('style') as any;
            el.id = (this.model.options?.viewerId ?? '') + id + 'Styles';
            el.setAttribute('type', 'text/css');
            if (this.model.options?.cSPNonce) {
                el.setAttribute('nonce', this.model.options.cSPNonce);
            }
            const head = document.getElementsByTagName('head')[0];
            if (head) { head.appendChild(el); }
            this.pagesCss[id] = el;
        }

        const el = this.pagesCss[id] as any;
        if (el.styleSheet) {
            el.styleSheet.cssText = style;
        } else {
            el.innerHTML = style;
        }
    }

    /**
     * Add @font-face declarations for custom fonts supplied by the server.
     * Skips fonts that are already declared to avoid duplicates.
     */
    public addCustomFontStyles(customFonts: any[]) {
        if (!customFonts) { return; }

        let existsStyles: HTMLCollectionOf<HTMLStyleElement>;
        try {
            existsStyles = document.getElementsByTagName('head')[0].getElementsByTagName('style');
        } catch (e) { return; }

        customFonts.forEach((customFont: any) => {
            if (customFont.contentForCss && customFont.originalFontFamily) {
                let exists = false;
                for (let i = 0; i < existsStyles.length; i++) {
                    if (existsStyles[i].innerHTML.indexOf(`font-family: '${customFont.originalFontFamily}'`) >= 0) {
                        exists = true;
                        break;
                    }
                }
                if (!exists) {
                    const style = document.createElement('style');
                    style.innerHTML = `@font-face {\r\nfont-family: '${customFont.originalFontFamily}';\r\n src: url(${customFont.contentForCss});\r\n }`;
                    document.getElementsByTagName('head')[0].appendChild(style);
                }
            }
        });
    }

    /**
     * Inject the chart animation script supplied by the server.
     * Removes the old script tag first to avoid stale scripts accumulating.
     */
    public addChartScript(script: string) {
        const viewerId = this.model.options?.viewerId ?? '';
        const scriptId = viewerId + 'chartScriptJsViewer';

        const existing = document.getElementById(scriptId);
        if (existing) {
            existing.parentElement?.removeChild(existing);
        }

        if (script) {
            const head = document.getElementsByTagName('head')[0];
            if (!head) { return; }

            const el = document.createElement('script');
            el.setAttribute('type', 'text/javascript');
            el.setAttribute('nonce', 'stichartanimation'); // for Content-Security-Policy
            el.id = scriptId;
            el.textContent = script;
            head.appendChild(el);
        }
    }
}
