// Аналог Angular DashboardsPanelComponent
// Панель с вкладками для переключения между дашбордами/отчётами + кнопки действий

import React, { useState } from 'react';
import { useViewer } from '../hooks/useViewer';
import { StiReactControllerService } from '../services/controller.service';

// ─── Кнопка дашборда (вкладка) ────────────────────────────────────────────────

interface DashboardTabProps {
    info: any;
    dbsMode: boolean;
    hidden?: boolean;
    onClick: () => void;
}

const DashboardTab: React.FC<DashboardTabProps> = ({ info, dbsMode, hidden, onClick }) => {
    const { model } = useViewer();
    const [over, setOver] = useState(false);
    const isSelected = info.isSelected;

    if (hidden) { return null; }

    const height = model.options?.toolbar?.displayMode === 'Separated'
        ? (dbsMode ? (model.options?.isTouchDevice ? '28px' : '23px') : '28px')
        : undefined;

    const bgColor = isSelected
        ? (model.options?.toolbar?.backgroundColor || '#d0d0d0')
        : (over ? '#e8e8e8' : 'transparent');

    return (
        <div
            style={{
                display: 'inline-flex', alignItems: 'center',
                height, padding: '0 10px', margin: '2px 1px 2px 2px',
                cursor: 'pointer', borderRadius: 2,
                border: dbsMode ? '1px solid #ccc' : 'none',
                borderColor: isSelected ? '#bbb' : (over ? '#bbb' : (dbsMode ? '#ccc' : 'transparent')),
                background: bgColor,
                fontSize: 12, whiteSpace: 'nowrap',
                fontFamily: model.options?.toolbar?.fontFamily,
                color: model.options?.toolbar?.fontColor
            }}
            onMouseOver={() => setOver(true)}
            onMouseOut={() => setOver(false)}
            onClick={onClick}
        >
            {info.caption ?? info.name ?? ''}
        </div>
    );
};

// ─── Иконка-кнопка действия ───────────────────────────────────────────────────

interface ActionIconProps {
    imageName: string;
    tooltip?: string;
    onClick: () => void;
    visible?: boolean;
}

const ActionIcon: React.FC<ActionIconProps> = ({ imageName, tooltip, onClick, visible = true }) => {
    const { model } = useViewer();
    const [over, setOver] = useState(false);

    if (!visible) { return null; }

    const dbsMode = true;
    const isTouchDevice = model.options?.isTouchDevice ?? false;
    const size = model.options?.toolbar?.displayMode === 'Separated'
        ? (dbsMode ? (isTouchDevice ? 28 : 23) : 28)
        : 23;

    return (
        <div
            title={tooltip}
            style={{
                display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
                width: size, height: size, margin: '2px 0 2px 2px',
                cursor: 'pointer', borderRadius: 2,
                background: over ? '#e0e0e0' : 'transparent',
                border: over ? '1px solid #bbb' : '1px solid transparent'
            }}
            onMouseOver={() => setOver(true)}
            onMouseOut={() => setOver(false)}
            onClick={onClick}
        >
            <img
                src={model.img?.(imageName) ?? ''}
                alt={tooltip ?? ''}
                style={{ width: 16, height: 16 }}
            />
        </div>
    );
};

// ─── Главный компонент ────────────────────────────────────────────────────────

export const DashboardsPanel: React.FC = () => {
    const { model, controller } = useViewer();

    const visible = model.controls.dashboardsPanel.visible;
    const dashboards: any[] = model.reportParams?.dashboards ?? [];
    const previewSettings = model.reportParams?.previewSettings ?? {};

    if (!visible || dashboards.length === 0) { return null; }

    const ctrl = controller as StiReactControllerService;
    const displayMode = model.options?.toolbar?.displayMode ?? 'Simple';
    const loc = (k: string) => model.loc?.(k) ?? k;
    const toolbarVisible = model.options?.toolbar?.visible ?? true;
    const imagesPath = 'Dashboards.Actions.Light.';

    const dashboardsCount = dashboards.filter((d: any) => d.type === 'Dashboard').length;
    const reportsCount    = dashboards.length - dashboardsCount;
    const dbsMode = dashboardsCount > 0 && reportsCount === 0;

    // Переключение активного дашборда
    const handleTabClick = (info: any) => {
        ctrl.postViewerEvent('SelectDashboard', {
            stiweb_dashboardName: info.name
        });
    };

    return (
        <div
            className={`stiJsViewerToolBar${displayMode === 'Separated' ? ' stiJsViewerToolBarSeparated' : ''}`}
            style={{
                fontFamily: model.options?.toolbar?.fontFamily,
                color: model.options?.toolbar?.fontColor,
                background: dbsMode ? 'transparent' : undefined,
                borderColor: dbsMode ? 'transparent' : undefined
            }}
        >
            <div style={{ paddingTop: displayMode === 'Simple' ? 2 : 0 }}>
                <table
                    className="stiJsViewerToolBarTable"
                    cellPadding={0} cellSpacing={0}
                    style={{
                        margin: 0, boxSizing: 'border-box',
                        border: displayMode === 'Separated' ? '0' : undefined,
                        background: dbsMode ? 'transparent' : undefined,
                        borderColor: dbsMode ? 'transparent' : undefined,
                        width: '100%'
                    }}
                >
                    <tbody>
                        <tr>
                            {/* Вкладки дашбордов/отчётов */}
                            <td style={{ width: '100%' }}>
                                <table
                                    className="stiJsViewerToolBarTable"
                                    cellPadding={0} cellSpacing={0}
                                    style={{
                                        textAlign: model.options?.appearance?.rightToLeft
                                            ? 'right'
                                            : (model.options?.toolbar?.alignment === 'default' ? 'left' : (model.options?.toolbar?.alignment ?? 'left'))
                                    }}
                                >
                                    <tbody>
                                        <tr>
                                            {dashboards.map((info: any, i: number) => (
                                                <td key={i}>
                                                    <DashboardTab
                                                        info={info}
                                                        dbsMode={dbsMode}
                                                        hidden={dashboardsCount === 1 && reportsCount === 0}
                                                        onClick={() => handleTabClick(info)}
                                                    />
                                                </td>
                                            ))}
                                        </tr>
                                    </tbody>
                                </table>
                            </td>

                            {/* Кнопки действий справа */}
                            <td>
                                <table className="stiJsViewerToolBarTable" cellPadding={0} cellSpacing={0}
                                    style={{ marginRight: 2 }}>
                                    <tbody>
                                        <tr>
                                            {model.options?.toolbar?.showRefreshButton && toolbarVisible && previewSettings.dashboardToolBar && previewSettings.dashboardRefreshButton && (
                                                <td>
                                                    <ActionIcon
                                                        imageName={imagesPath + 'Refresh.png'}
                                                        tooltip={loc('Refresh')}
                                                        onClick={() => ctrl.postViewerEvent('GetPages')}
                                                    />
                                                </td>
                                            )}

                                            {model.options?.toolbar?.showParametersButton && toolbarVisible && (
                                                <td>
                                                    <ActionIcon
                                                        imageName={imagesPath + 'Parameters.png'}
                                                        tooltip={loc('Parameters')}
                                                        onClick={() => {
                                                            if (model.controls.parametersPanel) {
                                                                model.controls.parametersPanel.visible = !model.controls.parametersPanel.visible;
                                                            }
                                                        }}
                                                    />
                                                </td>
                                            )}

                                            {model.options?.toolbar?.showOpenButton && toolbarVisible && previewSettings.dashboardToolBar && previewSettings.dashboardOpenButton && (
                                                <td>
                                                    <ActionIcon
                                                        imageName={imagesPath + 'Open.png'}
                                                        tooltip={loc('Open')}
                                                        onClick={() => {
                                                            model.openDialogFileMask = null;
                                                            setTimeout(() => { model.openDialogFileMask = '.mdc,.mdz,.mdx,.mrt,.mrz,.mrx'; });
                                                        }}
                                                    />
                                                </td>
                                            )}

                                            {model.options?.toolbar?.showDesignButton && toolbarVisible && previewSettings.dashboardToolBar && previewSettings.dashboardEditButton && (
                                                <td>
                                                    <ActionIcon
                                                        imageName={imagesPath + 'Edit.png'}
                                                        tooltip={loc('Edit')}
                                                        onClick={() => ctrl.postViewerEvent('DesignReport')}
                                                    />
                                                </td>
                                            )}

                                            {model.options?.toolbar?.showFullScreenButton && toolbarVisible && previewSettings.dashboardToolBar && previewSettings.dashboardFullScreenButton && (
                                                <td>
                                                    <ActionIcon
                                                        imageName={imagesPath + 'CloseFullScreen.png'}
                                                        tooltip={loc('FullScreen')}
                                                        onClick={() => ctrl.emitActionPublic('FullScreen', null)}
                                                    />
                                                </td>
                                            )}
                                        </tr>
                                    </tbody>
                                </table>
                            </td>
                        </tr>
                    </tbody>
                </table>
            </div>
        </div>
    );
};
