// Аналог Angular ReportPanelComponent
// Рендерит HTML-страницы отчёта (dangerouslySetInnerHTML — так же, как Angular [innerHTML])
// Обрабатывает клики по гиперссылкам (drill-down, bookmarks, interactions)
// После рендеринга страниц инициализирует интерактивные элементы (сортировка, drill-down, collapsing)

import React, { useRef, useCallback, useEffect } from 'react';
import { useViewer } from '../hooks/useViewer';
import { StiReactInteractionsService } from '../services/interactions.service';
import { StiReactHelperService } from '../services/helper.service';
import { StiReactAnimationService } from '../services/animation.service';
import { StiReactDrillDownService } from '../services/drill-down.service';
import { StiReactControllerService } from '../services/controller.service';
import { StiReactFindService } from '../services/find.service';

export const ReportPanel: React.FC = () => {
    const { model, controller } = useViewer();
    const panelRef = useRef<HTMLDivElement>(null);

    // Создаём InteractionsService — один раз на жизнь компонента
    const interactionSvcRef = useRef<StiReactInteractionsService | null>(null);
    if (!interactionSvcRef.current) {
        const animSvc = new StiReactAnimationService(model);
        const helperSvc = new StiReactHelperService(model, animSvc);
        const ddSvc = new StiReactDrillDownService(model);
        // Подписка DrillDownService на сообщения контроллера (аналог Angular constructor subscribe)
        ddSvc.subscribeToController(controller as StiReactControllerService);
        // Сохраняем ссылку для компонента DrillDownPanel
        model.drillDownService = ddSvc;
        // Создаём FindService и сохраняем на model для FindPanel
        if (!model.findService) {
            model.findService = new StiReactFindService(model, helperSvc, animSvc);
        }
        interactionSvcRef.current = new StiReactInteractionsService(
            model,
            controller as StiReactControllerService,
            helperSvc,
            ddSvc
        );
    }

    // Сохраняем ссылку на DOM-элемент в model.controls для других сервисов
    useEffect(() => {
        if (panelRef.current) {
            model.controls.reportPanelElement = panelRef.current;
        }
        return () => {
            model.controls.reportPanelElement = null;
        };
    }, [model]);

    // ═══════════════════════════════════════════════════════════════
    // Инициализация интерактивных элементов ПОСЛЕ рендеринга страниц
    // Аналог Angular: setTimeout(() => {
    //   pages.forEach(p => initializeInteractions(p.page));
    //   updateAllHyperLinks();
    //   addChartScript(chartScript);
    // })
    //
    // ВАЖНО: chartScript нужно выполнять ПОСЛЕ того как React отрендерил
    // HTML страниц в DOM, потому что скрипт ищет элементы по ID.
    // После выполнения chartScript — повторно initializeInteractions,
    // так как скрипт создаёт SVG-элементы с interaction-атрибутами.
    // ═══════════════════════════════════════════════════════════════
    useEffect(() => {
        const panel = panelRef.current;
        const svc = interactionSvcRef.current;
        const ctrl = controller as StiReactControllerService;
        if (!panel || !svc) return;

        // setTimeout(0) — ждём пока DOM отрендерится (как Angular)
        const timer = setTimeout(() => {
            // 1) Инициализируем интерактивные элементы на статическом HTML
            const initPages = () => {
                const pageElements = panel.querySelectorAll('[data-pageindex]');
                pageElements.forEach((pageEl) => {
                    svc.initializeInteractions(pageEl as HTMLElement);
                });
            };

            initPages();
            svc.updateAllHyperLinks();

            // 2) Выполняем отложенный chartScript (рисует SVG чарты)
            const pendingScript = model.pendingChartScript;
            console.log('[ReportPanel] pendingChartScript:', pendingScript ? `${pendingScript.length} chars` : 'null');
            if (pendingScript) {
                // Ищем ключевые слова в chartScript
                const keywords = ['click', 'interaction', 'drill', 'jsObject', 'postAction', 'postInteraction', 'onclick', 'mousedown', 'elementindex', 'pageguid'];
                keywords.forEach(kw => {
                    const idx = pendingScript.toLowerCase().indexOf(kw.toLowerCase());
                    if (idx >= 0) {
                        console.log(`[ReportPanel] chartScript contains "${kw}" at pos ${idx}:`, pendingScript.substring(Math.max(0, idx - 50), idx + 200));
                    }
                });
            }
            if (pendingScript && ctrl.stylesService) {
                model.pendingChartScript = null;
                console.log('[ReportPanel] executing chartScript...');
                ctrl.stylesService.addChartScript(pendingScript);

                // 3) После выполнения chartScript SVG-элементы появились в DOM —
                //    повторно инициализируем interactions на них
                //    (небольшой setTimeout чтобы скрипт успел отработать)
                setTimeout(() => {
                    console.log('[ReportPanel] re-running initPages after chartScript');
                    initPages();
                }, 50);
            }
        }, 0);

        return () => clearTimeout(timer);
    // Перезапускаем при изменении страниц
    }, [model.pages, model.pages.length]);

    // Обработчик кликов внутри страниц отчёта
    const handlePanelClick = useCallback((e: React.MouseEvent<HTMLDivElement>) => {
        let target = e.target as HTMLElement;

        // Поднимаемся по DOM-дереву в поиске кликабельного элемента
        while (target && target !== e.currentTarget) {
            // Drill-down ссылки (атрибут stiweb_* или href с javascript:)
            if (target.tagName === 'A') {
                const href = target.getAttribute('href');
                const componentIndex = target.getAttribute('componentindex');
                const action = target.getAttribute('action');

                if (componentIndex != null || action) {
                    e.preventDefault();
                    e.stopPropagation();
                    controller.postViewerEvent('InteractionClick', {
                        stiweb_componentIndex: componentIndex,
                        stiweb_action: action ?? 'DrillDown',
                        stiweb_pageIndex: target.closest('[data-pageindex]')?.getAttribute('data-pageindex') ?? 0
                    });
                    return;
                }

                // Якорная ссылка (bookmark) — теперь обрабатывается через updateAllHyperLinks
                if (href && href.startsWith('#')) {
                    // Если onclick уже установлен через updateAllHyperLinks, он сам обработает
                    // Иначе — fallback
                    if (!(target as any).onclick) {
                        e.preventDefault();
                        const anchorName = href.substring(1);
                        model.navigateNode = { title: anchorName, url: anchorName };
                    }
                    return;
                }
                break;
            }
            target = target.parentElement as HTMLElement;
        }
    }, [model, controller]);

    // Аналог Angular scroll() в ReportPanelComponent:
    // В Continuous mode отслеживаем какая страница видна и обновляем pageNumber
    const scrollTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    const handleScroll = useCallback(() => {
        const isContinuous = model.reportParams?.viewMode === 'Continuous';
        const scrollbars = model.options?.appearance?.scrollbarsMode;
        const fullScreen = model.options?.appearance?.fullScreenMode;
        if (!isContinuous || !(scrollbars || fullScreen)) return;

        if (scrollTimeoutRef.current) clearTimeout(scrollTimeoutRef.current);
        scrollTimeoutRef.current = setTimeout(() => {
            const panel = panelRef.current;
            if (!panel) return;
            const pages = panel.querySelectorAll('[data-pageindex]');
            let commonHeight = 0;
            let index = 0;
            for (index = 0; index < pages.length; index++) {
                commonHeight += (pages[index] as HTMLElement).offsetHeight + 10;
                if (commonHeight > panel.scrollTop) break;
            }
            const pagesCount = model.reportParams?.pagesCount ?? 1;
            if (index < pagesCount && index >= 0 && index !== model.reportParams?.pageNumber) {
                if (model.reportParams) {
                    model.reportParams.pageNumber = index;
                    controller.triggerUpdate();
                }
            }
        }, 300);
    }, [model, controller]);

    useEffect(() => {
        const panel = panelRef.current;
        if (!panel) return;
        panel.addEventListener('scroll', handleScroll);
        return () => panel.removeEventListener('scroll', handleScroll);
    }, [handleScroll]);

    const scrollbarsMode = model.options?.appearance?.scrollbarsMode ?? true;
    const bgColor = model.options?.appearance?.reportDisplayMode === 'FromReport'
        ? 'transparent'
        : (model.options?.appearance?.backgroundColor ?? '#c6c6c6');

    // Angular: pageAlignment → text-align на панели
    const pageAlignment = model.options?.appearance?.pageAlignment;
    const textAlign = (!pageAlignment || pageAlignment === 'default') ? 'center' : pageAlignment;

    return (
        <div
            ref={panelRef}
            className="stiJsViewerReportPanel"
            onClick={handlePanelClick}
            style={{
                overflow: scrollbarsMode ? 'auto' : 'hidden',
                flex: 1,
                background: bgColor,
                position: 'absolute',
                top: 0,
                bottom: 0,
                left: 0,
                right: 0,
                textAlign: textAlign,
            }}
        >
            {model.pages.map((page: any, idx: number) => {
                // Сервер возвращает объект {content, sizes, margins, brush}
                const isObj         = typeof page === 'object' && page !== null;
                const html: string  = isObj ? (page.content ?? page.html ?? '') : (page ?? '');
                const hasContent    = !!html;
                const sizes: string = isObj ? (page.sizes ?? '') : '';
                const margins       = isObj ? (page.margins ?? '') : '';
                const background    = isObj ? (page.background ?? page.brush ?? '') : '';
                const viewMode      = model.reportParams?.viewMode;

                // Парсим размеры: "827.0;1169.0" → {width, height}
                let pageWidth: number | undefined;
                let pageHeight: number | undefined;
                if (sizes) {
                    const parts = sizes.split(';');
                    if (parts.length >= 2) {
                        pageWidth  = parseFloat(parts[0]);
                        pageHeight = parseFloat(parts[1]);
                    }
                }

                const isContinuous = viewMode === 'Continuous';

                // Angular: background — если Transparent или rgba(255,255,255,0) → White
                let pageBg = background || 'White';
                if (pageBg === 'Transparent' || pageBg === 'rgba(255,255,255,0)') {
                    pageBg = 'White';
                }

                const showShadow = model.options?.appearance?.showPageShadow !== false;

                // Angular: один div — и тень, и контент (нет обёртки)
                // width/height ставится ТОЛЬКО когда НЕТ контента
                return (
                    <div
                        key={idx}
                        data-pageindex={idx}
                        className={showShadow ? 'stiJsViewerPageShadow' : 'stiJsViewerPage'}
                        style={{
                            display: isContinuous ? 'table' : 'inline-block',
                            margin: isContinuous ? '10px auto' : '10px',
                            overflow: 'hidden',
                            textAlign: 'left',
                            verticalAlign: 'top',
                            color: '#000000',
                            boxSizing: 'content-box',
                            border: `1px solid ${model.options?.appearance?.pageBorderColor ?? '#c6c6c6'}`,
                            background: pageBg,
                            padding: margins || undefined,
                            // Angular: width/height ТОЛЬКО когда нет content!
                            ...(!hasContent && pageWidth  ? { width:  pageWidth  + 'px' } : {}),
                            ...(!hasContent && pageHeight ? { height: pageHeight + 'px' } : {}),
                        }}
                        dangerouslySetInnerHTML={{ __html: html }}
                    />
                );
            })}
        </div>
    );
};
