// Main React Viewer Component
// Analogue of Angular StimulsoftViewerComponent
// Usage:
//   <StimulsoftViewer
//     requestUrl="http://localhost:5151/Viewer/{action}"
//     action="InitViewer"
//     height="100vh"
//     properties={{ reportName: 'MasterDetail.mrt' }}
//     onLoaded={() => console.log('loaded')}
//     onError={(err) => console.error(err)}
//     onExport={(data) => console.log('export', data)}
//   />

import React, {
    useEffect,
    useRef,
    useState,
    useCallback,
    forwardRef,
    useImperativeHandle
} from 'react';
import { ViewerContext } from './ViewerContext';
import { StiReactModelService } from './services/model.service';
import { StiReactHttpClientService } from './services/http-client.service';
import { StiReactControllerService } from './services/controller.service';
import { StiReactFullScreenService } from './services/full-screen.service';
import { StiReactPageService } from './services/page.service';
import { Toolbar } from './components/Toolbar';
import { ReportPanel } from './components/ReportPanel';
import { NavigatePanel } from './components/NavigatePanel';
import { FindPanel } from './components/FindPanel';
import { BookmarksPanel } from './components/BookmarksPanel';
import { DrillDownPanel } from './components/DrillDownPanel';
import { ParametersPanel } from './components/ParametersPanel';
import { ResourcesPanel } from './components/ResourcesPanel';
import { DashboardsPanel } from './components/DashboardsPanel';
import { AboutPanel } from './components/AboutPanel';
import { OpenDialog } from './components/OpenDialog';
import { Progress } from './components/Progress';
import { ExportForm } from './forms/ExportForm';
import { SendEmailForm } from './forms/SendEmailForm';
import { PasswordForm } from './forms/PasswordForm';
import { ErrorMessageForm } from './forms/ErrorMessageForm';
import { NotificationForm } from './forms/NotificationForm';
import { StiTooltip } from './components/Tooltip';

export interface StimulsoftViewerProps {
    /** Backend URL with {action} placeholder. E.g.: 'http://localhost:5151/Viewer/{action}' */
    requestUrl: string;
    /** First action to call. Default: 'InitViewer' */
    action?: string;
    /** Custom properties sent to backend (e.g. { reportName: 'report.mrt' }) */
    properties?: any;
    /** Viewer width. Default: '100%' */
    width?: string;
    /** Viewer height. Default: '650px' */
    height?: string;
    /** Background color. Default: 'White' */
    backgroundColor?: string;
    /** Function to add custom POST parameters */
    postParametersFunction?: (params: any) => any;

    // Events
    onLoaded?: () => void;
    onError?: (error: any) => void;
    onExport?: (data: any) => void;
    onEmail?: (data: any) => void;
    onPrint?: (data: any) => void;
    onDesign?: () => void;
}

export interface StimulsoftViewerHandle {
    export: (format: string) => void;
    print: () => void;
    search: (text: string, matchCase: boolean, wholeWord: boolean) => void;
    reload: () => void;
}

export const StimulsoftViewer = forwardRef<StimulsoftViewerHandle, StimulsoftViewerProps>(
    (props, ref) => {
        const {
            requestUrl,
            action = 'InitViewer',
            properties,
            width = '100%',
            height = '650px',
            backgroundColor = 'White',
            postParametersFunction,
            onLoaded, onError, onExport, onEmail, onPrint, onDesign
        } = props;

        // Create services once per component instance (replaces Angular DI providers:[])
        const modelRef = useRef<StiReactModelService>(new StiReactModelService());
        const httpRef  = useRef<StiReactHttpClientService>(
            new StiReactHttpClientService(modelRef.current)
        );
        const ctrlRef  = useRef<StiReactControllerService>(
            new StiReactControllerService(modelRef.current, httpRef.current)
        );
        const pageSvcRef = useRef<StiReactPageService>(
            new StiReactPageService(modelRef.current)
        );
        const fullScreenSvcRef = useRef<StiReactFullScreenService>(
            new StiReactFullScreenService(modelRef.current, pageSvcRef.current)
        );

        const [, forceUpdate] = useState(0);
        const [initialized, setInitialized] = useState(false);
        const [aboutVisible, setAboutVisible] = useState(false);
        const viewerRef = useRef<HTMLDivElement>(null);

        // Tell controller how to trigger React re-renders
        ctrlRef.current.setStateUpdateCallback(() => forceUpdate(n => n + 1));

        // Subscribe to events from controller (analogue of Angular @Output EventEmitters)
        useEffect(() => {
            const ctrl = ctrlRef.current;

            const unsubMessage = ctrl.onMessage((msg) => {
                if (msg.action === 'viewer_loaded') {
                    setInitialized(true);
                }
                if (msg.action === 'GetReport' || msg.action === 'OpenReport') {
                    onLoaded?.();
                    // Обновляем видимость ResourcesPanel
                    const model = modelRef.current;
                    model.controls.resourcesPanel.visible =
                        (model.reportParams?.resources?.length ?? 0) > 0;
                    // Обновляем видимость DashboardsPanel
                    model.controls.dashboardsPanel.visible =
                        (model.reportParams?.dashboards?.length ?? 0) > 0;
                }
            });

            const unsubAction = ctrl.onAction((msg) => {
                switch (msg.action) {
                    case 'Error':        onError?.(msg.data);          break;
                    // ExportReport = download completed (binary file downloaded)
                    case 'ExportReport': onExport?.(msg.data);         break;
                    // Export = user clicked save menu item → show settings dialog or export directly
                    case 'Export': {
                        const showDialog = model.options?.exports?.showExportDialog !== false;
                        if (showDialog) {
                            ctrl.openExportForm(msg.data?.format, false);
                        } else {
                            // Без диалога — экспорт с настройками по умолчанию
                            ctrl.postExport(msg.data?.format);
                        }
                        break;
                    }
                    // SendEmail = user clicked email menu item → show email form
                    case 'SendEmail':
                        ctrl.openExportForm(msg.data?.format, true);
                        break;
                    // Email = email send completed
                    case 'Email':        onEmail?.(msg.data);          break;
                    // Print = user clicked print menu item → route to proper handler
                    case 'Print': {
                        const printAction = msg.data?.format ?? 'PrintPdf';
                        ctrl.postPrint(printAction);
                        onPrint?.(msg.data);
                        break;
                    }
                    case 'Design':       onDesign?.();                 break;
                    case 'About':        setAboutVisible(true);        break;
                    case 'FullScreen':
                        if (viewerRef.current) {
                            const model = modelRef.current;
                            fullScreenSvcRef.current.changeFullScreenMode(
                                !model.options?.appearance?.fullScreenMode,
                                viewerRef.current
                            );
                        }
                        break;
                }
            });

            return () => { unsubMessage(); unsubAction(); };
        }, [onLoaded, onError, onExport, onEmail, onPrint, onDesign]);

        // Load viewer when props change (analogue of Angular ngOnChanges)
        useEffect(() => {
            const model = modelRef.current;
            model.requestUrl = requestUrl;
            model.action = action;
            model.properties = properties ?? null;
            model.postParametersFunction = postParametersFunction ?? null;
            ctrlRef.current.loadViewer();
        }, [requestUrl, action, properties, postParametersFunction]);

        // Handle resize (analogue of Angular window.onresize)
        useEffect(() => {
            const handleResize = () => {
                if (viewerRef.current) {
                    modelRef.current.viewerSize = {
                        width: viewerRef.current.offsetWidth,
                        height: viewerRef.current.offsetHeight
                    };
                    ctrlRef.current.viewerResized();
                }
            };
            window.addEventListener('resize', handleResize);
            // Initial size
            handleResize();
            // Set viewer element reference for print service (analogue of Angular: model.controls.viewer.el = viewerElement)
            if (viewerRef.current) {
                modelRef.current.controls.viewer.el = viewerRef.current;
            }
            return () => window.removeEventListener('resize', handleResize);
        }, []);

        // Public API exposed via ref (analogue of Angular viewer.api.*)
        useImperativeHandle(ref, () => ({
            export: (format: string) => {
                ctrlRef.current.postExport(format);
            },
            print: () => {
                ctrlRef.current.postPrint('PrintPdf');
            },
            search: (text: string, matchCase: boolean, wholeWord: boolean) => {
                ctrlRef.current.postViewerEvent('FindText', {
                    stiweb_findText: text,
                    stiweb_matchCase: matchCase,
                    stiweb_wholeWord: wholeWord
                });
            },
            reload: () => {
                ctrlRef.current.loadViewer();
            }
        }));

        const model = modelRef.current;
        const ctrl  = ctrlRef.current;
        const contextValue = { model, controller: ctrl };

        // Form visibility helpers
        const currentForm = model.form?.name ?? null;
        const formData    = model.form?.formData ?? null;

        const closeCurrentForm = useCallback(() => ctrl.closeForm(), [ctrl]);

        // Determine export format for forms
        const exportFormat = formData?.format ?? model.exportFormat ?? '';
        const paramPosition = model.options?.appearance?.currentParametersPanelPosition ?? 'Top';

        return (
            <ViewerContext.Provider value={contextValue}>
                <div
                    ref={viewerRef}
                    className="stiJsViewerMainPanel"
                    style={{
                        display: 'flex',
                        flexDirection: 'column',
                        width,
                        height,
                        backgroundColor,
                        position: 'relative',
                        boxSizing: 'border-box',
                        fontFamily: model.options?.toolbar?.fontFamily || 'Arial',
                        fontSize: '12px',
                    }}
                    id={model.options?.viewerId}
                >
                    {initialized && (
                        <>
                            {/* Tooltip (singleton — позиционируется абсолютно внутри MainPanel) */}
                            <StiTooltip />

                            {/* Тулбар */}
                            <Toolbar />

                            {/* Панели под тулбаром */}
                            <FindPanel />
                            <DrillDownPanel />
                            <ResourcesPanel />
                            <DashboardsPanel />

                            {/* Параметры — Top position */}
                            {paramPosition === 'Top' && <ParametersPanel />}

                            {/* Основная область — занимает оставшееся пространство */}
                            <div style={{
                                display: 'flex',
                                flex: 1,
                                overflow: 'hidden',
                                position: 'relative',
                                minHeight: 0
                            }}>
                                {/* Параметры — Left position */}
                                {paramPosition !== 'Top' && <ParametersPanel />}
                                <BookmarksPanel />
                                <ReportPanel />
                            </div>

                            <NavigatePanel />

                            {/* Скрытый диалог открытия файла */}
                            <OpenDialog />
                        </>
                    )}

                    <Progress />

                    {/* Панель About (оверлей) */}
                    <AboutPanel
                        visible={aboutVisible}
                        onClose={() => setAboutVisible(false)}
                    />

                    {/* ── Модальные формы ── */}
                    <ExportForm
                        visible={currentForm === 'exportForm'}
                        format={exportFormat}
                        sendMail={false}
                        onExport={(fmt, settings) => {
                            ctrl.postExport(fmt, settings);
                        }}
                        onClose={closeCurrentForm}
                    />

                    <SendEmailForm
                        visible={currentForm === 'sendEmailForm'}
                        format={exportFormat}
                        onSend={(fmt, settings) => {
                            ctrl.postViewerEvent('EmailReport', {
                                stiweb_exportFormat: fmt,
                                stiweb_email: settings.Email,
                                stiweb_subject: settings.Subject,
                                stiweb_message: settings.Message
                            });
                        }}
                        onClose={closeCurrentForm}
                    />

                    <PasswordForm
                        visible={currentForm === 'passwordForm'}
                        formData={formData}
                        onSubmit={(password, data) => {
                            ctrl.postViewerEvent('OpenReport', {
                                ...data,
                                stiweb_password: password
                            });
                        }}
                        onClose={closeCurrentForm}
                    />

                    <ErrorMessageForm
                        visible={currentForm === 'errorMessageForm'}
                        onClose={closeCurrentForm}
                    />

                    <NotificationForm
                        visible={currentForm === 'notificationForm'}
                        onClose={closeCurrentForm}
                    />
                </div>
            </ViewerContext.Provider>
        );
    }
);

StimulsoftViewer.displayName = 'StimulsoftViewer';
