// Analogue of Angular StiHttpClientService
// Handles all HTTP POST communication with ASP.NET Core backend

import { StiReactModelService } from './model.service';

export class StiReactHttpClientService {

    constructor(private model: StiReactModelService) {}

    // Build URL from requestUrl template: 'http://localhost:5151/Viewer/{action}'
    private buildUrl(action: string): string {
        return this.model.requestUrl.replace('{action}', action);
    }

    // Build FormData from params — same format as Angular createPostParameters
    // Ключевая логика (из Angular model.service.ts):
    //   1. stiweb_action, stiweb_component и т.д. — как отдельные FormData поля
    //   2. base64Data → stiweb_data (отдельное поле, НЕ в stiweb_parameters)
    //   3. properties → отдельное поле (читается из Request.Form["properties"])
    //   4. Всё остальное → JSON → base64 → stiweb_parameters
    private buildFormData(params: Record<string, any>): FormData {
        const formData = new FormData();

        // Поля, которые Angular выделяет отдельно (не внутрь stiweb_parameters)
        const topLevelKeys = new Set(['stiweb_component', 'stiweb_action', 'stiweb_viewerRequestUrl', 'stiweb_imagesScalingFactor', 'properties']);

        // stiweb_* поля и properties — на верхний уровень FormData
        for (const key of Object.keys(params)) {
            if (topLevelKeys.has(key)) {
                const value = params[key];
                if (value !== undefined && value !== null) {
                    formData.append(key, String(value));
                }
            }
        }

        // Angular: base64Data → stiweb_data (отдельное поле)
        if (params.base64Data) {
            formData.append('stiweb_data', params.base64Data);
        }

        // Angular: params.action → stiweb_action (top-level FormData field)
        if (params.action && !params.stiweb_action) {
            formData.append('stiweb_action', String(params.action));
        }

        // Собираем всё остальное в stiweb_parameters (как Angular createPostParameters)
        try {
            const paramsForEncoding: Record<string, any> = {};
            for (const key of Object.keys(params)) {
                // Исключаем: stiweb_* поля (уже на верхнем уровне), properties, base64Data, action (идёт в stiweb_action)
                if (!key.startsWith('stiweb_') && key !== 'properties' && key !== 'base64Data' && key !== 'action') {
                    paramsForEncoding[key] = params[key];
                }
            }
            const json = JSON.stringify(paramsForEncoding);
            const base64 = btoa(unescape(encodeURIComponent(json)));
            formData.append('stiweb_parameters', base64);
        } catch (e) {
            console.warn('[HttpClient] Failed to encode stiweb_parameters:', e);
        }

        return formData;
    }

    // Аналог Angular createPostParameters — стандартные параметры для каждого запроса
    private getStandardParams(): Record<string, any> {
        const opts = this.model.options;
        const rp   = this.model.reportParams;

        const std: Record<string, any> = {
            stiweb_component:        'Viewer',
            stiweb_viewerRequestUrl: this.model.requestUrl,
            // clientGuid генерируется один раз при создании модели, аналог Angular newToken()
            clientGuid:              this.model.clientGuid,
            // Дефолтные значения кэша (сервер требует эти поля)
            cacheMode:               'ObjectCache',
            cacheTimeout:            20,
            cacheItemPriority:       'Default',
        };

        if (opts) {
            if (opts.viewerId)                  std['viewerId']          = opts.viewerId;
            if (opts.server?.cacheMode)         std['cacheMode']         = opts.server.cacheMode;
            if (opts.server?.cacheTimeout)      std['cacheTimeout']      = opts.server.cacheTimeout;
            if (opts.server?.cacheItemPriority) std['cacheItemPriority'] = opts.server.cacheItemPriority;
        }

        // Текущее состояние просмотра
        if (rp) {
            if (rp.pageNumber  != null) std['pageNumber'] = rp.pageNumber;
            if (rp.zoom        != null) std['zoom']       = rp.zoom > 0 ? rp.zoom : 100;
            if (rp.viewMode)            std['viewMode']   = rp.viewMode;
            if (rp.drillDownParameters && rp.drillDownParameters.length > 0) std['drillDownParameters'] = rp.drillDownParameters;
            if (rp.drillDownGuid) std['drillDownGuid'] = rp.drillDownGuid;
        }

        // Параметры отображения — аналог Angular model.getParams(true)
        if (opts?.appearance) {
            std['chartRenderType']   = opts.appearance.chartRenderType ?? 'AnimatedVector';
            std['reportDisplayMode'] = opts.displayModeFromReport || opts.appearance.reportDisplayMode || 'Table';
            if (opts.appearance.imagesQuality)  std['imagesQuality'] = opts.appearance.imagesQuality;
        } else {
            // Fallback: без options всё равно отправляем AnimatedVector
            std['chartRenderType'] = 'AnimatedVector';
        }

        if (opts?.toolbar) {
            std['showBookmarks'] = opts.toolbar.showBookmarksButton ?? false;
        }

        // Editable parameters — изменённые пользователем значения полей отчёта
        if (rp?.editableParameters) {
            std['editableParameters'] = rp.editableParameters;
        }

        return std;
    }

    public async post(action: string, params: Record<string, any> = {}): Promise<any> {
        const url = this.buildUrl(action);

        // Объединяем стандартные параметры с переданными (переданные имеют приоритет)
        const mergedParams = { ...this.getStandardParams(), ...params };

        if (this.model.postParametersFunction) {
            const extra = this.model.postParametersFunction(mergedParams);
            if (extra) Object.assign(mergedParams, extra);
        }

        const formData = this.buildFormData(mergedParams);
        console.log('[HttpClient] POST', url, '| params:', JSON.stringify({ ...mergedParams, properties: mergedParams.properties ? '(base64)' : undefined }));

        try {
            const response = await fetch(url, {
                method: 'POST',
                body: formData
            });

            if (!response.ok) {
                // Читаем тело ответа для диагностики серверной ошибки
                let errorBody = '';
                try { errorBody = await response.text(); } catch {}
                console.error('[HttpClient] HTTP error body:', errorBody.substring(0, 500));
                throw new Error(`HTTP error: ${response.status} ${response.statusText}`);
            }

            const contentType = response.headers.get('content-type') || '';

            // JSON response — стандартные ответы сервера (fileName, параметры и т.д.)
            if (contentType.includes('application/json')) {
                return await response.json();
            }

            // Текстовая ошибка сервера (напр. "ServerError:The report is not specified.")
            // Но text/html может быть валидным экспортом (HTML export), поэтому проверяем только text/plain
            if (contentType.includes('text/plain')) {
                const text = await response.text();
                if (text.startsWith('ServerError:')) {
                    console.error('[StiViewer] Server error:', text);
                    return { action: 'ServerError', error: text };
                }
                // Обычный текстовый экспорт — возвращаем как blob
                const blob = new Blob([text], { type: contentType });
                return { isBinary: true, blob, contentType };
            }

            // Всё остальное (binary, text/html, application/*, etc.) — возвращаем как blob
            return { isBinary: true, blob: await response.blob(), contentType };
        } catch (error) {
            this.model.httpError = error;
            throw error;
        }
    }
}
