// Analogue of Angular ModelService
// Stores all viewer state - replaces Angular's @Injectable() + DI with a plain class
// used via React Context (see ViewerContext.tsx)

export interface ControlItem {
    visible: boolean;
    getVisibility: () => { subscribe: (fn: (v: boolean) => void) => void };
    _subscribers: Array<(v: boolean) => void>;
}

export interface DrillDown {
    guid?: string;
    reportFile?: string;
    caption?: string;
    selected?: boolean;
    visible?: boolean;
    reportParams?: any;
}

export interface ErrorMessage {
    text: string;
    type?: any;
}

export interface FormState {
    name: string;
    formData?: any;
}

export interface BookmarkNode {
    title: string;
    url: string;
    children?: BookmarkNode[];
}

export interface InteractionObject {
    [key: string]: any;
}

function createControlItem(initialVisible = false): ControlItem {
    const item: ControlItem = {
        visible: initialVisible,
        _subscribers: [],
        getVisibility: () => ({
            subscribe: (fn: (v: boolean) => void) => {
                item._subscribers.push(fn);
            }
        })
    };
    return item;
}

export class StiReactModelService {
    public requestUrl: string = '';
    public action: string = 'InitViewer';
    public properties: any = null;

    // Аналог Angular newToken() — генерируется один раз при создании модели
    // Сервер использует это как ключ кэша отчёта между запросами
    public readonly clientGuid: string = StiReactModelService.newToken();

    private static newToken(): string {
        const chars = '1234567890abcdefghijklmnopqrstuvwxyz'.split('');
        const parts = ['s'];
        for (let i = 1; i < 32; i++) {
            parts.push(chars[Math.floor(Math.random() * chars.length)]);
        }
        return parts.join('');
    }
    public showDashboard: boolean = false;
    public proxyData: any = null;

    public localization: any = null;
    public options: any = null;
    public pages: any[] = [];
    public months: string[] = [];
    public dayOfWeek: string[] = [];
    public dateRanges: string[] = [];
    public encodingData: any[] = [];
    public pdfSecurityCertificates: any[] = [];
    public paperSizes: string[] = [];
    public viewerSize: { width: number; height: number } | null = null;
    public drillDownButtons: DrillDown[] = [];
    /** Ссылка на DrillDownService — для использования из компонента DrillDownPanel */
    public drillDownService: any = null;
    /** Ссылка на FindService — для использования из компонента FindPanel */
    public findService: any = null;
    public openDialogFileMask: string = '';
    public images: any = null;
    public errorMessage: ErrorMessage | null = null;
    public httpError: any = null;
    public interactions: InteractionObject | null = null;
    public nodes: BookmarkNode[] = [];
    public navigateNode: BookmarkNode | null = null;
    public fullScreenOptions: any = null;
    public showProgress: boolean = false;
    public timerAutoUpdateCache: any = null;
    public refreshReportTimer: any = null;
    public toolbarHideTimer: any = null;
    public notificationFormOptions: any = null;
    public form: FormState | null = null;
    public exportFormat: string = '';
    public exportSettings: { Email?: string; Subject?: string; Message?: string; Attachment?: string } = {};
    public postParametersFunction: any = null;
    public dashboards: string = '';

    /** Chart script, отложенный для выполнения ПОСЛЕ React-рендеринга страниц */
    public pendingChartScript: string | null = null;

    private _reportParams: any = {};

    // Controls — analogues of Angular ControlClass
    public controls: {
        bookmarksPanel:     ControlItem;
        parametersPanel:    ControlItem;
        toolbar:            ControlItem;
        findPanel:          ControlItem;
        navigatePanel:      ControlItem;
        drillDownPanel:     ControlItem;
        resourcesPanel:     ControlItem;
        dashboardsPanel:    ControlItem;
        interactionsPanel:  ControlItem;
        viewer:             { el: any };
        // DOM references used by helper/find/animation services
        reportPanelElement: HTMLElement | null;
        bookmarksLabel:     HTMLElement | null;
        head:               HTMLElement | null;
    } = {
        bookmarksPanel:     createControlItem(),
        parametersPanel:    createControlItem(),
        toolbar:            createControlItem(true),
        findPanel:          createControlItem(),
        navigatePanel:      createControlItem(true),
        drillDownPanel:     createControlItem(),
        resourcesPanel:     createControlItem(),
        dashboardsPanel:    createControlItem(),
        interactionsPanel:  createControlItem(),
        viewer:             { el: null as any },
        reportPanelElement: null,
        bookmarksLabel:     null,
        head:               typeof document !== 'undefined' ? document.getElementsByTagName('head')[0] : null,
    };

    public get reportParams(): any {
        return this._reportParams;
    }

    public set reportParams(parameters: any) {
        this._reportParams.pagesArray = parameters.pagesArray;
        if (parameters.action && parameters.action !== 'GetPages') {
            this._reportParams.type              = parameters.reportType;
            this._reportParams.drillDownGuid     = parameters.drillDownGuid;
            this._reportParams.pagesCount        = parameters.pagesCount;
            if (parameters.pageNumber != null)
                this._reportParams.pageNumber    = parameters.pageNumber;
            this._reportParams.zoom              = parameters.zoom;
            this._reportParams.viewMode          = parameters.viewMode;
            this._reportParams.reportFileName    = parameters.reportFileName;
            this._reportParams.collapsingStates  = parameters.collapsingStates;
            if (parameters.bookmarksContent)
                this._reportParams.bookmarksContent = parameters.bookmarksContent;
            if (parameters.resources)
                this._reportParams.resources     = parameters.resources;
            this._reportParams.isCompilationMode = parameters.isCompilationMode;
            if (parameters.variablesValues)
                this._reportParams.variablesValues = parameters.variablesValues;
            if (parameters.parametersDateFormat && this.options?.appearance)
                this.options.appearance.parametersPanelDateFormat = parameters.parametersDateFormat;
            if (parameters.tableOfContentsPointers)
                this._reportParams.tableOfContentsPointers = parameters.tableOfContentsPointers;
            this._reportParams.isEditableReport  = parameters.isEditableReport;
            if (parameters.userValues && this.options)
                this.options.userValues          = parameters.userValues;
            this._reportParams.dashboards        = parameters.dashboards;
            this._reportParams.previewSettings   = parameters.previewSettings;
        }
    }

    public setReportParams(parameters: any) {
        this._reportParams = parameters;
    }

    /** Получить копию текущих reportParams (аналог Angular model.getReportParams()) */
    public getReportParams(): any {
        return { ...this._reportParams };
    }

    /** Локализация строк — аналог Angular model.loc() */
    public loc(attr: string): string {
        return this.localization?.[attr] ?? attr;
    }

    /** URL картинки по имени — аналог Angular model.img() */
    public img(name: string): string {
        return this.images?.[name] ?? '';
    }
}
