// Аналог Angular ExportFormComponent
// Диалог настроек экспорта отчёта — полное соответствие Angular

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { createPortal } from 'react-dom';
import { useViewer } from '../hooks/useViewer';
import { BaseForm } from './BaseForm';
import { StiDropDownList, DropDownItem } from '../controls/DropDownList';
import { StiTextBox } from '../controls/TextBox';
import { StiCheckbox } from '../controls/Checkbox';

export interface ExportFormProps {
    visible: boolean;
    format: string;
    sendMail?: boolean;
    initialSettings?: any;
    onExport: (format: string, settings: any, sendMail: boolean) => void;
    onClose: () => void;
}

// ─── Секция настроек (GroupPanel) — аналог Angular GroupPanelComponent ────────
// Angular: stiJsViewerFormButton для заголовка + stiJsViewerGroupPanelContainer
const GroupPanel: React.FC<{
    caption: string;
    opened?: boolean;
    imgFn?: (name: string) => string;
    children: React.ReactNode;
}> = ({ caption, opened: initialOpen = true, imgFn, children }) => {
    const [open, setOpen] = useState(initialOpen);
    const [over, setOver] = useState(false);
    const styleName = 'stiJsViewerFormButton';
    const headerClass = `${styleName} ${styleName}${over ? 'Over' : 'Default'}`;
    const arrowImg = imgFn
        ? imgFn(open ? 'Arrows.BigArrowDown.png' : 'Arrows.BigArrowRight.png')
        : null;

    return (
        <div style={{ minWidth: 390, margin: '4px' }}>
            {/* Заголовок группы — Angular: sti-form-button */}
            <div
                className={headerClass}
                onClick={() => setOpen(!open)}
                onMouseOver={() => setOver(true)}
                onMouseOut={() => setOver(false)}
                style={{ cursor: 'pointer', userSelect: 'none', margin: 0, background: '#ffffff', border: '1px solid #c6c6c6', borderRadius: '3px 3px 0 0' }}
            >
                <table className="stiJsViewerClearAllStyles" cellPadding={0} cellSpacing={0}
                    style={{ width: '100%', height: '100%' }}>
                    <tbody>
                        <tr className="stiJsViewerClearAllStyles">
                            <td className="stiJsViewerClearAllStyles"
                                style={{ width: 1, padding: 0, textAlign: 'center', lineHeight: 0 }}>
                                {arrowImg
                                    ? <img src={arrowImg} alt="" style={{ width: 16, height: 16, padding: '0 4px' }} />
                                    : <span style={{ padding: '0 6px', fontSize: 10 }}>{open ? '▼' : '▶'}</span>
                                }
                            </td>
                            <td className="stiJsViewerClearAllStyles"
                                style={{ textAlign: 'left', whiteSpace: 'nowrap', padding: '0 15px 0 5px' }}>
                                {caption}
                            </td>
                        </tr>
                    </tbody>
                </table>
            </div>
            {/* Содержимое — Angular: div.stiJsViewerGroupPanelContainer */}
            {open && (
                <div className="stiJsViewerGroupPanelContainer" style={{ padding: '4px 0' }}>
                    {children}
                </div>
            )}
        </div>
    );
};

// ─── Строка настройки ─────────────────────────────────────────────────────────
const SettingRow: React.FC<{
    label?: string;
    tooltip?: string;
    children: React.ReactNode;
}> = ({ label, tooltip, children }) => (
    <tr className="stiJsViewerClearAllStyles">
        {label != null
            ? <>
                <td className="stiJsViewerClearAllStyles"
                    title={tooltip}
                    style={{ padding: '3px 8px', minWidth: 150, whiteSpace: 'nowrap' }}>{label}</td>
                <td className="stiJsViewerClearAllStyles"
                    style={{ padding: '3px 8px' }}>{children}</td>
              </>
            : <td className="stiJsViewerClearAllStyles" colSpan={2}
                style={{ padding: '3px 8px' }}>{children}</td>
        }
    </tr>
);

// ─── Радиокнопка (аналог Angular sti-radio-button) ───────────────────────────
// Кастомные div-круги с CSS stiJsViewerRadioButtonOutCircle / InnerCircle
const RadioRow: React.FC<{
    label: string;
    name: string;
    group: string;
    checked: boolean;
    enabled?: boolean;
    onChange: () => void;
    children?: React.ReactNode;
    margin?: string;
}> = ({ label, name, group, checked, enabled = true, onChange, children, margin = '6px 8px' }) => {
    const [over, setOver] = useState(false);
    const outClass = !enabled
        ? 'stiJsViewerRadioButtonOutCircleDisabled'
        : (over ? 'stiJsViewerRadioButtonOutCircleOver' : 'stiJsViewerRadioButtonOutCircle');

    return (
        <tr className="stiJsViewerClearAllStyles">
            <td className="stiJsViewerClearAllStyles" colSpan={2} style={{ padding: margin }}>
                <table
                    className={enabled ? 'stiJsViewerRadioButton' : 'stiJsViewerRadioButtonDisabled'}
                    cellPadding={0} cellSpacing={0}
                    style={{ cursor: enabled ? 'pointer' : 'default' }}
                    onMouseOver={() => enabled && setOver(true)}
                    onMouseOut={() => enabled && setOver(false)}
                    onClick={() => enabled && onChange()}
                >
                    <tbody>
                        <tr className="stiJsViewerClearAllStyles">
                            <td className="stiJsViewerClearAllStyles">
                                <div className={outClass}
                                    style={{ width: 15, height: 15, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                    <div className="stiJsViewerRadioButtonInnerCircle"
                                        style={{
                                            width: 7, height: 7,
                                            margin: 3,
                                            visibility: checked ? 'visible' : 'hidden',
                                            opacity: enabled ? 1 : 0.5,
                                        }}
                                    />
                                </div>
                            </td>
                            <td className="stiJsViewerClearAllStyles"
                                style={{ paddingLeft: 4, whiteSpace: 'nowrap' }}>
                                {label}
                            </td>
                            {children && (
                                <td className="stiJsViewerClearAllStyles" style={{ paddingLeft: 4 }}>
                                    {children}
                                </td>
                            )}
                        </tr>
                    </tbody>
                </table>
            </td>
        </tr>
    );
};

// ─── Панель безопасности документа (Document Security) — аналог Angular DocumentSecurityMenuComponent ───
const DocumentSecurityPanel: React.FC<{
    settings: any;
    setSetting: (key: string, value: any) => void;
    loc: (k: string) => string;
    imgFn: (name: string) => string;
}> = ({ settings, setSetting, loc, imgFn }) => {
    const [open, setOpen] = useState(false);
    const [over, setOver] = useState(false);

    const keyLengthItems: DropDownItem[] = [
        { key: 'Bit40', value: '40 bit RC4 (Acrobat 3)' },
        { key: 'Bit128', value: '128 bit RC4 (Acrobat 5)' },
        { key: 'Bit128_r4', value: '128 bit AES (Acrobat 7)' },
        { key: 'Bit256_r5', value: '256 bit AES (Acrobat 9)' },
        { key: 'Bit256_r6', value: '256 bit AES (Acrobat X)' },
    ];

    // UserAccessPrivileges helpers
    const getPrivilege = (name: string): boolean => {
        const priv = settings.UserAccessPrivileges ?? 'All';
        return priv === 'All' || (priv || '').indexOf(name) >= 0;
    };
    const updatePrivileges = (name: string, checked: boolean) => {
        const privList = ['PrintDocument', 'ModifyContents', 'CopyTextAndGraphics', 'AddOrModifyTextAnnotations'];
        const current = settings.UserAccessPrivileges ?? 'All';
        let active: string[];
        if (current === 'All') {
            active = [...privList];
        } else {
            active = privList.filter(p => (current || '').indexOf(p) >= 0);
        }
        if (checked && !active.includes(name)) active.push(name);
        if (!checked) active = active.filter(p => p !== name);
        setSetting('UserAccessPrivileges', active.length === privList.length ? 'All' : active.join(','));
    };

    const styleName = 'stiJsViewerFormButton';
    const btnClass = `${styleName} ${styleName}${over ? 'Over' : 'Default'}`;
    const arrowImg = imgFn('Arrows.SmallArrowDown.png') || imgFn('Arrows.BigArrowDown.png');
    const btnRef = useRef<HTMLDivElement>(null);
    const [dropPos, setDropPos] = useState<{ top: number; left: number } | null>(null);

    const toggleOpen = useCallback(() => {
        if (!open && btnRef.current) {
            const rect = btnRef.current.getBoundingClientRect();
            setDropPos({ top: rect.bottom + 2, left: rect.left });
        }
        setOpen(!open);
    }, [open]);

    // Закрытие по клику вне панели
    useEffect(() => {
        if (!open) return;
        const handleClick = (e: MouseEvent) => {
            const portal = document.getElementById('sti-doc-security-portal');
            if (portal && portal.contains(e.target as Node)) return;
            if (btnRef.current && btnRef.current.contains(e.target as Node)) return;
            setOpen(false);
        };
        document.addEventListener('mousedown', handleClick);
        return () => document.removeEventListener('mousedown', handleClick);
    }, [open]);

    return (
        <div>
            {/* Button — аналог SmallButton с arrow Down */}
            <div
                ref={btnRef}
                className={btnClass}
                onClick={toggleOpen}
                onMouseOver={() => setOver(true)}
                onMouseOut={() => setOver(false)}
                style={{ cursor: 'pointer', userSelect: 'none', margin: 0, display: 'inline-block' }}
            >
                <table className="stiJsViewerClearAllStyles" cellPadding={0} cellSpacing={0}
                    style={{ width: '100%', height: '100%' }}>
                    <tbody>
                        <tr className="stiJsViewerClearAllStyles">
                            <td className="stiJsViewerClearAllStyles"
                                style={{ textAlign: 'left', whiteSpace: 'nowrap', padding: '0 10px 0 10px' }}>
                                {loc('DocumentSecurityButton')}
                            </td>
                            <td className="stiJsViewerClearAllStyles"
                                style={{ width: 1, lineHeight: 0, padding: '0 6px 0 0' }}>
                                {arrowImg
                                    ? <img src={arrowImg} alt="" style={{ width: 8, height: 8 }} />
                                    : <span style={{ fontSize: 8 }}>▼</span>
                                }
                            </td>
                        </tr>
                    </tbody>
                </table>
            </div>
            {/* Dropdown content — портал в body, чтобы не обрезалось overflow */}
            {open && dropPos && createPortal(
                <div id="sti-doc-security-portal" className="stiJsViewerDropdownPanel"
                    style={{ position: 'fixed', top: dropPos.top, left: dropPos.left, zIndex: 99999,
                        padding: '4px 0', background: '#fff', border: '1px solid #c6c6c6',
                        boxShadow: '0 2px 8px rgba(0,0,0,0.2)', minWidth: 340,
                        fontFamily: 'Arial', fontSize: 12, color: '#202020' }}>
                    <table className="stiJsViewerClearAllStyles" cellPadding={0} cellSpacing={0} style={{ width: '100%' }}>
                        <tbody>
                            <SettingRow label={loc('UserPassword')}>
                                <StiTextBox value={settings.PasswordInputUser ?? ''} width={160} margin="2px 8px"
                                    onChange={v => setSetting('PasswordInputUser', v)} />
                            </SettingRow>
                            <SettingRow label={loc('OwnerPassword')}>
                                <StiTextBox value={settings.PasswordInputOwner ?? ''} width={160} margin="2px 8px"
                                    onChange={v => setSetting('PasswordInputOwner', v)} />
                            </SettingRow>
                            <tr className="stiJsViewerClearAllStyles">
                                <td className="stiJsViewerClearAllStyles" colSpan={2} style={{ padding: '0px 8px' }}>
                                    <StiCheckbox captionText={loc('AllowPrintDocument')} isChecked={getPrivilege('PrintDocument')}
                                        margin="4px 0px" onChange={v => updatePrivileges('PrintDocument', !!v)} />
                                </td>
                            </tr>
                            <tr className="stiJsViewerClearAllStyles">
                                <td className="stiJsViewerClearAllStyles" colSpan={2} style={{ padding: '0px 8px' }}>
                                    <StiCheckbox captionText={loc('AllowModifyContents')} isChecked={getPrivilege('ModifyContents')}
                                        margin="4px 0px" onChange={v => updatePrivileges('ModifyContents', !!v)} />
                                </td>
                            </tr>
                            <tr className="stiJsViewerClearAllStyles">
                                <td className="stiJsViewerClearAllStyles" colSpan={2} style={{ padding: '0px 8px' }}>
                                    <StiCheckbox captionText={loc('AllowCopyTextAndGraphics')} isChecked={getPrivilege('CopyTextAndGraphics')}
                                        margin="4px 0px" onChange={v => updatePrivileges('CopyTextAndGraphics', !!v)} />
                                </td>
                            </tr>
                            <tr className="stiJsViewerClearAllStyles">
                                <td className="stiJsViewerClearAllStyles" colSpan={2} style={{ padding: '0px 8px' }}>
                                    <StiCheckbox captionText={loc('AllowAddOrModifyTextAnnotations')} isChecked={getPrivilege('AddOrModifyTextAnnotations')}
                                        margin="4px 0px" onChange={v => updatePrivileges('AddOrModifyTextAnnotations', !!v)} />
                                </td>
                            </tr>
                            <SettingRow label={loc('EncryptionKeyLength')}>
                                <StiDropDownList items={keyLengthItems} selectedKey={settings.KeyLength ?? 'Bit40'}
                                    width={160} margin="2px 8px"
                                    onChange={k => setSetting('KeyLength', k)} />
                            </SettingRow>
                        </tbody>
                    </table>
                </div>,
                document.body
            )}
        </div>
    );
};

