// ─── Получение настроек по умолчанию для формата ─────────────────────────────
function getDefaultExportSettings(format: string, model: any): any {
    const exports = model.options?.exports ?? {};
    const defaultSettings = exports.defaultSettings ?? {};

    let settings: any = {};

    switch (format) {
        case 'Document':
            settings = { Format: 'Mdc' };
            break;
        case 'Pdf':
            settings = { ...(defaultSettings['StiPdfExportSettings'] ?? {}),
                ImageResolutionMode: 'Auto', ImageResolution: 96, ImageQuality: 90, ImageCompressionMethod: 'Jpeg',
                AllowEditable: 'No', StandardPdfFonts: false, EmbeddedFonts: true, ExportRtfTextAsImage: false,
                PdfACompliance: false, PdfComplianceMode: 'A1',
                UseDigitalSignature: false, CertificateThumbprint: '',
                PasswordInputUser: '', PasswordInputOwner: '',
                UserAccessPrivileges: 'All', KeyLength: 'Bit40' };
            break;
        case 'Xps':
            settings = { ...(defaultSettings['StiXpsExportSettings'] ?? {}),
                ImageResolution: 96, ImageQuality: 90, ExportRtfTextAsImage: false };
            break;
        case 'PowerPoint':
            settings = { ...(defaultSettings['StiPowerPointExportSettings'] ?? defaultSettings['StiPpt2007ExportSettings'] ?? {}),
                ImageResolution: 96, ImageQuality: 90 };
            break;
        case 'Html':
            settings = { ...(defaultSettings['StiHtmlExportSettings'] ?? {}),
                HtmlType: 'Html', Zoom: 1, ImageFormat: 'Png', ExportMode: 'Table',
                UseEmbeddedImages: true, AddPageBreaks: false };
            break;
        case 'Html5':
            settings = { ...(defaultSettings['StiHtmlExportSettings'] ?? {}),
                HtmlType: 'Html5', ImageFormat: 'Png', ImageResolution: 96, ImageQuality: 90,
                ContinuousPages: false };
            break;
        case 'Mht':
            settings = { ...(defaultSettings['StiHtmlExportSettings'] ?? {}),
                HtmlType: 'Mht', Zoom: 1, ImageFormat: 'Png', ExportMode: 'Table', AddPageBreaks: false };
            break;
        case 'Text':
            settings = { ...(defaultSettings['StiTxtExportSettings'] ?? {}),
                KillSpaceLines: false, PutFeedPageCode: false, DrawBorder: true,
                CutLongLines: false, BorderType: 'UnicodeSingle', ZoomX: 1, ZoomY: 1, Encoding: 'UTF-8' };
            break;
        case 'Rtf':
            settings = { ...(defaultSettings['StiRtfExportSettings'] ?? {}),
                ImageResolution: 96, ImageQuality: 90, ExportMode: 'Table',
                UsePageHeadersAndFooters: false, RemoveEmptySpaceAtBottom: false };
            break;
        case 'Word':
            settings = { ...(defaultSettings['StiWordExportSettings'] ?? defaultSettings['StiWord2007ExportSettings'] ?? {}),
                ImageResolution: 96, ImageQuality: 90,
                UsePageHeadersAndFooters: false, RemoveEmptySpaceAtBottom: false };
            break;
        case 'Odt':
            settings = { ...(defaultSettings['StiOdtExportSettings'] ?? {}),
                ImageResolution: 96, ImageQuality: 90, RemoveEmptySpaceAtBottom: false };
            break;
        case 'Excel':
            settings = { ...(defaultSettings['StiExcelExportSettings'] ?? {}),
                ExcelType: 'Excel', ImageResolution: 96, ImageQuality: 90,
                DataExportMode: 'AllBands', ExportObjectFormatting: true,
                UseOnePageHeaderAndFooter: false, ExportEachPageToSheet: false, ExportPageBreaks: true };
            break;
        case 'ExcelBiff':
            settings = { ...(defaultSettings['StiExcelExportSettings'] ?? {}),
                ExcelType: 'ExcelBinary', ImageResolution: 96, ImageQuality: 90,
                DataExportMode: 'AllBands', ExportObjectFormatting: true,
                UseOnePageHeaderAndFooter: false, ExportEachPageToSheet: false, ExportPageBreaks: true };
            break;
        case 'ExcelXml':
            settings = { ...(defaultSettings['StiExcelExportSettings'] ?? {}),
                ExcelType: 'ExcelXml' };
            break;
        case 'Ods':
            settings = { ...(defaultSettings['StiOdsExportSettings'] ?? {}),
                ImageResolution: 96, ImageQuality: 90 };
            break;
        case 'Csv':
            settings = { ...(defaultSettings['StiDataExportSettings'] ?? {}),
                DataType: 'Csv', Encoding: 'UTF-8', Separator: ';', DataExportMode: 'AllBands', SkipColumnHeaders: false };
            break;
        case 'Dbf':
            settings = { ...(defaultSettings['StiDataExportSettings'] ?? {}),
                DataType: 'Dbf', CodePage: 'UTF-8' };
            break;
        case 'Dif':
            settings = { ...(defaultSettings['StiDataExportSettings'] ?? {}),
                DataType: 'Dif', ExportDataOnly: false, UseDefaultSystemEncoding: true, Encoding: 'UTF-8' };
            break;
        case 'Sylk':
            settings = { ...(defaultSettings['StiDataExportSettings'] ?? {}),
                DataType: 'Sylk', ExportDataOnly: false, UseDefaultSystemEncoding: true, Encoding: 'UTF-8' };
            break;
        case 'Json':
            settings = { ...(defaultSettings['StiDataExportSettings'] ?? {}),
                DataType: 'Json', DataExportMode: 'AllBands' };
            break;
        case 'Xml':
            settings = { ...(defaultSettings['StiDataExportSettings'] ?? {}),
                DataType: 'Xml', DataExportMode: 'AllBands' };
            break;
        default:
            // Image formats
            if (format.startsWith('Image')) {
                const imageType = format.replace('Image', '');
                settings = { ...(defaultSettings['StiImageExportSettings'] ?? {}),
                    ImageType: imageType, ImageZoom: 1, ImageResolution: 96,
                    ImageFormat: 'Color', DitheringType: 'None', TiffCompressionScheme: 'LZW',
                    CompressToArchive: false, CutEdges: false, MultipleFiles: false };
            }
            break;
    }

    // OpenAfterExport — всегда false, всегда скачиваем файл
    settings.OpenAfterExport = false;

    // PageRange default
    settings.PageRange = settings.PageRange ?? 'All';

    return settings;
}
