// Аналог Angular TooltipComponent + TooltipService
// Tooltip рендерится ВНУТРИ stiJsViewerMainPanel (как Angular), не через portal
// Позиционируется абсолютно: left от кнопки, top = toolbar.offsetHeight + dashboardsPanel.offsetHeight

import React, { useRef, useState, useEffect, useCallback } from 'react';
import { useViewer } from '../hooks/useViewer';

interface TooltipState {
    visible: boolean;
    caption: string;
    helpLink?: string;
    left: number;
    top: number;
    opacity: number;
}

const initialState: TooltipState = {
    visible: false,
    caption: '',
    left: 0,
    top: 0,
    opacity: 0,
};

// Singleton-сервис для управления tooltip — аналог Angular TooltipService
let _showFn: ((left: number, top: number, caption: string, below: boolean, helpLink?: string) => void) | null = null;
let _hideFn: (() => void) | null = null;
let _hideImmediatelyFn: (() => void) | null = null;

export const tooltipService = {
    show(left: number, top: number, caption: string, below: boolean = true, helpLink?: string) {
        _showFn?.(left, top, caption, below, helpLink);
    },
    hide() {
        _hideFn?.();
    },
    hideImmediately() {
        _hideImmediatelyFn?.();
    },
};

// helpLinks — аналог Angular HelperService.helpLinks
export const helpLinks: Record<string, string> = {
    Print: 'user-manual/index.html?viewer_reports.htm#toolbar',
    Save: 'user-manual/index.html?viewer_reports.htm#toolbar',
    SendEmail: 'user-manual/index.html?viewer_reports.htm#toolbar',
    Open: 'user-manual/index.html?viewer_reports.htm#toolbar',
    Bookmarks: 'user-manual/index.html?viewer_reports.htm#toolbar',
    Parameters: 'user-manual/index.html?viewer_reports.htm#toolbar',
    Resources: 'user-manual/index.html?viewer_reports.htm#toolbar',
    FirstPage: 'user-manual/index.html?viewer_reports.htm#statusbar',
    PrevPage: 'user-manual/index.html?viewer_reports.htm#statusbar',
    NextPage: 'user-manual/index.html?viewer_reports.htm#statusbar',
    LastPage: 'user-manual/index.html?viewer_reports.htm#statusbar',
    FullScreen: 'user-manual/index.html?viewer_reports.htm#toolbar',
    Zoom: 'user-manual/index.html?viewer_reports.htm#statusbar',
    ViewMode: 'user-manual/index.html?viewer_reports.htm#displayingmode',
    Editor: 'user-manual/index.html?viewer_reports.htm#toolbar',
    Find: 'user-manual/index.html?viewer_reports.htm#searchpanel',
};

export const StiTooltip: React.FC = () => {
    const { model } = useViewer();
    const elRef = useRef<HTMLDivElement>(null);
    const [state, setState] = useState<TooltipState>(initialState);
    const hideTimeoutRef = useRef<any>(null);
    const fadeTimeoutRef = useRef<any>(null);
    const innerStateRef = useRef<string>('initial');
    const captionRef = useRef<string>('');

    const showTooltips = model.options?.appearance?.showTooltips !== false;
    // Angular: model.options.appearance.showTooltipsHelp — показывает "Tell Me More" кнопку
    const showTooltipsHelp = model.options?.appearance?.showTooltipsHelp !== false;

    // Аналог Angular tooltipService.show()
    // left/top — координаты относительно stiJsViewerMainPanel
    const show = useCallback((left: number, top: number, caption: string, below: boolean, helpLink?: string) => {
        if (!showTooltips) {
            setState(initialState);
            return;
        }

        // Очищаем pending hide
        if (hideTimeoutRef.current) {
            clearTimeout(hideTimeoutRef.current);
            hideTimeoutRef.current = null;
        }

        // Если тот же caption уже показан — просто оставляем
        if (captionRef.current === caption && innerStateRef.current === 'expanded') {
            return;
        }

        captionRef.current = caption;
        innerStateRef.current = 'preInitial';

        // Сначала рендерим невидимо для измерения размеров
        setState({
            visible: true,
            caption,
            helpLink,
            left: -9999,
            top: -9999,
            opacity: 0,
        });

        // После рендера — позиционируем и запускаем fade-in
        requestAnimationFrame(() => {
            const el = elRef.current;
            if (!el || innerStateRef.current === 'initial') return;

            // Ширина контейнера (stiJsViewerMainPanel)
            const mainPanel = el.closest('.stiJsViewerMainPanel') as HTMLElement | null;
            const containerWidth = mainPanel?.offsetWidth ?? window.innerWidth;

            let finalLeft = left;
            let finalTop = below ? top : top - el.offsetHeight;

            // Не выходим за правый край контейнера
            if (finalLeft + el.offsetWidth > containerWidth) {
                finalLeft = containerWidth - el.offsetWidth;
            }
            if (finalLeft < 0) finalLeft = 0;

            setState(prev => ({
                ...prev,
                left: finalLeft,
                top: finalTop,
            }));

            // Задержка 300ms перед появлением — аналог Angular animate('300ms 300ms ease-in-out')
            if (fadeTimeoutRef.current) clearTimeout(fadeTimeoutRef.current);
            fadeTimeoutRef.current = setTimeout(() => {
                if (innerStateRef.current !== 'initial') {
                    innerStateRef.current = 'expanded';
                    setState(prev => ({ ...prev, opacity: 1 }));
                }
            }, 300);
        });
    }, [showTooltips]);

    // Аналог Angular tooltipService.hide() — с задержкой 1000ms
    const hide = useCallback(() => {
        innerStateRef.current = 'initial';
        if (fadeTimeoutRef.current) {
            clearTimeout(fadeTimeoutRef.current);
            fadeTimeoutRef.current = null;
        }
        if (hideTimeoutRef.current) {
            clearTimeout(hideTimeoutRef.current);
        }
        hideTimeoutRef.current = setTimeout(() => {
            if (innerStateRef.current === 'initial') {
                captionRef.current = '';
                setState(initialState);
            }
            hideTimeoutRef.current = null;
        }, 1000);
    }, []);

    // Аналог Angular tooltipService.hideImmediately()
    const hideImmediately = useCallback(() => {
        innerStateRef.current = 'initial';
        captionRef.current = '';
        if (hideTimeoutRef.current) clearTimeout(hideTimeoutRef.current);
        if (fadeTimeoutRef.current) clearTimeout(fadeTimeoutRef.current);
        setState(initialState);
    }, []);

    // Регистрируем функции как singleton
    useEffect(() => {
        _showFn = show;
        _hideFn = hide;
        _hideImmediatelyFn = hideImmediately;
        return () => {
            _showFn = null;
            _hideFn = null;
            _hideImmediatelyFn = null;
        };
    }, [show, hide, hideImmediately]);

    // Очистка таймеров при unmount
    useEffect(() => {
        return () => {
            if (hideTimeoutRef.current) clearTimeout(hideTimeoutRef.current);
            if (fadeTimeoutRef.current) clearTimeout(fadeTimeoutRef.current);
        };
    }, []);

    const handleMouseOver = () => {
        // Аналог Angular tooltipService.showFromTooltip()
        if (innerStateRef.current !== 'preInitial') {
            innerStateRef.current = 'expanded';
            if (hideTimeoutRef.current) {
                clearTimeout(hideTimeoutRef.current);
                hideTimeoutRef.current = null;
            }
            setState(prev => ({ ...prev, opacity: 1 }));
        }
    };

    const handleMouseOut = () => {
        hide();
    };

    const handleHelpClick = () => {
        if (state.helpLink) {
            const helpUrl = model.options?.helpUrl ?? 'https://www.stimulsoft.com/en/documentation/online/programming-manual/';
            window.open(helpUrl + state.helpLink, '_blank');
        }
        hideImmediately();
    };

    if (!state.visible) return null;

    // Рендерится прямо в JSX (внутри stiJsViewerMainPanel), НЕ через portal
    // Angular: <sti-tooltip> прямо внутри viewer component
    return (
        <div
            ref={elRef}
            className="stiJsViewerToolTip"
            style={{
                position: 'absolute',
                left: state.left,
                top: state.top,
                zIndex: 100000,
                opacity: state.opacity,
                transition: 'opacity 300ms ease-in-out',
                pointerEvents: state.opacity > 0 ? 'auto' : 'none',
            }}
            onMouseOver={handleMouseOver}
            onMouseOut={handleMouseOut}
        >
            {/* Angular: table.stiJsViewerClearAllStyles с border условным */}
            <table
                className="stiJsViewerClearAllStyles"
                cellPadding={0}
                cellSpacing={0}
                style={{
                    height: '100%',
                    border: showTooltipsHelp ? undefined : 0,
                }}
            >
                <tbody>
                    {/* Текст tooltip */}
                    <tr className="stiJsViewerClearAllStyles">
                        <td className="stiJsViewerToolTipTextCell">
                            {state.caption}
                        </td>
                    </tr>
                    {/* Кнопка "Tell Me More" — Angular: *ngIf="model.options.appearance.showTooltipsHelp" */}
                    {showTooltipsHelp && (
                        <tr className="stiJsViewerClearAllStyles">
                            <td className="stiJsViewerClearAllStyles">
                                {/* Angular: sti-button с styleName='stiJsViewerHyperlinkButton' */}
                                <div
                                    className="stiJsViewerHyperlinkButton stiJsViewerHyperlinkButtonDefault"
                                    style={{
                                        margin: '4px 8px 4px 8px',
                                        cursor: 'pointer',
                                        display: 'inline-block',
                                    }}
                                    onClick={handleHelpClick}
                                    onMouseOver={e => e.currentTarget.className = 'stiJsViewerHyperlinkButton stiJsViewerHyperlinkButtonOver'}
                                    onMouseOut={e => e.currentTarget.className = 'stiJsViewerHyperlinkButton stiJsViewerHyperlinkButtonDefault'}
                                >
                                    <table className="stiJsViewerClearAllStyles" cellPadding={0} cellSpacing={0} style={{ height: '100%' }}>
                                        <tbody>
                                            <tr className="stiJsViewerClearAllStyles">
                                                <td className="stiJsViewerClearAllStyles" style={{ lineHeight: 0, padding: '0 3px', textAlign: 'center' }}>
                                                    <img
                                                        src={model.img('HelpIcon.png')}
                                                        alt=""
                                                        style={{ width: 16, height: 16, display: 'block' }}
                                                    />
                                                </td>
                                                <td className="stiJsViewerClearAllStyles" style={{ whiteSpace: 'nowrap', textAlign: 'left', padding: '1px 5px 1px 0' }}>
                                                    {model.loc('TellMeMore')}
                                                </td>
                                            </tr>
                                        </tbody>
                                    </table>
                                </div>
                            </td>
                        </tr>
                    )}
                </tbody>
            </table>
        </div>
    );
};
