// Аналог Angular OpenDialogComponent
// Скрытый <input type="file">, который программно кликается когда задан openDialogFileMask

import React, { useRef, useEffect } from 'react';
import { useViewer } from '../hooks/useViewer';
import { StiReactControllerService } from '../services/controller.service';

export const OpenDialog: React.FC = () => {
    const { model, controller } = useViewer();
    const inputRef = useRef<HTMLInputElement>(null);
    const prevMaskRef = useRef<string | null>(null);

    useEffect(() => {
        const mask = model.openDialogFileMask;

        // Кликаем только когда маска свежевыставлена (не была такой в предыдущем рендере)
        if (mask != null && mask !== '' && mask !== prevMaskRef.current && inputRef.current) {
            prevMaskRef.current = mask;
            setTimeout(() => {
                inputRef.current?.click();
            });
        }

        if (mask == null) {
            prevMaskRef.current = null;
        }
    });

    const handleChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        const files = event.target.files;
        if (!files || files.length === 0) { return; }

        const file = files[0];
        const fileName = file.name;
        const reader = new FileReader();

        reader.onload = (e: ProgressEvent<FileReader>) => {
            const content = e.target?.result as string;
            (controller as StiReactControllerService).loadFile(fileName, content);
        };

        // Сбрасываем маску чтобы можно было открыть тот же файл ещё раз
        model.openDialogFileMask = null;
        // Сбрасываем value инпута
        if (inputRef.current) { inputRef.current.value = ''; }

        reader.readAsDataURL(file);
    };

    if (model.openDialogFileMask == null) { return null; }

    return (
        <input
            ref={inputRef}
            type="file"
            multiple
            accept={model.openDialogFileMask ?? undefined}
            style={{ display: 'none' }}
            onChange={handleChange}
        />
    );
};
