// React Context — replaces Angular's Dependency Injection system
// Every child component gets access to model and controller via useViewer() hook

import React, { createContext } from 'react';
import { StiReactModelService } from './services/model.service';
import { StiReactControllerService } from './services/controller.service';

export interface ViewerContextType {
    model: StiReactModelService;
    controller: StiReactControllerService;
}

export const ViewerContext = createContext<ViewerContextType | null>(null);
