// Аналог Angular ToolbarService
// Строит список кнопок тулбара по настройкам options.toolbar

import { StiReactModelService } from './model.service';
import { StiReactHelperService } from './helper.service';

export interface ComponentDescription {
    type: 'button' | 'separator' | 'separator6' | 'pageControl';
    action?: string;
    caption?: string;
    img?: string;
    tooltip?: boolean;
    arrow?: string | null;
    menuItems?: any[];
    selected?: boolean;
    imageSize?: string;
}

export class StiReactToolbarService {

    public comps: ComponentDescription[] = [];
    public dopComps: ComponentDescription[] = [];

    public controller: any = null;

    constructor(
        private model: StiReactModelService,
        private helper: StiReactHelperService
    ) { }

    /** Инициализировать список кнопок по настройкам из options.toolbar */
    public initButtons() {
        const opts = this.model.options?.toolbar;
        if (!opts) { return; }

        const comps: ComponentDescription[] = [];
        const dopComps: ComponentDescription[] = [];
        let isFirst = true;

        // Правый блок (about, design, pin)
        if (opts.showAboutButton) {
            dopComps.push({ type: 'button', action: 'About', img: 'Help.png' });
        }
        if (opts.showAboutButton && opts.showDesignButton) {
            dopComps.push({ type: 'separator' });
        }
        if (opts.showDesignButton) {
            dopComps.push({ type: 'button', action: 'Design', caption: this.loc('Design'), img: 'Design.png' });
        }
        if (opts.showPinToolbarButton && opts.showDesignButton) {
            dopComps.push({ type: 'separator' });
        }
        if (opts.showPinToolbarButton) {
            dopComps.push({ type: 'button', action: 'Pin', img: 'Pin.png' });
        }

        // Print
        if (opts.showPrintButton) {
            const hasMenu = opts.printDestination === 'Default';
            comps.push({
                type: 'button', action: 'Print', caption: this.loc('Print'), img: 'Print.png', tooltip: true,
                arrow: hasMenu ? 'Down' : null,
                menuItems: hasMenu ? [
                    { name: 'PrintPdf',             caption: this.loc('PrintPdf'),             img: 'Save.Small.Pdf.png' },
                    { name: 'PrintWithPreview',     caption: this.loc('PrintWithPreview'),     img: 'ViewMode.png' },
                    { name: 'PrintWithoutPreview',  caption: this.loc('PrintWithoutPreview'),  img: 'Print.png' }
                ] : null
            });
            isFirst = false;
        }

        // Open
        if (opts.showOpenButton) {
            comps.push({ type: 'button', action: 'Open', caption: this.loc('Open'), img: 'Open.png', tooltip: true });
            isFirst = false;
        }

        // Save
        if (opts.showSaveButton) {
            comps.push({
                type: 'button', action: 'Save', caption: this.loc('Save'), img: 'Save.png', tooltip: true, arrow: 'Down',
                menuItems: this.getSaveMenuItems('saveMenu')
            });
            isFirst = false;
        }

        // Send Email
        if (opts.showSendEmailButton) {
            comps.push({
                type: 'button', action: 'SendEmail', caption: this.loc('SendEmail'), img: 'SendEmail.png', tooltip: true, arrow: 'Down',
                menuItems: this.getSaveMenuItems('sendEmailMenu')
            });
            isFirst = false;
        }

        // Bookmarks / Parameters / Resources
        if (opts.showBookmarksButton || opts.showParametersButton) {
            if (!isFirst) { comps.push({ type: 'separator' }); }
            isFirst = false;
        }
        if (opts.showBookmarksButton) {
            comps.push({ type: 'button', action: 'Bookmarks', caption: opts.displayMode === 'Separated' ? this.loc('Bookmarks') : null, img: 'Bookmarks.png', tooltip: true });
        }
        if (opts.showParametersButton) {
            comps.push({ type: 'button', action: 'Parameters', caption: opts.displayMode === 'Separated' ? this.loc('Parameters') : null, img: 'Parameters.png', tooltip: true });
        }
        if (opts.showResourcesButton) {
            comps.push({ type: 'button', action: 'Resources', caption: opts.displayMode === 'Separated' ? this.loc('Resources') : null, img: 'Resources.png', tooltip: true });
        }

        // Find / Editor
        if (opts.showFindButton || opts.showEditorButton) {
            if (!isFirst) { comps.push({ type: 'separator' }); }
            isFirst = false;
        }
        if (opts.showFindButton) {
            comps.push({ type: 'button', action: 'Find', img: 'Find.png', tooltip: true });
        }
        if (opts.showEditorButton) {
            comps.push({ type: 'button', action: 'Editor', img: 'Editor.png', tooltip: true });
        }

        // Navigation (only in non-Separated mode)
        if (opts.displayMode !== 'Separated') {
            const hasNavButtons = opts.showFirstPageButton || opts.showPreviousPageButton ||
                opts.showNextPageButton || opts.showLastPageButton || opts.showCurrentPageControl;
            if (hasNavButtons) {
                if (!isFirst) { comps.push({ type: 'separator' }); }
                isFirst = false;
            }

            const rtl = this.model.options?.appearance?.rightToLeft;
            if (opts.showFirstPageButton) {
                comps.push({ type: 'button', action: 'FirstPage', img: rtl ? 'LastPage.png' : 'FirstPage.png', tooltip: true });
            }
            if (opts.showPreviousPageButton) {
                comps.push({ type: 'button', action: 'PrevPage', img: rtl ? 'NextPage.png' : 'PrevPage.png', tooltip: true });
            }
            if (opts.showCurrentPageControl) {
                comps.push({ type: 'pageControl' });
            }
            if (opts.showNextPageButton) {
                comps.push({ type: 'button', action: 'NextPage', img: rtl ? 'PrevPage.png' : 'NextPage.png', tooltip: true });
            }
            if (opts.showLastPageButton) {
                comps.push({ type: 'button', action: 'LastPage', img: rtl ? 'FirstPage.png' : 'LastPage.png', tooltip: true });
            }

            // Разделитель перед Zoom/ViewMode (аналог Angular строки 127-132)
            if (opts.showViewModeButton || opts.showZoomButton) {
                if (!isFirst) { comps.push({ type: 'separator' }); }
                isFirst = false;
            }
        }

        // Full Screen
        if (opts.showFullScreenButton) {
            comps.push({ type: 'button', action: 'FullScreen', img: 'FullScreen.png', tooltip: true });
            comps.push({ type: 'separator' });
            isFirst = false;
        }

        // Zoom
        if (opts.showZoomButton && opts.displayMode !== 'Separated') {
            comps.push({
                type: 'button', action: 'Zoom', caption: '100%', img: 'Zoom.png', tooltip: true, arrow: 'Down',
                menuItems: this.helper.getZoomMenuItems()
            });
            isFirst = false;
        }

        // View Mode
        if (opts.showViewModeButton) {
            comps.push({
                type: 'button', action: 'ViewMode', caption: this.loc('SinglePage'), img: 'SinglePage.png', tooltip: true, arrow: 'Down',
                menuItems: [
                    { name: 'ViewModeSinglePage',    caption: this.loc('SinglePage'),    img: 'SinglePage.png' },
                    { name: 'ViewModeContinuous',    caption: this.loc('Continuous'),    img: 'Continuous.png' },
                    { name: 'ViewModeMultiplePages', caption: this.loc('MultiplePages'), img: 'MultiplePages.png' }
                ]
            });
        }

        const rtl = this.model.options?.appearance?.rightToLeft;
        this.comps    = rtl ? [...comps].reverse()    : comps;
        this.dopComps = rtl ? [...dopComps].reverse() : dopComps;
    }

    /** Обновить caption/selected кнопок после загрузки страниц */
    public updateButtons() {
        const rp = this.model.reportParams;

        this.comps.filter(c => c.action === 'ViewMode').forEach(c => {
            c.caption = this.loc(rp.viewMode ?? 'Continuous');
        });

        this.comps.filter(c => c.action === 'Zoom').forEach(c => {
            c.caption = rp.zoom ? Math.round(rp.zoom) + '%' : '';
            c.menuItems?.forEach(n => {
                n.selected = n.name === 'Zoom' + rp.zoom;
            });
        });

        this.comps.filter(c => c.action === 'ShowFind').forEach(c => {
            c.selected = this.model.controls.findPanel?.visible ?? false;
        });
    }

    /** Кнопка активна? */
    public isEnabled(desc: ComponentDescription): boolean {
        const rp = this.model.reportParams;
        const disableNavi = this.disableNaviButtons();

        switch (desc.action) {
            case 'FirstPage':
            case 'PrevPage':
                return (rp.pageNumber ?? 0) > 0 && !disableNavi;
            case 'NextPage':
            case 'LastPage':
                return (rp.pageNumber ?? 0) < (rp.pagesCount ?? 1) - 1 && !disableNavi;
            case 'Bookmarks':
                return rp.bookmarksContent != null;
            case 'Parameters':
                return this.model.interactions?.paramsVariables != null;
            case 'Resources':
                return (rp.resources?.length ?? 0) > 0;
        }
        return true;
    }

    /** Кнопка нажата/активна? */
    public isSelected(desc: ComponentDescription): boolean {
        switch (desc.action) {
            case 'Find':       return this.model.controls.findPanel?.visible ?? false;
            case 'Bookmarks':  return this.model.controls.bookmarksPanel?.visible ?? false;
            case 'Parameters': return this.model.controls.parametersPanel?.visible ?? false;
            case 'Resources':  return this.model.controls.resourcesPanel?.visible ?? false;
            case 'FullScreen': return this.model.options?.appearance?.fullScreenMode ?? false;
            case 'Pin':        return !(this.model.options?.toolbar?.autoHide ?? false);
            case 'Editor':     return this.controller?.editableFieldsService?.visible ?? false;
        }
        return false;
    }

    public disableNaviButtons(): boolean {
        const vm = this.model.reportParams?.viewMode;
        const scrollbars = this.model.options?.appearance?.scrollbarsMode;
        const fullScreen = this.model.options?.appearance?.fullScreenMode;
        return vm === 'MultiplePages' || vm === 'WholeReport' ||
            (vm === 'Continuous' && !scrollbars && !fullScreen);
    }

    // ─── Save menu ────────────────────────────────────────────────────────────

    public getSaveMenuItems(menuName: string): ComponentDescription[] {
        const items: any[] = [];
        const exports = this.model.options?.exports;
        const imageSize = this.model.options?.appearance?.saveMenuImageSize;
        if (!exports) { return items; }

        let isFirst = true;
        const sep = () => { if (!isFirst) { items.push({ imageSize, type: 'separator' }); } isFirst = false; };

        // Document
        if (exports.showExportToDocument && menuName === 'saveMenu') {
            items.push({ name: menuName + 'Document', caption: this.loc('ReportSnapshot'), imageSize, img: this.img('Document') });
            isFirst = false;
        }

        // PDF / XPS / PowerPoint
        if (exports.showExportToPdf || exports.showExportToXps || exports.showExportToPowerPoint) {
            sep();
        }
        if (exports.showExportToPdf)         { items.push({ name: menuName + 'Pdf',        caption: 'Adobe PDF',             imageSize, img: this.img('Pdf') }); }
        if (exports.showExportToXps)         { items.push({ name: menuName + 'Xps',        caption: 'Microsoft XPS',         imageSize, img: this.img('Xps') }); }
        if (exports.showExportToPowerPoint)  { items.push({ name: menuName + 'PowerPoint', caption: 'Microsoft PowerPoint',  imageSize, img: this.img('Ppt') }); }

        // HTML
        if (exports.showExportToHtml || exports.showExportToHtml5 || exports.showExportToMht) {
            sep();
            let htmlType = exports.defaultSettings?.StiHtmlExportSettings?.HtmlType ?? 'Html';
            if (!exports['showExportTo' + htmlType]) {
                htmlType = exports.showExportToHtml ? 'Html' : exports.showExportToHtml5 ? 'Html5' : 'Mht';
            }
            items.push({ name: menuName + htmlType, caption: 'HTML', imageSize, img: this.img('Html') });
        }

        // Text / RTF / Word / ODT
        if (exports.showExportToText || exports.showExportToRtf || exports.showExportToWord || exports.showExportToOdt) { sep(); }
        if (exports.showExportToText) { items.push({ name: menuName + 'Text', caption: this.loc('Text'), imageSize, img: this.img('Text') }); }
        if (exports.showExportToRtf)  { items.push({ name: menuName + 'Rtf',  caption: 'RTF',             imageSize, img: this.img('Rtf') }); }
        if (exports.showExportToWord) { items.push({ name: menuName + 'Word', caption: 'Microsoft Word',  imageSize, img: this.img('Word') }); }
        if (exports.showExportToOpenDocumentWriter) {
            items.push({ name: menuName + 'Odt', caption: 'OpenDocument Writer', imageSize, img: this.img('Odt') });
        }

        // Excel
        if (exports.showExportToExcelBiff || exports.showExportToExcel || exports.showExportToExcelXml) {
            sep();
            let excelType = exports.defaultSettings?.StiExcelExportSettings?.ExcelType ?? 'Excel';
            if (!exports['showExportTo' + excelType]) {
                excelType = exports.showExportToExcel ? 'Excel' : exports.showExportToExcelBiff ? 'ExcelBiff' : 'ExcelXml';
            }
            items.push({ name: menuName + excelType, caption: 'Microsoft Excel', imageSize, img: this.img('Excel') });
        }
        if (exports.showExportToOpenDocumentCalc) {
            items.push({ name: menuName + 'Ods', caption: 'OpenDocument Calc', imageSize, img: this.img('Ods') });
        }

        // CSV / XML / JSON / DBF / DIF / SYLK
        if (exports.showExportToCsv || exports.showExportToDbf || exports.showExportToXml ||
            exports.showExportToDif || exports.showExportToSylk || exports.showExportToJson) {
            sep();
            let dataType = exports.defaultSettings?.StiDataExportSettings?.DataType ?? 'Csv';
            if (!exports['showExportTo' + dataType]) {
                dataType = exports.showExportToCsv ? 'Csv' : exports.showExportToDbf ? 'Dbf' :
                    exports.showExportToXml ? 'Xml' : exports.showExportToDif ? 'Dif' :
                    exports.showExportToSylk ? 'Sylk' : 'Json';
            }
            items.push({ name: menuName + dataType, caption: this.loc('Data'), imageSize, img: this.img('Data') });
        }

        // Images
        const hasImage = exports.showExportToImageBmp || exports.showExportToImageGif || exports.showExportToImageJpeg ||
            exports.showExportToImagePcx || exports.showExportToImagePng || exports.showExportToImageTiff ||
            exports.showExportToImageMetafile || exports.showExportToImageSvg || exports.showExportToImageSvgz;
        if (hasImage) {
            sep();
            let imgType = exports.defaultSettings?.StiImageExportSettings?.ImageType ?? 'Png';
            const imgType_ = imgType === 'Emf' ? 'Metafile' : imgType;
            if (!exports['showExportToImage' + imgType_]) {
                imgType = exports.showExportToImagePng ? 'Png' : exports.showExportToImageJpeg ? 'Jpeg' :
                    exports.showExportToImageBmp ? 'Bmp' : exports.showExportToImageGif ? 'Gif' :
                    exports.showExportToImageTiff ? 'Tiff' : exports.showExportToImageSvg ? 'Svg' : 'Svgz';
            }
            items.push({ name: menuName + 'Image' + imgType, caption: this.loc('Image'), imageSize, img: this.img('Image') });
        }

        return items;
    }

    private loc(key: string): string { return this.model.loc(key); }

    private img(name: string): string {
        const size = this.model.options?.appearance?.saveMenuImageSize;
        if (size === 'None') { return null; }
        const prefix = size === 'Big' ? 'Save.Big.' : 'Save.Small.';
        return prefix + name + '.png';
    }
}
