// Аналог Angular DropDownListComponent — выпадающий список

import React, { useState, useRef } from 'react';
import { useViewer } from '../hooks/useViewer';

export interface DropDownItem {
    key: any;
    value: string;
}

export interface DropDownListProps {
    items: DropDownItem[];
    selectedKey?: any;
    width?: number;
    margin?: string;
    enabled?: boolean;
    readOnly?: boolean;
    tooltip?: string;
    onChange?: (key: any, value: string) => void;
}

export const StiDropDownList: React.FC<DropDownListProps> = ({
    items = [],
    selectedKey,
    width = 160,
    margin,
    enabled = true,
    readOnly = false,
    tooltip,
    onChange
}) => {
    const { model } = useViewer();
    const [over, setOver] = useState(false);

    const isTouchDevice = model.options?.isTouchDevice ?? false;
    const h = isTouchDevice ? '26px' : '21px';
    const fontFamily = model.options?.toolbar?.fontFamily ?? 'inherit';
    const fontColor = model.options?.toolbar?.fontColor ?? 'inherit';

    const selectedItem = items.find(i => i.key === selectedKey);
    const displayValue = selectedItem?.value ?? '';

    const className = enabled
        ? (over ? 'stiJsViewerDropDownListOver' : 'stiJsViewerDropDownList')
        : 'stiJsViewerDropDownListDisabled';

    return (
        <div
            className={className}
            title={tooltip}
            style={{ display: 'inline-block', margin, verticalAlign: 'top' }}
            onMouseOver={() => setOver(true)}
            onMouseOut={() => setOver(false)}
        >
            <select
                value={selectedKey ?? ''}
                disabled={!enabled || readOnly}
                style={{
                    width, height: h, fontFamily, color: fontColor,
                    border: 'none', background: 'transparent',
                    fontSize: 'inherit', cursor: enabled && !readOnly ? 'pointer' : 'default',
                    boxSizing: 'border-box', padding: '0 2px'
                }}
                onChange={e => {
                    const selected = items.find(i => String(i.key) === e.target.value);
                    if (selected) onChange?.(selected.key, selected.value);
                }}
            >
                {items.map((item, i) => (
                    <option key={i} value={String(item.key)}>{item.value}</option>
                ))}
            </select>
        </div>
    );
};
