// Аналог Angular DrillDownService
// Управляет панелью хлебных крошек (drill-down кнопки) и состоянием drill-down навигации

import { StiReactModelService } from './model.service';
import { StiReactControllerService } from './controller.service';

export class StiReactDrillDownService {

    private controller: StiReactControllerService | null = null;

    constructor(private model: StiReactModelService) { }

    /**
     * Подписаться на сообщения контроллера (аналог Angular constructor subscribe)
     * Вызывается один раз при инициализации
     */
    public subscribeToController(controller: StiReactControllerService): () => void {
        this.controller = controller;
        return controller.onMessage((message) => {
            if (message.action !== 'InitVars' && message.action !== 'viewer_loaded') {
                this.model.options.drillDownInProgress = false;
                const parameters = message.data;
                if (!parameters) return;

                // Если нет кнопок — добавляем корневую (исходный отчёт)
                // Имя берём из ТЕКУЩЕГО model.reportParams (до замены на drill-down),
                // а не из ответа (ответ DrillDown содержит имя drill-down страницы)
                if (this.model.drillDownButtons.length === 0) {
                    const rootName = this.model.reportParams?.reportFileName ?? 'Report';
                    this.addButton(rootName, {});
                }

                if (message.action === 'DrillDown') {
                    this.showDrillDownPage(
                        parameters.reportFileName,
                        parameters.drillDownGuid,
                        parameters.drillDownParameters
                    );
                }
            }
        });
    }

    private showDrillDownPage(reportFileName: string, drillDownGuid: string, drillDownParameters: any) {
        let buttonExist = false;

        this.model.drillDownButtons.forEach((b: any) => {
            if (b.reportParams?.drillDownGuid === drillDownGuid) {
                this.model.drillDownButtons.forEach((bt: any) => { bt.selected = false; });
                buttonExist = b.selected = b.visible = true;
                this.model.reportParams.drillDownParameters = b.reportParams.drillDownParameters;
            }
        });

        if (!buttonExist) {
            // Создаём кнопку с drillDownGuid и drillDownParameters в reportParams,
            // чтобы при повторном drill-down на тот же уровень кнопка находилась
            this.addButton(reportFileName, { drillDownGuid, drillDownParameters });
            this.model.reportParams.drillDownParameters = drillDownParameters;
            this.model.reportParams.pageNumber = 0;
        }
    }

    public addButton(caption: string, reportParams: any = {}) {
        this.model.drillDownButtons.forEach((b: any) => { b.selected = false; });
        this.model.drillDownButtons.push({
            caption,
            selected: true,
            reportParams: { ...reportParams },
            visible: true,
        });
        this.updateVisibility();
    }

    public updateVisibility() {
        if (this.model.controls.drillDownPanel) {
            this.model.controls.drillDownPanel.visible = this.model.drillDownButtons.length > 1;
        }
    }

    /**
     * Сохранить состояние активной кнопки (страница, зум, и т.д.) перед drill-down
     * Вызывается перед каждым новым drill-down из InteractionsService
     *
     * ВАЖНО: если кнопок ещё нет — создаём корневую кнопку с ТЕКУЩИМ состоянием.
     * Это критично, т.к. saveState() вызывается в postInteraction ДО отправки
     * drill-down запроса, и когда onMessage получит ответ — reportParams уже будет
     * обновлён данными drill-down страницы. Без этого корневая кнопка получит пустой
     * reportParams и навигация назад не сработает.
     */
    public saveState() {
        if (this.model.drillDownButtons.length === 0) {
            // Создаём корневую кнопку с текущим (ещё не изменённым) состоянием
            const rootName = this.model.reportParams?.reportFileName ?? 'Report';
            this.addButton(rootName, this.model.getReportParams());
            return;
        }
        const selected = this.model.drillDownButtons.find((b: any) => b.selected);
        if (selected) {
            selected.reportParams = this.model.getReportParams();
        }
    }

    /**
     * Клик по вкладке — восстановить состояние и перезагрузить страницы
     * Аналог Angular DrillDownPanelComponent.action(button)
     */
    public selectButton(button: any) {
        this.saveState();
        this.model.drillDownButtons.forEach((b: any) => { b.selected = false; });
        button.selected = true;
        this.model.setReportParams(button.reportParams);
        this.controller?.getPages();
    }

    /**
     * Закрыть вкладку — удалить кнопку, если она была выбрана — перейти к корневой
     * Аналог Angular DrillDownPanelComponent.close(button)
     */
    public closeButton(button: any) {
        const buttons = this.model.drillDownButtons;
        const idx = buttons.indexOf(button);
        if (idx >= 0) {
            buttons.splice(idx, 1);
        }
        button.visible = false;

        if (button.selected && buttons.length > 0) {
            this.selectButton(buttons[0]);
        }
        this.updateVisibility();
    }
}
