// Аналог Angular SendEmailFormComponent — форма отправки отчёта по e-mail

import React, { useState, useEffect } from 'react';
import { useViewer } from '../hooks/useViewer';
import { BaseForm } from './BaseForm';
import { StiTextBox } from '../controls/TextBox';

export interface SendEmailFormProps {
    visible: boolean;
    format: string;
    onSend: (format: string, settings: { Email: string; Subject: string; Message: string }) => void;
    onClose: () => void;
}

export const SendEmailForm: React.FC<SendEmailFormProps> = ({ visible, format, onSend, onClose }) => {
    const { model } = useViewer();
    const exportSettings = model.exportSettings;

    const [email,   setEmail]   = useState(exportSettings.Email   ?? '');
    const [subject, setSubject] = useState(exportSettings.Subject ?? '');
    const [message, setMessage] = useState(exportSettings.Message ?? '');

    // Sync from model when opened
    useEffect(() => {
        if (visible) {
            setEmail(exportSettings.Email   ?? '');
            setSubject(exportSettings.Subject ?? '');
            setMessage(exportSettings.Message ?? '');
        }
    }, [visible]);

    const loc = (k: string) => model.loc?.(k) ?? k;

    const handleOk = () => {
        // Persist back to model
        model.exportSettings.Email   = email;
        model.exportSettings.Subject = subject;
        model.exportSettings.Message = message;
        onSend(format, { Email: email, Subject: subject, Message: message });
        onClose();
    };

    const inputWidth = 280;

    const tdLabel: React.CSSProperties = {
        padding: '4px 8px', fontSize: 12, whiteSpace: 'nowrap', verticalAlign: 'middle'
    };
    const tdField: React.CSSProperties = {
        padding: '4px 8px'
    };

    return (
        <BaseForm
            name="sendEmailForm"
            caption={loc('EmailOptions')}
            visible={visible}
            level={1}
            defaultTop={150}
            onOk={handleOk}
            onClose={onClose}
        >
            <table cellPadding={0} cellSpacing={0} style={{ margin: 5 }}>
                <tbody>
                    <tr>
                        <td className="stiJsViewerCaptionControls" style={tdLabel}>{loc('Email')}</td>
                        <td style={tdField}>
                            <StiTextBox
                                value={email}
                                width={inputWidth}
                                focusOnCreate={true}
                                onChange={setEmail}
                            />
                        </td>
                    </tr>
                    <tr>
                        <td className="stiJsViewerCaptionControls" style={tdLabel}>{loc('Subject')}</td>
                        <td style={tdField}>
                            <StiTextBox
                                value={subject}
                                width={inputWidth}
                                onChange={setSubject}
                            />
                        </td>
                    </tr>
                    <tr>
                        <td className="stiJsViewerCaptionControls"
                            style={{ ...tdLabel, verticalAlign: 'top', paddingTop: 7 }}>
                            {loc('Message')}
                        </td>
                        <td style={tdField}>
                            <textarea
                                value={message}
                                rows={4}
                                onChange={e => setMessage(e.target.value)}
                                style={{
                                    width: inputWidth, height: 70, fontSize: 12,
                                    padding: '2px 4px', boxSizing: 'border-box',
                                    resize: 'vertical', fontFamily: 'inherit'
                                }}
                            />
                        </td>
                    </tr>
                    {exportSettings.Attachment && (
                        <tr>
                            <td className="stiJsViewerCaptionControls" style={tdLabel}>{loc('Attachment')}</td>
                            <td style={{ ...tdField, fontSize: 12 }}>{exportSettings.Attachment}</td>
                        </tr>
                    )}
                </tbody>
            </table>
        </BaseForm>
    );
};
