// Аналог Angular ToolbarComponent + ButtonComponent + ToolbarDopComponent
// Структура HTML и CSS-классы точно совпадают с Angular-реализацией

import React, { useRef, useState, useEffect, useLayoutEffect, useCallback } from 'react';
import { createPortal } from 'react-dom';
import { useViewer } from '../hooks/useViewer';
import { StiReactToolbarService, ComponentDescription } from '../services/toolbar.service';
import { StiReactHelperService } from '../services/helper.service';
import { StiReactAnimationService } from '../services/animation.service';
import { tooltipService, helpLinks } from './Tooltip';

// ─── Кнопка тулбара (аналог Angular ButtonComponent) ────────────────────────

interface StiButtonProps {
    comp: ComponentDescription;
    enabled: boolean;
    selected: boolean;
    menuOpen: boolean;
    onAction: (action: string) => void;
    onToggleMenu: (action: string, el: HTMLElement) => void;
    imgFn: (name: string) => string;
    showCaptions: boolean;
    isMobile: boolean;
    locFn: (key: string) => string;
    localization: any;
    toolbarOffsetHeight: number;
}

const StiButton: React.FC<StiButtonProps> = ({
    comp, enabled, selected, menuOpen, onAction, onToggleMenu, imgFn, showCaptions, isMobile,
    locFn, localization, toolbarOffsetHeight
}) => {
    const [over, setOver] = useState(false);
    const canShowTooltipRef = useRef(true);
    const btnRef = useRef<HTMLDivElement>(null);
    const styleName = 'stiJsViewerStandartSmallButton';

    // Аналог Angular className getter:
    // styleName + ' ' + styleName + (enabled ? (selected/over/default) : 'Disabled')
    const state = !enabled
        ? 'Disabled'
        : (selected || menuOpen) ? 'Selected'
        : over ? 'Over'
        : 'Default';
    const className = `${styleName} ${styleName}${state}`;

    // Angular: caption отображается всегда если задан в ComponentDescription
    // showButtonCaptions не влияет на отображение caption в Angular
    const caption = comp.caption ?? null;
    const imageName = comp.img ?? null;
    const arrow = !isMobile ? comp.arrow : null;
    const hasMenu = !!(comp.menuItems && comp.menuItems.length > 0);

    const handleClick = () => {
        if (!enabled) return;
        tooltipService.hideImmediately();
        canShowTooltipRef.current = false;
        if (hasMenu) {
            onToggleMenu(comp.action ?? '', btnRef.current!);
        } else {
            onAction(comp.action ?? '');
        }
    };

    // Аналог Angular button.component mouseover — показываем tooltip
    const handleMouseOver = () => {
        if (!enabled) return;
        setOver(true);

        if (comp.tooltip && canShowTooltipRef.current) {
            const actionName = comp.action ?? '';
            // Аналог Angular: localization[actionName + 'ToolTip'] ?? loc(actionName)
            const tooltipText = localization?.[actionName + 'ToolTip'] != null
                ? locFn(actionName + 'ToolTip')
                : locFn(actionName);
            const hLink = helpLinks[actionName];

            // Позиция: Angular: findPosX от кнопки, top = toolbar.offsetHeight + dashboardsPanel.offsetHeight
            const el = btnRef.current;
            if (el) {
                // findPosX relative to stiJsViewerMainPanel
                let posX = 0;
                let node: HTMLElement | null = el;
                while (node && !node.classList.contains('stiJsViewerMainPanel')) {
                    posX += node.offsetLeft;
                    node = node.offsetParent as HTMLElement | null;
                }
                // top: toolbar height + dashboards panel height (если есть)
                const mainPanel = el.closest('.stiJsViewerMainPanel') as HTMLElement | null;
                let topPos = toolbarOffsetHeight;
                if (mainPanel) {
                    const dashPanel = mainPanel.querySelector('.stiJsViewerDashboardsPanel') as HTMLElement | null;
                    if (dashPanel) topPos += dashPanel.offsetHeight;
                }
                tooltipService.show(posX, topPos, tooltipText, true, hLink);
            }
        }
    };

    const handleMouseOut = () => {
        if (!enabled) return;
        setOver(false);
        tooltipService.hide();
        setTimeout(() => { canShowTooltipRef.current = true; }, 1000);
    };

    // Стрелка: Arrows.SmallArrowDown.png или Arrows.SmallArrowUp.png
    const arrowImg = arrow === 'Down' || arrow === 'Up'
        ? imgFn(`Arrows.SmallArrow${arrow}.png`)
        : arrow ? imgFn(arrow) : null;

    return (
        <div
            ref={btnRef}
            className={className}
            style={{
                height: '23px',
                boxSizing: 'content-box',
                margin: '1px',
                display: 'inline-block',
                cursor: enabled ? 'pointer' : 'default',
                userSelect: 'none',
            }}
            onMouseOver={handleMouseOver}
            onMouseOut={handleMouseOut}
            onClick={handleClick}
        >
            {/* Внутренняя таблица — точная копия Angular */}
            <table
                className="stiJsViewerClearAllStyles"
                cellPadding={0}
                cellSpacing={0}
                style={{ height: '100%' }}
            >
                <tbody>
                    <tr className="stiJsViewerClearAllStyles">
                        {/* Ячейка с иконкой */}
                        {imageName && (
                            <td
                                className="stiJsViewerClearAllStyles"
                                style={{ lineHeight: 0, padding: '0 3px', textAlign: 'center' }}
                            >
                                <img
                                    src={imgFn(imageName)}
                                    alt=""
                                    style={{
                                        width: 16,
                                        height: 16,
                                        opacity: enabled ? 1 : 0.5,
                                        display: 'block',
                                    }}
                                />
                            </td>
                        )}
                        {/* Ячейка с текстом (только если showButtonCaptions и caption задан) */}
                        {caption != null && (
                            <td
                                className="stiJsViewerClearAllStyles"
                                style={{
                                    whiteSpace: 'nowrap',
                                    textAlign: 'left',
                                    padding: arrow ? '1px 0' : `1px 5px 1px ${imageName ? '0' : '5px'}`,
                                }}
                            >
                                {caption}
                            </td>
                        )}
                        {/* Ячейка со стрелкой дропдауна */}
                        {arrow && (
                            <td className="stiJsViewerClearAllStyles">
                                {arrowImg ? (
                                    <img
                                        src={arrowImg}
                                        alt=""
                                        style={{
                                            lineHeight: 0,
                                            width: 8,
                                            height: 8,
                                            verticalAlign: 'baseline',
                                            padding: caption ? '0 5px' : '0 5px 0 2px',
                                            opacity: enabled ? 1 : 0.5,
                                            display: 'inline-block',
                                        }}
                                    />
                                ) : (
                                    <span style={{ fontSize: 9, padding: '0 4px', color: '#666' }}>▾</span>
                                )}
                            </td>
                        )}
                    </tr>
                </tbody>
            </table>
        </div>
    );
};

// ─── Выпадающее меню (аналог Angular MenuService popup) ─────────────────────
// Рендерится через Portal в document.body чтобы не клипаться родительскими контейнерами

interface StiDropdownMenuProps {
    anchorEl: HTMLElement;   // кнопка-триггер для вычисления позиции
    items: any[];
    imgFn: (name: string) => string;
    onAction: (action: string) => void;
    onClose: () => void;
    fontFamily?: string;
}

const StiDropdownMenu: React.FC<StiDropdownMenuProps> = ({ anchorEl, items, imgFn, onAction, onClose, fontFamily }) => {
    const menuRef = useRef<HTMLDivElement>(null);
    const [pos, setPos] = useState<{ top: number; left: number } | null>(null);

    // Вычисляем позицию после монтирования — под кнопкой, но в координатах viewport+scroll
    useLayoutEffect(() => {
        if (!anchorEl || !menuRef.current) return;
        const btnRect = anchorEl.getBoundingClientRect();
        const menuRect = menuRef.current.getBoundingClientRect();
        const scrollX = window.scrollX ?? window.pageXOffset;
        const scrollY = window.scrollY ?? window.pageYOffset;

        let left = btnRect.left + scrollX;
        const top  = btnRect.bottom + scrollY;

        // Если меню выходит за правый край — выравниваем по правому краю кнопки
        if (left + menuRect.width > window.innerWidth + scrollX) {
            left = btnRect.right + scrollX - menuRect.width;
        }

        setPos({ top, left });
    }, [anchorEl]);

    const menu = (
        <div
            ref={menuRef}
            className="stiJsViewerMenu"
            style={{
                position: 'absolute',
                top:  pos ? pos.top  : -9999,
                left: pos ? pos.left : -9999,
                zIndex: 99999,
                visibility: pos ? 'visible' : 'hidden',
                fontFamily: fontFamily || 'Arial',
                fontSize: '12px',
            }}
            onMouseDown={e => e.stopPropagation()}
        >
            <table
                className="stiJsViewerClearAllStyles"
                cellPadding={0}
                cellSpacing={0}
                style={{ borderCollapse: 'collapse' }}
            >
                <tbody>
                    {items.map((item: any, idx: number) => {
                        if (item.type === 'separator') {
                            return (
                                <tr key={idx}>
                                    <td colSpan={2}>
                                        <div className="stiJsViewerVerticalMenuSeparator" />
                                    </td>
                                </tr>
                            );
                        }
                        const itemImg = item.img ? imgFn(item.img) : null;
                        const itemAction = item.name ?? item.action ?? '';
                        const isBig = item.imageSize === 'Big';
                        const imgSize = isBig ? 32 : 16;
                        const itemHeight = isBig ? '38px' : '24px';
                        const styleName = 'stiJsViewerMenuStandartItem';
                        return (
                            <tr key={idx}>
                                <td colSpan={2} style={{ padding: 0 }}>
                                    <div
                                        className={`${styleName} ${styleName}Default`}
                                        onMouseOver={e => (e.currentTarget.className = `${styleName} ${styleName}Over`)}
                                        onMouseOut={e => (e.currentTarget.className = `${styleName} ${styleName}Default`)}
                                        onClick={() => { onAction(itemAction); onClose(); }}
                                        style={{ height: itemHeight, cursor: 'pointer', userSelect: 'none' }}
                                    >
                                        <table className="stiJsViewerClearAllStyles" cellPadding={0} cellSpacing={0}
                                            style={{ height: '100%', width: '100%' }}>
                                            <tbody>
                                                <tr className="stiJsViewerClearAllStyles">
                                                    {itemImg && (
                                                        <td className="stiJsViewerClearAllStyles"
                                                            style={{ width: 22, minWidth: 22, padding: 0, textAlign: 'center', lineHeight: 0 }}>
                                                            <img src={itemImg} alt=""
                                                                style={{ width: imgSize, height: imgSize }} />
                                                        </td>
                                                    )}
                                                    <td className="stiJsViewerClearAllStyles"
                                                        style={{ whiteSpace: 'nowrap', textAlign: 'left', padding: '0 20px 0 7px' }}>
                                                        {item.caption ?? ''}
                                                    </td>
                                                </tr>
                                            </tbody>
                                        </table>
                                    </div>
                                </td>
                            </tr>
                        );
                    })}
                </tbody>
            </table>
        </div>
    );

    // Рендерим через Portal — прямо в body, вне любых overflow-контейнеров
    return createPortal(menu, document.body);
};

// ─── Главный компонент тулбара ───────────────────────────────────────────────

export const Toolbar: React.FC = () => {
    const { model, controller } = useViewer();

    // Ленивая инициализация ToolbarService
    const toolbarSvcRef = useRef<StiReactToolbarService | null>(null);
    if (!toolbarSvcRef.current && model.options) {
        const animSvc = new StiReactAnimationService(model);
        const helperSvc = new StiReactHelperService(model, animSvc);
        toolbarSvcRef.current = new StiReactToolbarService(model, helperSvc);
        toolbarSvcRef.current.controller = controller;
        toolbarSvcRef.current.initButtons();
    } else if (toolbarSvcRef.current && model.options) {
        toolbarSvcRef.current.updateButtons();
    }

    const [openDropdown, setOpenDropdown] = useState<string | null>(null);
    const [anchorEl, setAnchorEl] = useState<HTMLElement | null>(null);
    const toolbarRef = useRef<HTMLDivElement>(null);

    // Закрыть дропдаун при клике в любом месте (меню — в portal, вне toolbar)
    useEffect(() => {
        if (!openDropdown) return;
        const handler = (e: MouseEvent) => {
            setOpenDropdown(null);
            setAnchorEl(null);
        };
        document.addEventListener('mousedown', handler);
        return () => document.removeEventListener('mousedown', handler);
    }, [openDropdown]);

    // Обработка действий кнопок — делегируем controller.action() (аналог Angular)
    // controller.action() обновляет model.reportParams, затем вызывает GetPages
    const handleAction = useCallback((action: string) => {
        console.log('[Toolbar] handleAction:', action);
        setOpenDropdown(null);
        controller.action({ name: action });
    }, [controller]);

    const toolbarSvc = toolbarSvcRef.current;
    const opts = model.options?.toolbar;

    if (!opts || opts.visible === false) {
        return null;
    }

    const comps = toolbarSvc?.comps ?? [];
    const dopComps = toolbarSvc?.dopComps ?? [];
    const showCaptions = opts.showButtonCaptions ?? false;
    const isMobile = model.options?.isMobileDevice ?? false;
    const isSeparated = opts.displayMode === 'Separated';
    const bgColor = opts.backgroundColor ?? undefined;
    const borderColor = opts.borderColor ?? undefined;
    const fontFamily = opts.fontFamily ?? undefined;
    const fontColor = opts.fontColor ?? undefined;

    const toolbarClass = `stiJsViewerToolBar${isSeparated ? ' stiJsViewerToolBarSeparated' : ''}`;

    // Рендер одного компонента (кнопка, разделитель, pageControl)
    const renderComp = (comp: ComponentDescription, idx: number) => {
        if (comp.type === 'separator' || comp.type === 'separator6') {
            return (
                <td key={idx} className="stiJsViewerClearAllStyles" style={{ padding: '0 2px' }}>
                    <div className="stiJsViewerToolBarSeparator" style={{ width: 1, height: isMobile ? '0.4in' : '21px' }} />
                </td>
            );
        }

        if (comp.type === 'pageControl') {
            const pcEnabled = !toolbarSvc?.disableNaviButtons?.();
            const pageCount = model.reportParams?.pagesCount ?? 1;
            const toolbarFontColor = opts?.fontColor;
            const textBoxColor = pcEnabled
                ? (toolbarFontColor && toolbarFontColor !== 'Empty' ? toolbarFontColor : '#444444')
                : (model.reportParams?.viewMode !== 'SinglePage' ? 'transparent' : toolbarFontColor);
            return (
                <td key={idx} className="stiJsViewerClearAllStyles">
                    {/* Аналог Angular sti-page-control: Page [input] of [count] */}
                    <table className="stiJsViewerClearAllStyles" cellPadding={0} cellSpacing={0} style={{ margin: '1px' }}>
                        <tbody>
                            <tr className="stiJsViewerClearAllStyles">
                                <td className="stiJsViewerClearAllStyles" style={{ padding: '0 2px' }}>
                                    {model.loc('Page')}
                                </td>
                                {isMobile ? (
                                    <td className="stiJsViewerClearAllStyles" style={{ padding: '0 2px' }}>
                                        <span>{(model.reportParams?.pageNumber ?? 0) + 1}</span>
                                    </td>
                                ) : (
                                    <td className="stiJsViewerClearAllStyles" style={{ padding: '0 2px' }}>
                                        <input
                                            className="stiJsViewerTextBox stiJsViewerTextBoxDefault"
                                            type="text"
                                            disabled={!pcEnabled}
                                            value={(model.reportParams?.pageNumber ?? 0) + 1}
                                            style={{
                                                width: 45,
                                                height: 21,
                                                lineHeight: '21px',
                                                boxSizing: 'content-box',
                                                textAlign: 'center',
                                                fontFamily: opts?.fontFamily || undefined,
                                                color: textBoxColor ?? undefined,
                                                opacity: pcEnabled ? 1 : 0.5,
                                            }}
                                            onChange={e => {
                                                // будет обработано в onKeyDown/onBlur
                                            }}
                                            onKeyDown={e => {
                                                if (e.key === 'Enter') {
                                                    let val = parseInt((e.target as HTMLInputElement).value, 10);
                                                    if (!val || val < 1) val = 1;
                                                    if (val > pageCount) val = pageCount;
                                                    if (model.reportParams && model.reportParams.pageNumber !== val - 1) {
                                                        controller.action({ name: 'GoToPage', value: val - 1 });
                                                    }
                                                }
                                            }}
                                            onBlur={e => {
                                                let val = parseInt(e.target.value, 10);
                                                if (!val || val < 1) val = 1;
                                                if (val > pageCount) val = pageCount;
                                                if (model.reportParams && model.reportParams.pageNumber !== val - 1) {
                                                    controller.action({ name: 'GoToPage', value: val - 1 });
                                                }
                                            }}
                                        />
                                    </td>
                                )}
                                <td className="stiJsViewerClearAllStyles" style={{ padding: '0 2px' }}>
                                    {model.loc('PageOf')}
                                </td>
                                <td className="stiJsViewerClearAllStyles" style={{ padding: '0 2px' }}>
                                    {pageCount > 0 ? pageCount : '?'}
                                </td>
                            </tr>
                        </tbody>
                    </table>
                </td>
            );
        }

        if (comp.type !== 'button') return null;

        const enabled = toolbarSvc ? toolbarSvc.isEnabled(comp) : true;
        const selected = toolbarSvc ? toolbarSvc.isSelected(comp) : false;
        const hasMenu = !!(comp.menuItems && comp.menuItems.length > 0);
        const isOpen = hasMenu && openDropdown === comp.action;

        return (
            <td key={idx} className="stiJsViewerClearAllStyles" style={{ position: 'relative' }}>
                <StiButton
                    comp={comp}
                    enabled={enabled}
                    selected={selected}
                    menuOpen={isOpen}
                    onAction={handleAction}
                    onToggleMenu={(action, el) => {
                        if (openDropdown === action) {
                            setOpenDropdown(null);
                            setAnchorEl(null);
                        } else {
                            setOpenDropdown(action);
                            setAnchorEl(el);
                        }
                    }}
                    imgFn={name => model.img(name)}
                    showCaptions={showCaptions}
                    isMobile={isMobile}
                    locFn={key => model.loc(key)}
                    localization={model.localization}
                    toolbarOffsetHeight={toolbarRef.current?.offsetHeight ?? 36}
                />
                {isOpen && comp.menuItems && anchorEl && (
                    <StiDropdownMenu
                        anchorEl={anchorEl}
                        items={comp.menuItems}
                        imgFn={name => model.img(name)}
                        onAction={handleAction}
                        onClose={() => { setOpenDropdown(null); setAnchorEl(null); }}
                        fontFamily={fontFamily}
                    />
                )}
            </td>
        );
    };

    return (
        <div
            ref={toolbarRef}
            id={`${model.options?.viewerId ?? 'stiJsViewer'}ToolBar`}
            className={toolbarClass}
            style={{ display: 'block', position: 'relative', zIndex: 2 }}
        >
            {/* paddingTop: 2px для Simple режима — аналог Angular */}
            <div style={!isSeparated ? { paddingTop: 2 } : undefined}>
                <table
                    className="stiJsViewerToolBarTable"
                    cellPadding={0}
                    cellSpacing={0}
                    style={{
                        margin: 0,
                        boxSizing: 'border-box',
                        width: '100%',
                        background: bgColor ?? undefined,
                        border: isSeparated ? '0px' : (borderColor ? `1px solid ${borderColor}` : undefined),
                        color: fontColor ?? undefined,
                        fontFamily: fontFamily ?? undefined,
                    }}
                >
                    <tbody>
                        <tr className="stiJsViewerClearAllStyles">
                            {/* Основные кнопки (левый блок) */}
                            <td className="stiJsViewerClearAllStyles" style={{ width: '100%' }}>
                                <table
                                    className="stiJsViewerClearAllStyles"
                                    cellPadding={0}
                                    cellSpacing={0}
                                    style={{ margin: 1 }}
                                >
                                    <tbody>
                                        <tr className="stiJsViewerClearAllStyles">
                                            {comps.map((comp, idx) => renderComp(comp, idx))}
                                        </tr>
                                    </tbody>
                                </table>
                            </td>

                            {/* Правые кнопки (About, Design) */}
                            {dopComps.length > 0 && (
                                <td className="stiJsViewerClearAllStyles">
                                    <table
                                        className="stiJsViewerClearAllStyles"
                                        cellPadding={0}
                                        cellSpacing={0}
                                        style={{ margin: 1 }}
                                    >
                                        <tbody>
                                            <tr className="stiJsViewerClearAllStyles">
                                                {dopComps.map((comp, idx) => renderComp(comp, 1000 + idx))}
                                            </tr>
                                        </tbody>
                                    </table>
                                </td>
                            )}
                        </tr>
                    </tbody>
                </table>
            </div>

            {/* Панель блокировки тулбара (disabled overlay) */}
            {(model.controls.toolbar as any)?.enabled === false && (
                <div
                    className="stiJsViewerDisabledPanel"
                    style={{ position: 'absolute', inset: 0, zIndex: 10 }}
                />
            )}
        </div>
    );
};
