// Аналог Angular AboutPanelComponent
// Плавающая панель «О программе» — центрируется внутри вьювера, закрывается кликом

import React, { useRef, useLayoutEffect, useState } from 'react';
import { useViewer } from '../hooks/useViewer';

export interface AboutPanelProps {
    visible: boolean;
    onClose: () => void;
}

export const AboutPanel: React.FC<AboutPanelProps> = ({ visible, onClose }) => {
    const { model } = useViewer();
    const panelRef = useRef<HTMLDivElement>(null);
    const [pos, setPos] = useState({ top: 0, left: 0, opacity: 0 });

    const year = new Date().getFullYear();

    // Центрируем панель после первого появления
    useLayoutEffect(() => {
        if (visible && panelRef.current && model.viewerSize) {
            const el = panelRef.current;
            const top  = model.viewerSize.height / 2 - el.offsetHeight / 2;
            const left = model.viewerSize.width  / 2 - el.offsetWidth  / 2;
            setPos({ top, left, opacity: 1 });
        }
        if (!visible) {
            setPos({ top: 0, left: 0, opacity: 0 });
        }
    }, [visible, model.viewerSize]);

    if (!visible) { return null; }

    const isLicensed = () => {
        const o = model.options;
        return o && !o.cloudMode && !o.serverMode && !o.standaloneJsMode &&
               !o.reportDesignerMode && !o.licenseIsValid;
    };

    const userLabel = (): string => {
        const name = model.options?.licenseUserName ?? '';
        if (isLicensed()) {
            return (name ? name + ', ' : '') + 'Unlicensed Version';
        }
        return name;
    };

    const handleLinkClick = (e: React.MouseEvent) => {
        e.stopPropagation();
        e.preventDefault();
        window.open('https://www.stimulsoft.com', '_blank');
    };

    return (
        <div
            ref={panelRef}
            className="stiJsViewerAboutPanel"
            style={{
                position: 'absolute',
                top: pos.top,
                left: pos.left,
                opacity: pos.opacity,
                transition: 'opacity 200ms ease',
                zIndex: 1000,
                backgroundSize: 'contain',
                cursor: 'pointer',
                userSelect: 'none'
            }}
            onClick={onClose}
        >
            <div className="stiJsViewerAboutPanelHeader">
                Stimulsoft Reports
            </div>

            <div style={{ textAlign: 'center' }}>
                <img
                    src={model.img?.('About.png') ?? ''}
                    alt="Stimulsoft"
                    style={{ marginTop: 30, width: 94, height: 94 }}
                />
            </div>

            <div className="stiJsViewerAboutPanelCopyright">
                {`Copyright 2003-${year} Stimulsoft`}
            </div>

            <div className="stiJsViewerAboutPanelVersion">
                {[
                    model.options?.productVersion?.trim(),
                    model.options?.frameworkType,
                    'React'
                ].filter(Boolean).join(', ')}
            </div>

            <div className="stiJsViewerAboutPanelVersion">
                All rights reserved
            </div>

            {userLabel() && (
                <div
                    className="stiJsViewerAboutPanelVersion"
                    style={{
                        marginTop: 20,
                        fontWeight: 'bold',
                        color: isLicensed() ? 'red' : '#444444'
                    }}
                >
                    {userLabel()}
                </div>
            )}

            <div className="stiJsViewerFormSeparator" style={{ marginTop: 20 }} />

            <div
                className="stiJsViewerAboutPanelStiLink"
                onClick={handleLinkClick}
                style={{ cursor: 'pointer' }}
            >
                www.stimulsoft.com
            </div>
        </div>
    );
};
