// Аналог Angular TextBoxComponent

import React, { useRef, useEffect } from 'react';
import { useViewer } from '../hooks/useViewer';

export interface TextBoxProps {
    value?: string;
    width?: number;
    type?: string;
    placeholder?: string;
    readOnly?: boolean;
    enabled?: boolean;
    focusOnCreate?: boolean;
    autocomplete?: string;
    margin?: string;
    tooltip?: string;
    onChange?: (value: string) => void;
    onEnter?: () => void;
}

export const StiTextBox: React.FC<TextBoxProps> = ({
    value = '',
    width,
    type = 'text',
    placeholder,
    readOnly = false,
    enabled = true,
    focusOnCreate = false,
    autocomplete,
    margin,
    tooltip,
    onChange,
    onEnter
}) => {
    const { model } = useViewer();
    const inputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        if (focusOnCreate) { inputRef.current?.focus(); }
    }, [focusOnCreate]);

    const isTouchDevice = model.options?.isTouchDevice ?? false;
    const h = isTouchDevice ? '23px' : '18px';

    return (
        <input
            ref={inputRef}
            type={type}
            value={value}
            placeholder={placeholder}
            readOnly={readOnly}
            disabled={!enabled}
            autoComplete={autocomplete}
            title={tooltip}
            style={{
                width: width ? `${width}px` : undefined,
                height: h,
                lineHeight: h,
                fontFamily: model.options?.toolbar?.fontFamily ?? 'inherit',
                color: model.options?.toolbar?.fontColor ?? 'inherit',
                border: enabled ? '1px solid #c6c6c6' : '1px solid #e0e0e0',
                borderRadius: 3,
                padding: '0 4px',
                boxSizing: 'border-box',
                margin: margin ?? undefined,
                backgroundColor: enabled ? '#fff' : '#f0f0f0',
                opacity: enabled ? 1 : 0.7,
            }}
            className="stiJsViewerTextBox"
            onChange={e => onChange?.(e.target.value)}
            onKeyDown={e => { if (e.key === 'Enter') onEnter?.(); }}
        />
    );
};
