// Аналог Angular ErrorMessageFormComponent

import React from 'react';
import { useViewer } from '../hooks/useViewer';
import { BaseForm } from './BaseForm';

export interface ErrorMessageFormProps {
    visible: boolean;
    onClose: () => void;
}

export const ErrorMessageForm: React.FC<ErrorMessageFormProps> = ({ visible, onClose }) => {
    const { model } = useViewer();
    const error = model.errorMessage;

    if (!visible || !error) { return null; }

    const type = error.type;
    const captionKey = type === 'Error' ? 'Error' : 'FormViewerTitle';
    const caption = model.loc?.(captionKey) ?? captionKey;

    const imgName = type === 'Warning'
        ? 'MsgFormWarning.png'
        : (type === true || type === 'Info')
            ? 'MsgFormInfo.png'
            : 'MsgFormError.png';
    const imgSrc = model.img?.(imgName);

    return (
        <BaseForm
            name="errorMessageForm"
            caption={caption}
            visible={visible}
            level={4}
            defaultTop={150}
            showCancel={false}
            onOk={onClose}
            onClose={onClose}
        >
            <table cellPadding={0} cellSpacing={0}>
                <tbody>
                    <tr>
                        <td style={{ verticalAlign: 'top' }}>
                            {imgSrc
                                ? <img src={imgSrc} alt="" style={{ padding: 15, width: 32, height: 32 }} />
                                : <span style={{ padding: 15, fontSize: 24 }}>
                                    {type === 'Warning' ? '⚠️' : type === 'Info' ? 'ℹ️' : '❌'}
                                  </span>
                            }
                        </td>
                        <td
                            className="stiJsViewerMessagesFormDescription"
                            style={{ maxWidth: 600, color: model.options?.toolbar?.fontColor }}
                            dangerouslySetInnerHTML={{ __html: error.text ?? '' }}
                        />
                    </tr>
                </tbody>
            </table>
        </BaseForm>
    );
};
