// Аналог Angular InteractionsPanelComponent
// Панель параметров отчёта (переменных) с полями ввода и кнопками Submit / Reset

import React, { useRef } from 'react';
import { useViewer } from '../hooks/useViewer';
import { StiReactInteractionsService } from '../services/interactions.service';
import { StiReactHelperService } from '../services/helper.service';
import { StiReactAnimationService } from '../services/animation.service';
import { StiReactDrillDownService } from '../services/drill-down.service';
import { StiReactControllerService } from '../services/controller.service';

// ─── Параметр-виджет ──────────────────────────────────────────────────────────

interface ParameterWidgetProps {
    variable: any;
    interactionSvc: StiReactInteractionsService;
    helper: StiReactHelperService;
}

const ParameterWidget: React.FC<ParameterWidgetProps> = ({ variable, helper }) => {
    const rowHeight = 21;

    // Bool (checkbox)
    if (variable.type === 'Bool' && (variable.basicType === 'Value' || variable.basicType === 'NullableValue')) {
        return (
            <input
                type="checkbox"
                checked={!!variable.value}
                disabled={!variable.allowUserValues}
                onChange={e => { variable.value = e.target.checked; }}
                style={{ margin: '0 2px', height: rowHeight }}
            />
        );
    }

    // List (multi-select display)
    if (variable.basicType === 'List') {
        const listValue = (variable.items || [])
            .filter((i: any) => i.isChecked)
            .map((i: any) => i.value || helper.getStringKey(i.key, variable))
            .join('; ');
        return (
            <div style={{ display: 'flex', alignItems: 'center', gap: 2 }}>
                <input
                    type="text"
                    readOnly
                    value={listValue}
                    className="stiJsViewerTextBox stiJsViewerTextBoxDefault"
                                    style={{ width: 205, height: rowHeight, padding: '0 3px', boxSizing: 'content-box' }}
                />
            </div>
        );
    }

    // Range
    if (variable.basicType === 'Range') {
        const fromVal = helper.getStringKey(variable.key, variable) ?? '';
        const toVal   = helper.getStringKey(variable.keyTo, variable) ?? '';
        return (
            <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
                <input
                    className="stiJsViewerTextBox stiJsViewerTextBoxDefault"
                    type="text"
                    defaultValue={String(fromVal)}
                    disabled={!variable.allowUserValues}
                    onBlur={e => { variable.key = e.target.value; }}
                    style={{ width: 130, height: rowHeight, boxSizing: 'content-box' }}
                />
                <span>–</span>
                <input
                    className="stiJsViewerTextBox stiJsViewerTextBoxDefault"
                    type="text"
                    defaultValue={String(toVal)}
                    disabled={!variable.allowUserValues}
                    onBlur={e => { variable.keyTo = e.target.value; }}
                    style={{ width: 130, height: rowHeight, boxSizing: 'content-box' }}
                />
            </div>
        );
    }

    // Value / NullableValue (default: text input)
    const strValue = variable.type === 'DateTime'
        ? (helper.getStringKey(variable.key, variable) ?? '')
        : (variable.value != null ? String(variable.value) : '');

    return (
        <input
            className="stiJsViewerTextBox stiJsViewerTextBoxDefault"
            type="text"
            defaultValue={String(strValue)}
            disabled={!variable.allowUserValues}
            onBlur={e => {
                if (variable.type === 'DateTime') {
                    variable.key = e.target.value;
                } else {
                    variable.value = e.target.value;
                    if (variable.basicType === 'Value') { variable.key = e.target.value; }
                }
            }}
            style={{ width: 210, height: rowHeight, boxSizing: 'content-box' }}
        />
    );
};

// ─── Кнопка панели ────────────────────────────────────────────────────────────

interface PanelButtonProps {
    caption: string;
    onClick: () => void;
}
const PanelButton: React.FC<PanelButtonProps> = ({ caption, onClick }) => {
    const [over, setOver] = React.useState(false);
    // Angular: sti-form-button → sti-button с styleName='stiJsViewerFormButton', minWidth: 80px
    const styleName = 'stiJsViewerFormButton';
    const className = `${styleName} ${styleName}${over ? 'Over' : 'Default'}`;
    return (
        <div
            className={className}
            onClick={onClick}
            onMouseOver={() => setOver(true)}
            onMouseOut={() => setOver(false)}
            style={{
                height: '23px',
                boxSizing: 'content-box',
                margin: '1px',
                minWidth: '80px',
                display: 'inline-block',
                cursor: 'pointer',
                userSelect: 'none',
            }}
        >
            <table className="stiJsViewerClearAllStyles" cellPadding={0} cellSpacing={0} style={{ height: '100%', width: '100%' }}>
                <tbody>
                    <tr className="stiJsViewerClearAllStyles">
                        <td className="stiJsViewerClearAllStyles" style={{ whiteSpace: 'nowrap', textAlign: 'center', padding: '1px 5px' }}>
                            {caption}
                        </td>
                    </tr>
                </tbody>
            </table>
        </div>
    );
};

// ─── Главный компонент ────────────────────────────────────────────────────────

export const ParametersPanel: React.FC = () => {
    const { model, controller } = useViewer();

    // Инициализируем interaction service один раз
    const interSvcRef = useRef<StiReactInteractionsService | null>(null);
    const helperSvcRef = useRef<StiReactHelperService | null>(null);

    if (!interSvcRef.current) {
        const animSvc  = new StiReactAnimationService(model);
        const helperSvc = new StiReactHelperService(model, animSvc);
        const ddSvc    = new StiReactDrillDownService(model);
        helperSvcRef.current = helperSvc;
        interSvcRef.current  = new StiReactInteractionsService(model, controller as StiReactControllerService, helperSvc, ddSvc);
    }

    const interSvc  = interSvcRef.current!;
    const helperSvc = helperSvcRef.current!;

    const visible = model.controls.parametersPanel.visible;
    const interactions = model.interactions;
    const position = model.options?.appearance?.currentParametersPanelPosition ?? 'Top';
    const isTop = position === 'Top';

    if (!visible || !interactions?.paramsVariables) { return null; }

    const variables: any[] = Array.isArray(interactions.paramsVariables)
        ? interactions.paramsVariables
        : Object.values(interactions.paramsVariables);

    const loc = (k: string) => model.loc?.(k) ?? k;

    // Layout: Top = horizontal grid, Left = vertical list
    const countInColumn: number = interactions.countInColumn?.length ?? variables.length;
    const countColumns: number  = interactions.countColumns?.length ?? 1;

    const fontFamily = model.options?.toolbar?.fontFamily ?? 'inherit';
    const fontColor  = model.options?.toolbar?.fontColor ?? 'inherit';
    const bgColor    = model.options?.toolbar?.backgroundColor ?? '';

    const panelStyle: React.CSSProperties = {
        fontFamily, color: fontColor,
        background: bgColor || '#fff',
        border: bgColor ? `1px solid ${bgColor}` : undefined,
        overflowY: 'auto',
        maxHeight: isTop ? (model.options?.appearance?.parametersPanelMaxHeight ?? 300) : undefined,
        width: isTop ? '100%' : undefined,
        padding: '4px 0',
        // Для Left: сбрасываем position: absolute из CSS (.stiJsViewerParametersPanel),
        // inner div тоже absolute — сбрасываем оба, чтобы панель была в flex flow
        ...(!isTop ? {
            position: 'static' as const,
            flexShrink: 0,
            zIndex: 2,
            borderRight: '1px solid #c6c6c6',
            overflow: 'auto',
        } : {}),
    };

    const handleSubmit = () => { interSvc.submitVariables(); };
    const handleReset  = () => { interSvc.resetVariables(); };

    return (
        <div
            className={`stiJsViewerParametersPanel${isTop ? ' stiJsViewerParametersPanelTop' : ''}`}
            style={panelStyle}
        >
            <div
                className={isTop ? '' : 'stiJsViewerInnerParametersPanelLeft'}
                style={{
                    padding: '0 4px',
                    // Сбрасываем position: absolute из CSS stiJsViewerInnerParametersPanelLeft
                    ...(!isTop ? { position: 'static' as const } : {}),
                }}
            >
                <table cellPadding={0} cellSpacing={0}>
                    <tbody>
                        {Array.from({ length: countInColumn }, (_, rowIdx) => (
                            <tr key={rowIdx}>
                                {Array.from({ length: countColumns }, (_, colIdx) => {
                                    const varIdx = colIdx * countInColumn + rowIdx;
                                    if (varIdx >= variables.length) { return null; }
                                    const v = variables[varIdx];
                                    return (
                                        <React.Fragment key={colIdx}>
                                            {/* Label cell */}
                                            <td
                                                title={v.description ?? ''}
                                                style={{
                                                    padding: `0 10px 0 ${colIdx > 0 ? 30 : 0}px`,
                                                    whiteSpace: 'nowrap',
                                                    verticalAlign: (v.basicType === 'Range' && !isTop) ? 'top' : 'middle',
                                                    paddingTop: (v.basicType === 'Range' && !isTop) ? 9 : undefined
                                                }}
                                            >
                                                {v.alias ?? v.name ?? ''}
                                            </td>
                                            {/* Widget cell */}
                                            <td style={{ padding: '2px 0' }}>
                                                <ParameterWidget
                                                    variable={v}
                                                    interactionSvc={interSvc}
                                                    helper={helperSvc}
                                                />
                                            </td>
                                        </React.Fragment>
                                    );
                                })}
                            </tr>
                        ))}
                        {/* Submit / Reset row */}
                        <tr>
                            {countColumns > 1 && <><td /><td /></>}
                            <td />
                            <td style={{ padding: '5px 2px 10px 0' }}>
                                <div style={{ display: 'flex', gap: 10, justifyContent: 'flex-end' }}>
                                    <PanelButton caption={loc('Reset')}  onClick={handleReset}  />
                                    <PanelButton caption={loc('Submit')} onClick={handleSubmit} />
                                </div>
                            </td>
                        </tr>
                    </tbody>
                </table>
            </div>
        </div>
    );
};
