// Аналог Angular BaseFormComponent — базовое модальное окно просмотрщика
// Структура HTML и CSS-классы точно совпадают с Angular-реализацией

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { useViewer } from '../hooks/useViewer';

export interface BaseFormProps {
    name: string;
    caption: string;
    visible: boolean;
    level?: number;
    showCancel?: boolean;
    showButtons?: boolean;
    showSeparator?: boolean;
    containerPadding?: string;
    defaultTop?: number;
    onOk?: () => void;
    onClose?: () => void;
    children?: React.ReactNode;
}

// ─── Кнопка формы (аналог Angular sti-form-button) ───
// styleName: 'stiJsViewerFormButton' (обычная) или 'stiJsViewerFormButtonTheme' (синяя)
const FormButton: React.FC<{
    caption: string;
    onClick: () => void;
    styleName?: string;
    imageName?: string;
    imgFn?: (name: string) => string;
}> = ({ caption, onClick, styleName = 'stiJsViewerFormButton', imageName, imgFn }) => {
    const [over, setOver] = useState(false);
    const className = `${styleName} ${styleName}${over ? 'Over' : 'Default'}`;

    return (
        <div
            className={className}
            onMouseOver={() => setOver(true)}
            onMouseOut={() => setOver(false)}
            onClick={onClick}
            style={{ cursor: 'pointer', userSelect: 'none', display: 'inline-block', height: 23, minWidth: 80, boxSizing: 'content-box', fontFamily: 'Arial' }}
        >
            <table className="stiJsViewerClearAllStyles" cellPadding={0} cellSpacing={0}
                style={{ width: '100%', height: '100%' }}>
                <tbody>
                    <tr className="stiJsViewerClearAllStyles">
                        {imageName && imgFn && (
                            <td className="stiJsViewerClearAllStyles"
                                style={{ width: 1, padding: 0, textAlign: 'center', lineHeight: 0 }}>
                                <img src={imgFn(imageName)} alt="" style={{ width: 16, height: 16 }} />
                            </td>
                        )}
                        <td className="stiJsViewerClearAllStyles"
                            style={{ textAlign: 'center', whiteSpace: 'nowrap', padding: '0 15px' }}>
                            {caption}
                        </td>
                    </tr>
                </tbody>
            </table>
        </div>
    );
};

export const BaseForm: React.FC<BaseFormProps> = ({
    name,
    caption,
    visible,
    level = 1,
    showCancel = true,
    showButtons = true,
    showSeparator = false,
    containerPadding = '4px',
    defaultTop,
    onOk,
    onClose,
    children
}) => {
    const { model } = useViewer();
    const formRef = useRef<HTMLDivElement>(null);

    // Позиция формы
    const [pos, setPos] = useState<{ left: number; top: number } | null>(null);
    const dragStart = useRef<{ screenX: number; screenY: number; formLeft: number; formTop: number } | null>(null);

    // Сброс позиции при каждом появлении формы
    useEffect(() => {
        if (visible) {
            setPos(null);
        }
    }, [visible]);

    // Вычисляем начальную позицию (центрирование как в Angular setObjectToCenter)
    useEffect(() => {
        if (visible && !pos && formRef.current) {
            // Используем requestAnimationFrame чтобы элемент получил реальные размеры
            requestAnimationFrame(() => {
                if (!formRef.current) return;
                const vw = model.viewerSize?.width ?? window.innerWidth;
                const vh = model.viewerSize?.height ?? window.innerHeight;
                const fw = formRef.current.offsetWidth || 300;
                const fh = formRef.current.offsetHeight || 200;
                const leftPos = Math.max(0, vw / 2 - fw / 2);
                // Angular: в fullscreen — центр; иначе defaultTop или 250
                const fullScreen = model.options?.appearance?.fullScreenMode;
                const topPos = fullScreen
                    ? Math.max(0, vh / 2 - fh / 2)
                    : Math.max(0, defaultTop ?? 250);
                setPos({ left: leftPos, top: topPos });
            });
        }
    }, [visible, model.viewerSize, defaultTop, pos]);

    // Перетаскивание (Angular использует screenX/screenY)
    const handleMouseDown = useCallback((e: React.MouseEvent) => {
        if (!pos) return;
        e.preventDefault();
        dragStart.current = { screenX: e.screenX, screenY: e.screenY, formLeft: pos.left, formTop: pos.top };
        const onMove = (me: MouseEvent) => {
            if (!dragStart.current) return;
            setPos({
                left: dragStart.current.formLeft + me.screenX - dragStart.current.screenX,
                top: dragStart.current.formTop + me.screenY - dragStart.current.screenY
            });
        };
        const onUp = () => {
            dragStart.current = null;
            window.removeEventListener('mousemove', onMove);
            window.removeEventListener('mouseup', onUp);
        };
        window.addEventListener('mousemove', onMove);
        window.addEventListener('mouseup', onUp);
    }, [pos]);

    if (!visible) return null;

    const fontFamily = model.options?.toolbar?.fontFamily || 'Arial';
    const fontColor  = model.options?.toolbar?.fontColor ?? undefined;
    const fontSize   = '12px';
    const zIndex     = level * 10 + 1;
    const okText     = model.loc?.('ButtonOk')     ?? 'OK';
    const cancelText = model.loc?.('ButtonCancel') ?? 'Cancel';
    const closeImgSrc = model.img?.('CloseForm.png');

    return (
        // Overlay — перехватывает клики вне формы (не fixed — остаёмся внутри viewer)
        <>
            <div
                style={{
                    position: 'absolute', inset: 0,
                    zIndex: zIndex - 1,
                    background: 'transparent'
                }}
                onMouseDown={e => { if (e.target === e.currentTarget) onClose?.(); }}
            />
            {/* Аналог Angular: div.stiJsViewerForm — fixed чтобы не обрезалась overflow:hidden viewer */}
            <div
                ref={formRef}
                className="stiJsViewerForm"
                style={{
                    // position: absolute задаётся CSS .stiJsViewerForm — не перезаписываем
                    left: pos != null ? pos.left : -9999,
                    top: pos != null ? pos.top : -9999,
                    visibility: pos != null ? 'visible' : 'hidden',
                    zIndex,
                    fontFamily,
                    color: fontColor,
                    fontSize,
                }}
            >
                {/* Заголовок — Angular: div.stiJsViewerFormHeader */}
                <div
                    className="stiJsViewerFormHeader"
                    onMouseDown={handleMouseDown}
                    style={{ cursor: 'move', userSelect: 'none' }}
                >
                    <table className="stiJsViewerClearAllStyles" cellPadding={0} cellSpacing={0}
                        style={{ width: '100%' }}>
                        <tbody>
                            <tr className="stiJsViewerClearAllStyles">
                                <td className="stiJsViewerClearAllStyles"
                                    style={{ textAlign: 'left', padding: '5px 10px 8px 15px', whiteSpace: 'nowrap' }}>
                                    {caption}
                                </td>
                                {/* Spacer */}
                                <td className="stiJsViewerClearAllStyles" style={{ width: '100%' }} />
                                {/* Кнопка закрытия — Angular: sti-button с imageName='CloseForm.png' */}
                                <td className="stiJsViewerClearAllStyles"
                                    style={{ verticalAlign: 'top', width: 30, textAlign: 'right', padding: '2px 1px 1px' }}>
                                    <CloseButton imgSrc={closeImgSrc} onClick={() => onClose?.()} />
                                </td>
                            </tr>
                        </tbody>
                    </table>
                </div>

                {/* Содержимое — Angular: div.stiJsViewerFormContainer */}
                <div className="stiJsViewerFormContainer" style={{ padding: containerPadding }}>
                    {children}
                </div>

                {/* Разделитель — Angular: div.stiJsViewerFormSeparator */}
                {showButtons && showSeparator && (
                    <div className="stiJsViewerFormSeparator" />
                )}

                {/* Кнопки — Angular: div.stiJsViewerFormButtonsPanel */}
                {showButtons && (
                    <div className="stiJsViewerFormButtonsPanel">
                        <table className="stiJsViewerClearAllStyles" cellPadding={0} cellSpacing={0}>
                            <tbody>
                                <tr className="stiJsViewerClearAllStyles">
                                    <td className="stiJsViewerClearAllStyles" style={{ padding: '8px 12px 8px 8px' }}>
                                        <FormButton caption={okText} onClick={() => onOk?.()} styleName="stiJsViewerFormButtonTheme" />
                                    </td>
                                    {showCancel && (
                                        <td className="stiJsViewerClearAllStyles" style={{ padding: '8px 8px 8px 0px' }}>
                                            <FormButton caption={cancelText} onClick={() => onClose?.()} />
                                        </td>
                                    )}
                                </tr>
                            </tbody>
                        </table>
                    </div>
                )}
            </div>
        </>
    );
};

// ─── Кнопка закрытия формы (повторяет Angular sti-button с imageMargin) ───
const CloseButton: React.FC<{ imgSrc?: string; onClick: () => void }> = ({ imgSrc, onClick }) => {
    const [over, setOver] = useState(false);
    return (
        <div
            style={{
                display: 'inline-block', cursor: 'pointer',
                margin: '0 2px', lineHeight: 0,
            }}
            className={`stiJsViewerStandartSmallButton stiJsViewerStandartSmallButton${over ? 'Over' : 'Default'}`}
            onMouseOver={() => setOver(true)}
            onMouseOut={() => setOver(false)}
            onClick={e => { e.stopPropagation(); onClick(); }}
        >
            {imgSrc
                ? <img src={imgSrc} alt="×" style={{ width: 16, height: 16, margin: '0 2px' }} />
                : <span style={{ fontSize: 14, padding: '0 4px' }}>✕</span>
            }
        </div>
    );
};
