// Аналог Angular PrintService
// Обработка печати: PDF в iframe, HTML popup, без предварительного просмотра

import { StiReactModelService } from './model.service';
import { StiReactHelperService } from './helper.service';
import { StiReactHttpClientService } from './http-client.service';
import { StiReactControllerService } from './controller.service';

export class StiReactPrintService {

    constructor(
        private model: StiReactModelService,
        private helper: StiReactHelperService,
        private httpClient: StiReactHttpClientService,
        private controller: StiReactControllerService
    ) { }

    /**
     * Обработать результат печати — вызывается из controller.processResponse
     * когда action === 'PrintReport'
     */
    public handlePrintResult(subAction: string, data: any) {
        switch (subAction) {
            case 'PrintWithPreview':
                this.printAsPopup(data);
                break;
            case 'PrintWithoutPreview':
                this.printAsHtml(data);
                break;
        }
    }

    /**
     * PDF-печать через blob + iframe
     */
    public async printAsPdf(pdfBlob: Blob) {
        const viewerEl = this.model.controls.viewer?.el;
        if (!viewerEl) {
            // Fallback: скачать файл
            const url = URL.createObjectURL(pdfBlob);
            window.open(url, '_blank');
            return;
        }

        const printFrameId = (this.model.options?.viewerId ?? 'sti') + '_PdfPrintFrame';
        let printFrame = document.getElementById(printFrameId) as HTMLIFrameElement;
        if (printFrame) { viewerEl.removeChild(printFrame); }

        printFrame = document.createElement('iframe');
        printFrame.id = printFrameId;
        printFrame.name = printFrameId;
        printFrame.style.cssText = 'width:0;height:0;position:absolute;border:none;';

        const isFirefox = this.helper.getNavigatorName() === 'Mozilla';
        if (isFirefox) {
            // Firefox не загружает скрытый iframe
            printFrame.style.cssText = 'width:100px;height:100px;position:absolute;border:none;visibility:hidden;z-index:-100;pointer-events:none;';
        }

        viewerEl.insertBefore(printFrame, viewerEl.firstChild);

        const blobUrl = URL.createObjectURL(pdfBlob);

        if (!isFirefox) {
            printFrame.onload = () => {
                printFrame.contentWindow?.focus();
                printFrame.contentWindow?.print();
            };
        }

        printFrame.src = blobUrl;
    }

    /**
     * Печать через popup-окно (HTML)
     */
    public printAsPopup(html: string) {
        const width = this.model.reportParams?.pagesWidth || 790;
        const win = this.helper.openNewWindow(
            'about:blank', 'PrintReport',
            `height=900,width=${width},toolbar=no,menubar=yes,scrollbars=yes,resizable=yes,location=no,status=no`
        );
        if (win) {
            win.document.open();
            win.document.write(html);
            win.document.close();
        }
    }

    /**
     * Печать через скрытый iframe (без предварительного просмотра)
     */
    public printAsHtml(html: string) {
        // Проверим — может это сообщение об ошибке?
        if (html && html.indexOf('<html') === -1 && html.length < 500) {
            this.controller.showError(html);
            return;
        }

        const viewerEl = this.model.controls.viewer?.el;
        if (!viewerEl) { return; }

        const printFrameId = (this.model.options?.viewerId ?? 'sti') + '_HtmlPrintFrame';
        let printFrame = document.getElementById(printFrameId) as HTMLIFrameElement;
        if (printFrame) { viewerEl.removeChild(printFrame); }

        printFrame = document.createElement('iframe');
        printFrame.id = printFrameId;
        printFrame.name = printFrameId;
        printFrame.style.cssText = 'width:0;height:0;position:absolute;border:none;';
        viewerEl.insertBefore(printFrame, viewerEl.firstChild);

        printFrame.contentWindow!.document.open();
        printFrame.contentWindow!.document.write(html);
        printFrame.contentWindow!.document.close();

        setTimeout(() => {
            printFrame.contentWindow?.focus();
            printFrame.contentWindow?.print();
        }, 100);
    }
}
