// Аналог Angular NavigatePanelComponent
// Строка навигации (снизу): номер страницы, кнопки первой/последней, zoom, viewMode
// Показывается только в режиме Separated или на мобильных устройствах

import React from 'react';
import { useViewer } from '../hooks/useViewer';

export const NavigatePanel: React.FC = () => {
    const { model, controller } = useViewer();

    const opts = model.options;
    const displayMode = opts?.toolbar?.displayMode;
    const isMobile = opts?.isMobileDevice ?? false;

    // NavigatePanel нужен в режиме Separated (кнопки навигации перенесены сюда)
    // или на мобильных устройствах
    if (displayMode !== 'Separated' && !isMobile) {
        return null;
    }

    const rp = model.reportParams;
    const page = (rp?.pageNumber ?? 0) + 1;
    const total = rp?.pagesCount ?? 1;
    const zoom = rp?.zoom ? Math.round(rp.zoom) + '%' : '100%';
    const rtl = opts?.appearance?.rightToLeft ?? false;

    const go = (pageNum: number) => {
        controller.postViewerEvent('GetPages', { stiweb_pageNumber: pageNum });
    };

    return (
        <div
            className="stiJsViewerNavigatePanel"
            style={{
                display: 'flex', alignItems: 'center', gap: 4, padding: '2px 8px',
                borderTop: '1px solid #ddd', background: '#f5f5f5',
                fontSize: 12, minHeight: 28, boxSizing: 'border-box'
            }}
        >
            {/* Кнопки навигации */}
            {opts?.toolbar?.showFirstPageButton && (
                <button
                    disabled={page <= 1}
                    onClick={() => go(0)}
                    style={btnStyle(page > 1)}
                    title={model.loc?.('FirstPage') ?? 'First Page'}
                >
                    {rtl ? '⏭' : '⏮'}
                </button>
            )}
            {opts?.toolbar?.showPreviousPageButton && (
                <button
                    disabled={page <= 1}
                    onClick={() => go(page - 2)}
                    style={btnStyle(page > 1)}
                    title={model.loc?.('PrevPage') ?? 'Previous Page'}
                >
                    {rtl ? '▶' : '◀'}
                </button>
            )}

            {/* Счётчик страниц */}
            {opts?.toolbar?.showCurrentPageControl && (
                <span style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
                    <input
                        type="number"
                        min={1}
                        max={total}
                        value={page}
                        onChange={e => {
                            const n = parseInt(e.target.value, 10);
                            if (!isNaN(n) && n >= 1 && n <= total) { go(n - 1); }
                        }}
                        style={{ width: 40, textAlign: 'center', padding: '1px 2px', fontSize: 12 }}
                    />
                    <span style={{ color: '#666' }}>/ {total}</span>
                </span>
            )}

            {opts?.toolbar?.showNextPageButton && (
                <button
                    disabled={page >= total}
                    onClick={() => go(page)}
                    style={btnStyle(page < total)}
                    title={model.loc?.('NextPage') ?? 'Next Page'}
                >
                    {rtl ? '◀' : '▶'}
                </button>
            )}
            {opts?.toolbar?.showLastPageButton && (
                <button
                    disabled={page >= total}
                    onClick={() => go(total - 1)}
                    style={btnStyle(page < total)}
                    title={model.loc?.('LastPage') ?? 'Last Page'}
                >
                    {rtl ? '⏮' : '⏭'}
                </button>
            )}

            {/* Zoom */}
            {opts?.toolbar?.showZoomButton && (
                <>
                    <div style={{ width: 1, height: 16, background: '#ccc', margin: '0 4px' }} />
                    <select
                        value={rp?.zoom ?? 100}
                        onChange={e => controller.postViewerEvent('GetPages', { stiweb_zoom: parseInt(e.target.value, 10) })}
                        style={{ fontSize: 12, padding: '1px 2px' }}
                    >
                        {[25, 50, 75, 100, 150, 200].map(z => (
                            <option key={z} value={z}>{z}%</option>
                        ))}
                    </select>
                </>
            )}
        </div>
    );
};

function btnStyle(enabled: boolean): React.CSSProperties {
    return {
        padding: '1px 6px', fontSize: 12, cursor: enabled ? 'pointer' : 'default',
        opacity: enabled ? 1 : 0.4, border: '1px solid transparent',
        background: 'transparent', borderRadius: 2
    };
}
