// Аналог Angular FindPanelComponent (sti-find-panel)
// Панель поиска текста в отчёте
//
// Angular items:
//   1. Close button (CloseForm.png)
//   2. "Find What" text label
//   3. TextBox (170px)
//   4. FindPrevious (ArrowUpBlue.png + caption)
//   5. FindNext (ArrowDownBlue.png + caption)
//   6. MatchCase (toggle button)
//   7. MatchWholeWord (toggle button)

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { useViewer } from '../hooks/useViewer';
import { StiButton } from '../controls/Button';

export const FindPanel: React.FC = () => {
    const { model, controller } = useViewer();
    const inputRef = useRef<HTMLInputElement>(null);
    const [, forceUpdate] = useState(0);

    const findService = (model as any).findService;
    const visible = model.controls.findPanel?.visible ?? false;

    // Focus input when panel becomes visible
    useEffect(() => {
        if (visible && inputRef.current) {
            findService.text = '';
            setTimeout(() => inputRef.current?.focus(), 50);
        }
    }, [visible]);

    const find = useCallback((direction: string) => {
        if (!findService) return;
        if (findService.text === '') {
            findService.hideFindLabels();
            return;
        }
        if (findService.lastFindText !== findService.text || (findService as any)._changeFind) {
            (findService as any)._changeFind = false;
            findService.showFindLabels();
        } else {
            findService.selectFindLabel(direction);
        }
    }, [findService]);

    if (!visible) { return null; }

    const displayMode = model.options?.toolbar?.displayMode ?? 'Simple';
    const isSeparated = displayMode === 'Separated';

    const locFindWhat = (model.loc?.('FindWhat') ?? 'Find What:').replace(':', '');
    const locFindPrevious = model.loc?.('FindPrevious') ?? 'Find Previous';
    const locFindNext = model.loc?.('FindNext') ?? 'Find Next';
    const locMatchCase = (model.loc?.('MatchCase') ?? 'Match Case').replace('&', '');
    const locMatchWholeWord = (model.loc?.('MatchWholeWord') ?? 'Match Whole Word').replace('&', '');

    const handleClose = () => {
        if (model.controls.findPanel) {
            model.controls.findPanel.visible = false;
            forceUpdate(n => n + 1);
        }
        findService?.hideFindLabels();
    };

    const handleTextBoxAction = () => {
        if (findService) {
            find('Next');
        }
    };

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter') {
            handleTextBoxAction();
        }
        if (e.key === 'Escape') {
            handleClose();
        }
    };

    const handleMatchCase = () => {
        if (findService) {
            findService.matchCase = !findService.matchCase;
            (findService as any)._changeFind = true;
            forceUpdate(n => n + 1);
        }
    };

    const handleMatchWholeWord = () => {
        if (findService) {
            findService.matchWholeWord = !findService.matchWholeWord;
            (findService as any)._changeFind = true;
            forceUpdate(n => n + 1);
        }
    };

    const handleFindPrevious = () => {
        if (findService && inputRef.current) {
            findService.text = inputRef.current.value;
            find('Previous');
        }
    };

    const handleFindNext = () => {
        if (findService && inputRef.current) {
            findService.text = inputRef.current.value;
            find('Next');
        }
    };

    const sepHeight = isSeparated ? '28px' : undefined;

    return (
        <div
            className={'stiJsViewerToolBar' + (isSeparated ? ' stiJsViewerToolBarSeparated' : '')}
            style={{ display: visible ? '' : 'none' }}
        >
            <div style={{ paddingTop: displayMode === 'Simple' ? '2px' : undefined }}>
                <div
                    className="stiJsViewerToolBarTable"
                    style={{
                        border: isSeparated ? '0px' : undefined,
                        boxSizing: 'border-box',
                    }}
                >
                    <table className="stiJsViewerClearAllStyles" cellPadding={0} cellSpacing={0} style={{ margin: 0 }}>
                        <tbody>
                            <tr className="stiJsViewerClearAllStyles">
                                {/* 1. Close button */}
                                <td className="stiJsViewerClearAllStyles">
                                    <StiButton
                                        imageName="CloseForm.png"
                                        margin="2px"
                                        height={sepHeight}
                                        onClick={handleClose}
                                    />
                                </td>

                                {/* 2. "Find What" label */}
                                <td className="stiJsViewerClearAllStyles">
                                    <div style={{
                                        margin: '2px',
                                        whiteSpace: 'nowrap',
                                        padding: '0 4px',
                                        lineHeight: sepHeight ?? '23px',
                                    }}>
                                        {locFindWhat}
                                    </div>
                                </td>

                                {/* 3. TextBox */}
                                <td className="stiJsViewerClearAllStyles">
                                    <div style={{ margin: '2px' }}>
                                        <input
                                            ref={inputRef}
                                            className="stiJsViewerTextBox"
                                            style={{
                                                width: 170,
                                                height: 21,
                                                boxSizing: 'border-box',
                                                padding: '0 4px',
                                                border: '1px solid #c6c6c6',
                                                outline: 'none',
                                                fontFamily: 'inherit',
                                                fontSize: 'inherit',
                                            }}
                                            defaultValue=""
                                            onChange={(e) => {
                                                if (findService) findService.text = e.target.value;
                                            }}
                                            onKeyDown={handleKeyDown}
                                            autoFocus
                                        />
                                    </div>
                                </td>

                                {/* 4. Find Previous */}
                                <td className="stiJsViewerClearAllStyles">
                                    <StiButton
                                        imageName="Arrows.ArrowUpBlue.png"
                                        caption={locFindPrevious}
                                        margin="2px"
                                        height={sepHeight}
                                        onClick={handleFindPrevious}
                                    />
                                </td>

                                {/* 5. Find Next */}
                                <td className="stiJsViewerClearAllStyles">
                                    <StiButton
                                        imageName="Arrows.ArrowDownBlue.png"
                                        caption={locFindNext}
                                        margin="2px"
                                        height={sepHeight}
                                        onClick={handleFindNext}
                                    />
                                </td>

                                {/* 6. Match Case */}
                                <td className="stiJsViewerClearAllStyles">
                                    <StiButton
                                        caption={locMatchCase}
                                        margin="2px"
                                        height={sepHeight}
                                        selected={findService?.matchCase ?? false}
                                        onClick={handleMatchCase}
                                    />
                                </td>

                                {/* 7. Match Whole Word */}
                                <td className="stiJsViewerClearAllStyles">
                                    <StiButton
                                        caption={locMatchWholeWord}
                                        margin="2px"
                                        height={sepHeight}
                                        selected={findService?.matchWholeWord ?? false}
                                        onClick={handleMatchWholeWord}
                                    />
                                </td>
                            </tr>
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};
